-- Poems batch 265
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('31debe29-d0be-4c14-85d3-1ec67817cb14','將進酒','周密','宋','宋诗','song-poetry','','[]','莫舞鬰輪袍，莫酌金叵羅。',158,'全唐诗/poet.song.236000.json','["莫舞鬰輪袍，莫酌金叵羅。", "四坐一時靜，聽我感慨歌。", "君不見滔滔易水咸陽路，漸離擊筑荆卿舞。", "酒盃在手醉不成，八創空遶秦宮柱。", "又不見睢陽夜戰城欲摧，孤臣駡賊聲如雷。", "酒不下咽指流血，白羽空射浮圖迴。", "古來志士輕一死，意氣相期每如此。", "獨醒自古欲何爲，空留遺恨隨流水。", "長歌感慨多愴神，不須聞此眉雙顰。", "直須痛飲烏程酒，與君醉倒蘋華春。"]'),
('8dbba3aa-516e-4124-b182-3581d520a534','香林','周密','宋','宋诗','song-poetry','','[]','鷲峰深處寺，嵐影翠紛紛。',48,'全唐诗/poet.song.236000.json','["鷲峰深處寺，嵐影翠紛紛。", "止水受秋月，空煙生夜雲。", "谷虛猿墜果，地暖鶴眠芸。", "合澗橋邊路，松聲九里聞。"]'),
('bfc922c0-bf2a-4bed-9d7a-9938abd284b4','題宋伯仁煙波圖後','周密','宋','宋诗','song-poetry','','[]','是處煙波有釣蓑，底須濠濮與西河。',64,'全唐诗/poet.song.236000.json','["是處煙波有釣蓑，底須濠濮與西河。", "三吳舊日圖漁具，九曲當年賦棹歌。", "濯足濯纓吟欵乃，知魚知我樂如何。", "會須携取新詩卷，西塞山前問志和。"]'),
('d7ba02a5-f22f-41b6-aeec-e41754f11d3c','柳枝詞','周密','宋','宋诗','song-poetry','','[]','鏡裏愁眉怨曉霜，多情猶解拂離觴。',32,'全唐诗/poet.song.236000.json','["鏡裏愁眉怨曉霜，多情猶解拂離觴。", "西風十里新堤路，半带蟬聲半夕陽。"]'),
('d155e402-1071-4e6e-b9ce-5584c39b79d9','送僧歸峨眉','周密','宋','宋诗','song-poetry','','[]','大峨山頂寺，歸路八千遥。',48,'全唐诗/poet.song.236000.json','["大峨山頂寺，歸路八千遥。", "百丈牽雲上，三衣带雨挑。", "嶺寒棲板屋，路斷隔繩橋。", "若過三閭宅，騷魂試一招。"]'),
('1895c049-99cc-454b-9d65-9f1db2c4bf76','懷鳴禽','周密','宋','宋诗','song-poetry','','[]','竹樹環幽棲，積翠何森森。',132,'全唐诗/poet.song.236000.json','["竹樹環幽棲，積翠何森森。", "鳴禽不知數，日夕傳好音。", "居然謝囂𡏖，宛若居山林。", "哢清孤枕曉，聲碎花房深。", "笙竽雜天籟，鼓吹無哇淫。", "物我自兩忘，彼此無機心。", "髽奴不解事，探鷇稍見侵。", "忽動擇木志，一去不可尋。", "鷗鳥駭海翁，智莫欺魚禽。", "何以慰寂寥，靜對空愔愔。", "風篁落纖月，誰伴清宵吟。"]'),
('9eb3f41c-c8f0-4c3d-a5c4-915f8a78bfdc','琵琶','周密','宋','宋诗','song-poetry','','[]','曾聞賀老說當年，玉軸東風四百絃。',64,'全唐诗/poet.song.236000.json','["曾聞賀老說當年，玉軸東風四百絃。", "寶結颺春鶑語滑，香槽抱月鳳心圓。", "荻花江上逢商婦，楊柳灣頭見小憐。", "莫向樽前彈怨曲，青衫白髮易凄然。"]'),
('1c7b990e-a93f-4664-ae86-0714d9d52fbd','一棹','周密','宋','宋诗','song-poetry','','[]','一棹歸何處，西風夕照邊。',48,'全唐诗/poet.song.236000.json','["一棹歸何處，西風夕照邊。", "市豐招碓鼓，橋近落帆船。", "竹密懸青雨，溪虛漲白煙。", "到家知不遠，酒熟菊花前。"]'),
('29a7d307-51fa-40c3-9266-3901e6ec3b1a','雨後過湖偶成二首  其一','周密','宋','宋诗','song-poetry','','[]','堤上西風柳葉疎，雁浮新影照平湖。',32,'全唐诗/poet.song.236000.json','["堤上西風柳葉疎，雁浮新影照平湖。", "閑雲本自無心出，却爲玄暉了畫圖。"]'),
('6f69c0ba-08d2-4cc7-8300-793ad6b3961e','雨後過湖偶成二首  其二','周密','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雨重楊絲不曳風，小舟斜出斷橋東。',32,'全唐诗/poet.song.236000.json','["雨重楊絲不曳風，小舟斜出斷橋東。", "分明幾點閑鷗鷺，着在西湖便不同。"]'),
('43cc0b28-2edf-4873-a449-44146b4f48f0','閑晝','周密','宋','宋诗','song-poetry','','[]','新竹詵詵出矮牆，虛窗風度碾茶香。',32,'全唐诗/poet.song.236000.json','["新竹詵詵出矮牆，虛窗風度碾茶香。", "疎雲逗日簾垂地，一蝶飛來晝夢長。"]'),
('fc1b217e-6f81-493e-a512-91ade9bbe1ae','靜倚','周密','宋','宋诗','song-poetry','','[]','小樓寂寂倚春陰，宿酒殘香惱客情。',32,'全唐诗/poet.song.236000.json','["小樓寂寂倚春陰，宿酒殘香惱客情。", "連日峭寒疑有雪，隔簾錯聽落梅聲。"]'),
('a0736e4b-84f8-4740-a3e4-b1b7fcad1ae4','渡易水','周密','宋','宋诗','song-poetry','','[]','丈夫一死已許人，高歌忼慨西入秦。',96,'全唐诗/poet.song.236000.json','["丈夫一死已許人，高歌忼慨西入秦。", "一旦直欲揕呂政，何異隻手批逆鱗。", "舞陽色變衮龍絕，環柱模糊八創血。", "督亢地圖秦已知，强燕反是速燕滅。", "壯志不就千古悲，易水蕭蕭雲垂垂。", "尺八匕首何足恃，當時枉殺樊於期。"]'),
('4bcd6829-a739-42bc-b61c-3a371070f585','戲題製荷吟','周密','宋','宋诗','song-poetry','','[]','多事紉蘭襞菊裳，等閑吟褐付秋塘。',32,'全唐诗/poet.song.236000.json','["多事紉蘭襞菊裳，等閑吟褐付秋塘。", "正須太華峰頭葉，底用成都郭外桑。"]'),
('08886d3a-a71d-46d5-956b-244b1c70f032','橫翠亭','周密','宋','宋诗','song-poetry','','[]','晴空漠漠迷蒼煙，凭闌一望心茫然。',64,'全唐诗/poet.song.236000.json','["晴空漠漠迷蒼煙，凭闌一望心茫然。", "舊游已落飛鳥外，新詩應在歸雲邊。", "亭高千里納山色，人靜萬物爭春妍。", "天涯倦客早歸去，空山日暮多啼鵑。"]'),
('92917193-dfc0-455c-a64e-c406521b4a65','仙霞嶺次徐意一參政韻','周密','宋','宋诗','song-poetry','','[]','不知天已近，但覺衆山微。',48,'全唐诗/poet.song.236000.json','["不知天已近，但覺衆山微。", "世道古來險，客行何日歸。", "舊游青鬢改，故國白雲飛。", "今日重登眺，悠然悟昨非。"]'),
('0d5d1adb-b4d5-4bd3-8cad-90a85a4b98d5','次李篔房秋晚見寄韻','周密','宋','宋诗','song-poetry','','[]','短髮蕭蕭不耐霜，賦情誰似老河陽。',64,'全唐诗/poet.song.236000.json','["短髮蕭蕭不耐霜，賦情誰似老河陽。", "橘中自樂同商隠，酒後長歌笑楚狂。", "鴉带夕陽山紫翠，雁啼寒水樹青黄。", "蘋邊肯寄停雲句，何日扁舟訪葯房。"]'),
('95c9c3fb-03c1-4b8f-9d15-33e72b62b15f','山居','周密','宋','宋诗','song-poetry','','[]','隠几支頤枕曲肱，丹田養氣石田耕。',32,'全唐诗/poet.song.236000.json','["隠几支頤枕曲肱，丹田養氣石田耕。", "紅旗黄紙非吾事，白石清泉了一生。"]'),
('86ba8c54-1d4c-4170-8d73-f5b26f7589f2','題小李將軍著色山水','周密','宋','宋诗','song-poetry','','[]','群山積古翠，空谷滿白雲。',72,'全唐诗/poet.song.236000.json','["群山積古翠，空谷滿白雲。", "遠溜從何來，飛玉聲磤磤。", "東風入千巖，花雨紅繽紛。", "何人卜深隠，結屋蒼崖垠。", "浩然山林思，高謝朝市氛。", "咏歌歸來篇，贅甚鍾山文。"]'),
('9429441d-e149-44ae-ae51-35f2e723bc91','江湖偉觀','周密','宋','宋诗','song-poetry','','[]','暇日登臨酒一樽，半空傑閣倚雲根。',64,'全唐诗/poet.song.236000.json','["暇日登臨酒一樽，半空傑閣倚雲根。", "東南王氣浮天闕，吳越潮聲出海門。", "玉局柳高含古意，金沙梅老冷吟魂。", "凭高討勝多幽事，細讀殘碑剝蘚痕。"]'),
('583475eb-3bbd-4d7c-9d96-a802882e0eae','荒塚謠','周密','宋','宋诗','song-poetry','','[]','老樗颼飀灑寒雨，狐狸冷伴幽魂語。',64,'全唐诗/poet.song.236000.json','["老樗颼飀灑寒雨，狐狸冷伴幽魂語。", "草沒麒麟仆斷碑，白骨年深化黄土。", "荒凉古徑無人行，凄風盡日吹陰雲。", "青山莽莽幾更主，翁仲無言成萬古。"]'),
('64bd874c-664e-4717-8806-c58d26dfb90d','吳山晚望','周密','宋','宋诗','song-poetry','','[]','春江分影送殘陽，淺薄東風颺晚香。',32,'全唐诗/poet.song.236000.json','["春江分影送殘陽，淺薄東風颺晚香。", "燕子已歸寒未去，柳蛾酣雨弄青黄。"]'),
('df26ec20-65f3-4f09-906f-ddae6fc60d0f','早梅嘆','周密','宋','宋诗','song-poetry','','[]','失喜東園見早梅，翻愁開早被風吹。',32,'全唐诗/poet.song.236000.json','["失喜東園見早梅，翻愁開早被風吹。", "珠鈿滿路無人惜，傲雪凌霜是北枝。"]'),
('c44015ca-c6ca-4981-8fa1-b0ac2ba5a062','游凉觀謹次親老韻','周密','宋','宋诗','song-poetry','','[]','錦雲照方鏡，碧玉環四岸。',96,'全唐诗/poet.song.236000.json','["錦雲照方鏡，碧玉環四岸。", "奇凉徹心境，幽芳清鼻觀。", "恍如泛仙查，飄飄泝河漢。", "雲收片月上，風來萬荷亂。", "玩幽發孤詠，慨古興浩歎。", "魚鳥各有樂，鵬鷃不足算。", "林虛白露滴，竹冷茶烟散。", "清景未易殫，當於靜中看。"]'),
('24c67c61-3a2a-46d7-b939-74a86f0fbcba','胡月江書堂','周密','宋','宋诗','song-poetry','','[]','水西雲北外，詩屋柳陰陰。',48,'全唐诗/poet.song.236000.json','["水西雲北外，詩屋柳陰陰。", "小卷編唐宋，危冠講古今。", "跛馿乘淺醉，老鶴伴孤吟。", "門外雖車馬，游塵自不侵。"]'),
('6fd0acdc-5ade-4c6e-bea0-c7dd2b68e352','清心樓晚眺','周密','宋','宋诗','song-poetry','','[]','霜空澄晚景，高處眼增明。',48,'全唐诗/poet.song.236000.json','["霜空澄晚景，高處眼增明。", "幽草生官舍，秋霖壞古城。", "遠山圍野闊，飛鳥與雲平。", "擬作登樓賦，依然故國情。"]'),
('1b087bfe-9440-420e-af3e-4aaf77b77558','太乙西宮','周密','宋','宋诗','song-poetry','','[]','仙宮金碧照清漪，聖主憂民事禱祈。',64,'全唐诗/poet.song.236000.json','["仙宮金碧照清漪，聖主憂民事禱祈。", "五福正臨吳分野，百年敢惜御園池。", "雲浮蕊殿春來早，香冷梅鄰月到遲。", "清夜綠章陳露醮，天風吹下步虛詞。"]'),
('b0a2a5d6-0713-4ac5-b8c0-832478d07551','釣臺三十韻','周密','宋','宋诗','song-poetry','','[]','沛公三尺劍，欲溺章甫冠。',288,'全唐诗/poet.song.236000.json','["沛公三尺劍，欲溺章甫冠。", "莫致魯二生，佐命惟彭韓。", "舉世尚功利，有若蜹慕酸。", "末造不可支，問璽生雄姦。", "真人握赤符，援臂鼎再安。", "灼知受病源，極力回狂瀾。", "異時南陽親，緣附攀龍翰。", "矧如吾子陵，久要平生歡。", "何至變姓名，坐釣七里灘。", "三聘始一往，矯矯如孤鸞。", "惟知貴天爵，不羨人間官。", "欲爲故人留，終愧負素餐。", "而況故人情，安保不易闌。", "君房真癡人，乃欲相控摶。", "醉後偶伸足，豈料星象干。", "始知市朝隘，不及山林寬。", "歸來富春山，山色終耐看。", "豈無秦山商，亦有周谿磻。", "出處雖不同，同在濟世難。", "先生意有在，未易淺近觀。", "東都貴節義，公實闓其端。", "流風數百載，猶足媿老瞞。", "雲臺不可畫，漢史不可刊。", "至今桐江魚，不上俗士竿。"]'),
('7a1235b5-a2c4-49d9-b045-8cd5f5f91384','杼山村舍','周密','宋','宋诗','song-poetry','','[]','石田餘數畝，茅屋小三椽。',48,'全唐诗/poet.song.236000.json','["石田餘數畝，茅屋小三椽。", "雞犬桃源外，桑麻渭水邊。", "刳松分野蜜，筧竹引山泉。", "便可隨君隠，居然謝俗緣。"]'),
('9c1ece9d-191b-404b-bcfa-426d94d99ef2','秋霖','周密','宋','宋诗','song-poetry','','[]','久客驚秋老，愁聞積日霖。',48,'全唐诗/poet.song.236000.json','["久客驚秋老，愁聞積日霖。", "巷泥妨馬足，庭草聚蛩聲。", "俸薄欲饑死，詩清太瘦生。", "未能忘祿養，作賦媿閒情。"]'),
('435784f6-c329-405f-b738-698ad500cd9f','題族伯自醉翁吟稿','周密','宋','宋诗','song-poetry','','[]','淵明千載人，太白一世士。',120,'全唐诗/poet.song.236000.json','["淵明千載人，太白一世士。", "天子呼不來，大吏徵不起。", "十詩九言酒，寧抱凍餓死。", "是豈真醉邪，寓意聊爾耳。", "翁今歠其醨，反騷笑湘水。", "翁醉非物欲，翁醉非勢利。", "物不能醉翁，翁所謂自醉。", "惟翁知其天，醉吟醒時事。", "堪續醉時歌，可補醉鄉記。", "請誦小阮詩，庶識醉翁意。"]'),
('8d5182d5-5332-45c3-b1d1-4e0b45cd68a9','題江山萬里圖','周密','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','暮雨朝雲巫峽夢，西風落葉洞庭秋。',32,'全唐诗/poet.song.236000.json','["暮雨朝雲巫峽夢，西風落葉洞庭秋。", "扁舟兩屐終多事，短軸明窗且卧遊。"]'),
('8a7c5ad1-7c3c-4802-b1bf-57021cafd59a','次雪林春日雜題','周密','宋','宋诗','song-poetry','','[]','落日餘寒鎖水城，汀洲綠遍客空驚。',32,'全唐诗/poet.song.236000.json','["落日餘寒鎖水城，汀洲綠遍客空驚。", "年來懶作尋芳夢，一樹閒花任蝶爭。"]'),
('dc6ebd10-40b8-4040-8724-1b0fda9bdb81','病中寄二隠','周密','宋','宋诗','song-poetry','','[]','名途塵海浩難親，黄葉門前一尺深。',64,'全唐诗/poet.song.236000.json','["名途塵海浩難親，黄葉門前一尺深。", "五畝桑麻荒舊隠，十年書劍負初心。", "客愁不奈貧多感，老色偏隨病見侵。", "奏賦相如今白首，倦游空有茂陵吟。"]'),
('cf9c6213-7a3b-4ad9-ad10-e5e4fc5b8305','二隠皆有和篇因再用韻','周密','宋','宋诗','song-poetry','','[]','貧無知己老無親，踸踔空憐涉世深。',64,'全唐诗/poet.song.236000.json','["貧無知己老無親，踸踔空憐涉世深。", "種藥漸爲衰晚計，對花銷盡少年心。", "牛衣忍病寒初覺，蠹簡翻愁雨半侵。", "平昔結交惟二仲，折梅時寄短長吟。"]'),
('de768514-81ce-4840-88d8-ba89c4327b6e','夜坐','周密','宋','宋诗','song-poetry','','[]','豆花籬落候蟲鳴，斜月分秋到研屏。',32,'全唐诗/poet.song.236000.json','["豆花籬落候蟲鳴，斜月分秋到研屏。", "露滴斜河凉不寐，自將蓮漏驗中星。"]'),
('8878e372-ce08-495b-994d-a4911f940e8d','讀舒王集二首  其一','周密','宋','宋诗','song-poetry','','[]','談王公所期，言霸世亦賤。',24,'全唐诗/poet.song.236000.json','["談王公所期，言霸世亦賤。", "不意周官書，僅似商君傳。"]'),
('31da76ef-402a-44ae-87fb-7f0d945ca679','讀舒王集二首  其二','周密','宋','宋诗','song-poetry','','[]','周易誤輔嗣，本草誤隠居。',24,'全唐诗/poet.song.236000.json','["周易誤輔嗣，本草誤隠居。", "遂令後世人，不能盡信書。"]'),
('a0f7db2a-3a71-426f-bb2a-b383b07264ce','小酌','周密','宋','宋诗','song-poetry','','[]','禁烟時節燕來初，對此新晴釂一壺。',32,'全唐诗/poet.song.236000.json','["禁烟時節燕來初，對此新晴釂一壺。", "二十四番花信了，不知更有峭寒無。"]'),
('595269ff-7299-43cd-a951-c36e6ee56aaa','題三友圖','周密','宋','宋诗','song-poetry','','[]','冰霜交潔玉橫陳，誰主群芳歲晚盟。',32,'全唐诗/poet.song.236000.json','["冰霜交潔玉橫陳，誰主群芳歲晚盟。", "賈傅弔平皮悼賈，三君千古一家清。"]'),
('ccbfe4af-4cc1-49b8-b255-bdc8bb93a895','擬古呈存翁二首  其一','周密','宋','宋诗','song-poetry','','[]','大明照率土，物物資輝光。',48,'全唐诗/poet.song.236000.json','["大明照率土，物物資輝光。", "萬彙有不齊，一氣鼓混茫。", "紛華與萎薾，巨細靡可常。", "驪珠晦滄海，何異錐處囊。"]'),
('e93bb3b1-cdfc-472c-bc9a-7d5de8ba27dd','擬古呈存翁二首  其二','周密','宋','宋诗','song-poetry','','[]','端居閲群動，造物無時閒。',48,'全唐诗/poet.song.236000.json','["端居閲群動，造物無時閒。", "群動不自覺，妍醜紛兩間。", "萌達至枯槁，日夕常循環。", "嗟嗟水東流，去海聲潺湲。"]'),
('c85f452d-9120-496c-b81e-172940f7e587','四皓','周密','宋','宋诗','song-poetry','','[]','避時不肯作秦民，採藥餐芝幾度春。',32,'全唐诗/poet.song.236000.json','["避時不肯作秦民，採藥餐芝幾度春。", "一出可憐隨祿産，商山松竹定疑人。"]'),
('b47a29ae-b563-48e9-bcdd-fb7bb654208c','秋夕懷','周密','宋','宋诗','song-poetry','','[]','露草寒螿夜夜愁，病懷無語獨驚秋。',32,'全唐诗/poet.song.236000.json','["露草寒螿夜夜愁，病懷無語獨驚秋。", "二千里外今宵月，誰倚西風十二樓。"]'),
('3c08bfdd-46c3-4509-8bbf-91647cddbb07','送柳下惠上人遊維揚訪孫制參道子','周密','宋','宋诗','song-poetry','','[]','衮衮天機新，𤁳𤁳淮水流。',120,'全唐诗/poet.song.236000.json','["衮衮天機新，𤁳𤁳淮水流。", "青纏繫白足，又踏淮南州。", "淮南古形勝，屹立東諸侯。", "三生杜牧之，談笑籌邊樓。", "據鞍草書檄，醉袖藏吳鉤。", "子非功名人，負笈將安求。", "及此瓊花春，聊作方外游。", "北道有主人，行李當無憂。", "臨分祈贈言，意重嗟難酬。", "日暮多碧雲，令人思惠休。"]'),
('b19e1bcb-b272-4211-b02c-a4603cc17291','登垂虹亭二首  其一','周密','宋','宋诗','song-poetry','','[]','水國生涯一釣輪，荻芽鱸鱠四時新。',32,'全唐诗/poet.song.236000.json','["水國生涯一釣輪，荻芽鱸鱠四時新。", "安知白首滄洲客，不是三高行輩人。"]'),
('5b99b4b5-8052-4d3e-ba31-656cc27f1a7f','登垂虹亭二首  其二','周密','宋','宋诗','song-poetry','','[]','岸草江花萬古春，感今懷昔最傷神。',32,'全唐诗/poet.song.236000.json','["岸草江花萬古春，感今懷昔最傷神。", "不知一片垂虹月，照却凭欄幾許人。"]'),
('8ebe266a-3400-461b-96fe-02c90b6ea62b','題畫卷六言','周密','宋','宋诗','song-poetry','','[]','嵐翠山藏野寺，夕陽舟倚汀沙。',28,'全唐诗/poet.song.236000.json','["嵐翠山藏野寺，夕陽舟倚汀沙。", "一段三湘晚色，白雲深處誰家。"]'),
('55ff2286-e428-4227-a140-d75823b6b618','秋夜五言','周密','宋','宋诗','song-poetry','','[]','雨餘寒碧深，空烟滿庭竹。',24,'全唐诗/poet.song.236000.json','["雨餘寒碧深，空烟滿庭竹。", "深掩讀書燈，莫惱秋禽宿。"]'),
('9598e9ef-460e-4776-a277-d05557f6035d','春晚','周密','宋','宋诗','song-poetry','','[]','㶁㶁泉聲遠，流春到水涯。',24,'全唐诗/poet.song.236000.json','["㶁㶁泉聲遠，流春到水涯。", "東風千萬恨，片片逐飛花。"]'),
('05cc75e2-e044-4a1b-b1db-1bf1f276cd78','試闈即事','周密','宋','宋诗','song-poetry','','[]','讀書窗暗日西斜，鎖棘門深噪晚鴉。',32,'全唐诗/poet.song.236000.json','["讀書窗暗日西斜，鎖棘門深噪晚鴉。", "又是一番秋事了，粉黄如雪落槐花。"]'),
('649b25fb-6b14-48d0-82b8-319d9ad6aed4','擬長吉十二月樂辭 正月','周密','宋','宋诗','song-poetry','','[]','八埏夢醒驚勾芒，青旂翠節迎東皇。',64,'全唐诗/poet.song.236000.json','["八埏夢醒驚勾芒，青旂翠節迎東皇。", "柔風玉破第一香，明霞院宇懸金璫。", "蘭唇笑紅草心喜，七十二番芳候始。", "流蘇夜暖催羯鼓，日日梨園按新舞。"]'),
('76246c8f-c514-48cf-9215-807fe93def57','擬長吉十二月樂辭 二月','周密','宋','宋诗','song-poetry','','[]','一綠浮千郊，新風新雨吹秧毛。',70,'全唐诗/poet.song.236000.json','["一綠浮千郊，新風新雨吹秧毛。", "倉庚玄乙聲交交，愁心亂結丁香梢。", "錦衣俠少千金豪，買春不怕春價高，量珠戛玉聲嘈嘈。", "青春青春急行樂，莫待紅泥埋馬脚。"]'),
('ec93e194-7c44-44d2-bdca-b45bdb673ac5','擬長吉十二月樂辭 三月','周密','宋','宋诗','song-poetry','','[]','大堤韋曲芳菲菲，麴塵粉絮迷東西。',80,'全唐诗/poet.song.236000.json','["大堤韋曲芳菲菲，麴塵粉絮迷東西。", "榆烟梨月烘夜白，春國染花成五色。", "餳簫社鼓歡拍拍，五侯七貴爭芳夕。", "烏絲細織留春語，怨血千枝吟杜主。", "翠樓歌冷粉魂愁，一夜東風落薌雨。"]'),
('5d930af6-6aca-448c-9610-37a166018c7f','擬長吉十二月樂辭 四月','周密','宋','宋诗','song-poetry','','[]','半夜蒼龍移玉斗，朱絲乍變南風奏。',56,'全唐诗/poet.song.236000.json','["半夜蒼龍移玉斗，朱絲乍變南風奏。", "女桑再綠竹箘紅，三十六陂烟雨中。", "香塵脂水隨宮溝，謝娘掩幌鶑鶑愁。", "翠濤千里崆峒秋。"]'),
('9bf1045c-7317-4cef-8448-3caa76b36d21','擬長吉十二月樂辭 五月','周密','宋','宋诗','song-poetry','','[]','阿房守宮血，太液鴛鴦湯。',48,'全唐诗/poet.song.236000.json','["阿房守宮血，太液鴛鴦湯。", "新螢小扇輕，老艾生羅香。", "鑄月爲君壽，壓雪爲君醉。", "波底吟饑龍，菖華一千歲。"]'),
('3b54fdf8-873f-4052-8620-a5b90b6ea6dc','擬長吉十二月樂辭 六月','周密','宋','宋诗','song-poetry','','[]','三庚來，二陰伏，六十刻長日南陸。',40,'全唐诗/poet.song.236000.json','["三庚來，二陰伏，六十刻長日南陸。", "榑桑石裂海水飛，飆車雪碗方爭奇，秋聲隠隠檉桐枝。"]'),
('ae810a35-4d1c-4166-91d7-d5c6732ac16e','擬長吉十二月樂辭 七月','周密','宋','宋诗','song-poetry','','[]','商旗稍西指，赤幟方癡停。',60,'全唐诗/poet.song.236000.json','["商旗稍西指，赤幟方癡停。", "餘霞散蝦尾，凈宇浮魚鱗。", "羽梁駕查渚，綺屋開蓉城。", "輕霏洗空綠，一葉敲凉聲。", "綀帷掩塵扇，壯士心空驚。"]'),
('771b2cd9-9201-4a40-9f34-c85891801346','擬長吉十二月樂辭 八月','周密','宋','宋诗','song-poetry','','[]','銛飆剪庭綠，紺髮愁清商。',48,'全唐诗/poet.song.236000.json','["銛飆剪庭綠，紺髮愁清商。", "吹銀海沫明，濯錦江花凉。", "冰規射白曉，琪樹蜚黄香。", "楚夢空悠悠，遠恨浮三湘。"]'),
('c16cbcde-5719-409e-8a9a-d6572cbc084e','擬長吉十二月樂辭 九月','周密','宋','宋诗','song-poetry','','[]','飛蓬病葉聲索索，暗壁孀娥夢中泣。',64,'全唐诗/poet.song.236000.json','["飛蓬病葉聲索索，暗壁孀娥夢中泣。", "蟲聲螢影伴寒雨，二十三絲夜彈苦。", "千花翻紅上凉葉，萬寶吹香落金雪。", "佩萸戲馬誰家郎，不管人間更漏長。"]'),
('41ef083b-5810-4186-9d30-8100c50e94be','擬長吉十二月樂辭 十月','周密','宋','宋诗','song-poetry','','[]','枯桑委地成死灰，蘋洲客雁號朝饑。',56,'全唐诗/poet.song.236000.json','["枯桑委地成死灰，蘋洲客雁號朝饑。", "崦嵫急景寸輝薄，夜半霜痕着綃箔。", "金寒翠薄千尺臺，笑梅一笛臨風哀，佳人佳人來不來。"]'),
('25ff9037-6c72-4179-835a-f5e61a1c7885','擬長吉十二月樂辭 十一月','周密','宋','宋诗','song-poetry','','[]','碧筩九寸吹寶瓶，老麋脫角占卿雲。',48,'全唐诗/poet.song.236000.json','["碧筩九寸吹寶瓶，老麋脫角占卿雲。", "酸風射寒入幽素，采采芳芸拂秋蠹。", "繡宮華漏融玉汁，雲母窗明烘暖白。"]'),
('a14cefc4-6b9c-40ab-9405-5ac136e71059','擬長吉十二月樂辭 十二月','周密','宋','宋诗','song-poetry','','[]','雙丸倦擲羲和手，儺鼓烘爐傳壽酒。',32,'全唐诗/poet.song.236000.json','["雙丸倦擲羲和手，儺鼓烘爐傳壽酒。", "莫驚錦瑟換華年，東風已入吳宮柳。"]'),
('a8e2ac90-c2f2-4cc3-a2c1-7f41d0302749','擬長吉十二月樂辭 閏月','周密','宋','宋诗','song-poetry','','[]','靈光舒，積氣餘，左扉虎豹天王居。',48,'全唐诗/poet.song.236000.json','["靈光舒，積氣餘，左扉虎豹天王居。", "杓停兩界槎訊迂，黄楊翠怨桐碧敷。", "赤黄道遥倦烏兔，寶月修圓十三度。"]'),
('289dcc3f-2acf-44cd-aecb-5cc7a1096b22','暑夕放舟有懷茂悅史君','周密','宋','宋诗','song-poetry','','[]','溪凉供野放，機盡狎鷗群。',48,'全唐诗/poet.song.236000.json','["溪凉供野放，機盡狎鷗群。", "風月懷元度，山川憶少文。", "遠峯明過雨，疎樹泊歸雲。", "幽玩情何限，回橈夜已分。"]'),
('5f5cd402-e28c-4787-90bc-3a32583b74f0','江寺送客','周密','宋','宋诗','song-poetry','','[]','送別西風寺，愁添鬢影華。',48,'全唐诗/poet.song.236000.json','["送別西風寺，愁添鬢影華。", "江空回夜汐，岸遠漲秋沙。", "塔古棲雙鸛，檣高立數鴉。", "臨歧一盃酒，回首即天涯。"]'),
('fea618f1-38cb-497e-8961-fbc6cd7bf941','姑蘇臺','周密','宋','宋诗','song-poetry','','[]','望中只尺越來溪，溪上興亡欲問誰。',64,'全唐诗/poet.song.236000.json','["望中只尺越來溪，溪上興亡欲問誰。", "定霸已成嘗膽日，傾城不在捧心時。", "冷楓江遠飄遺恨，秋草臺荒沒舊基。", "堪笑吳傖太癡絕，不讎宰嚭恨西施。"]'),
('3c079058-8e7a-40f6-bac7-1e7d85dc1388','西泠小立即事二首  其一','周密','宋','宋诗','song-poetry','','[]','雨後湖天似水清，斷霞新月兩峯明。',32,'全唐诗/poet.song.236000.json','["雨後湖天似水清，斷霞新月兩峯明。", "西風恰到芙蓉外，過雁初聞第一聲。"]'),
('71d0860a-eccb-4bfb-9c09-79c4de6773bb','西泠小立即事二首  其二','周密','宋','宋诗','song-poetry','','[]','桂風蘭露晚陰清，遠翠空濛去鷺明。',32,'全唐诗/poet.song.236000.json','["桂風蘭露晚陰清，遠翠空濛去鷺明。", "一葉扁舟一彎月，白荷香裏聽蟬聲。"]'),
('b451aef8-d35e-401e-9aaa-4977fa794383','子房二首  其一','周密','宋','宋诗','song-poetry','','[]','漢儲未定若垂旒，誰爲君王借筯籌。',32,'全唐诗/poet.song.236000.json','["漢儲未定若垂旒，誰爲君王借筯籌。", "堪笑商山采芝老，到頭却上子房鈎。"]'),
('8b6ed274-8d3d-4b5b-94c4-c15c6e977b32','子房二首  其二','周密','宋','宋诗','song-poetry','','[]','報韓興漢已封留，辟穀將爲世外遊。',32,'全唐诗/poet.song.236000.json','["報韓興漢已封留，辟穀將爲世外遊。", "四老已歸如意死，不堪人彘戚姬愁。"]'),
('390943b7-4b29-4a80-8458-e85fa8ef72b9','大滌洞天','周密','宋','宋诗','song-poetry','','[]','太虛灝氣浮空濛，烟霞九瑣蓬萊宮。',144,'全唐诗/poet.song.236000.json','["太虛灝氣浮空濛，烟霞九瑣蓬萊宮。", "崩騰雲木競奇險，澗芳野實紛青紅。", "何年斷鰲立天柱，古洞陰森白鴉舞。", "玉書寶劍不可尋，老蘚封崖滴玄乳。", "光芒靈氣干斗牛，遺丹葉下誰能求。", "黄精紫杞遍巖谷，玄霜夜搗聲幽幽。", "老蛟千年睡未足，癡涎吼雷噴飛瀑。", "陰風黑穴吹海腥，石虎當關橫地軸。", "是非萬古一笑嘅，神仙不死今安在。"]'),
('9fa0e069-74d4-40f4-aa63-f0cd212f1321','古塞下曲','周密','宋','宋诗','song-poetry','','[]','塞下棗已紅，胡馬號北風。',152,'全唐诗/poet.song.236000.json','["塞下棗已紅，胡馬號北風。", "傳聞右賢王，萬騎圍雲中。", "雲中太守猛如虎，夜開城門納降虜。", "十丈高旂沉黑雲，一尺捷書飛白羽。", "武皇但喜奏捷頻，豈知白骨高如城。", "邊城百戰勝常少，一勝惟著將軍名。", "將軍成名戰士死，去年戰士今無幾。", "血染黄沙草不青，萬里陰雲哭胡鬼。", "塞下曲，不忍聞，何人爲我達漢君。", "武功本是輔文具，願君偃武而修文。"]'),
('883eb434-8f27-417e-bd61-af8a582e2653','寄梯飆','周密','宋','宋诗','song-poetry','','[]','老樹號北風，索索落枯葉。',72,'全唐诗/poet.song.236000.json','["老樹號北風，索索落枯葉。", "越水多風濤，可望不可涉。", "異地不異情，同此江月明。", "江空少飛雁，莫寄芳洲蘅。", "寸心逐寒潮，日夕流曲折。", "願保青松姿，相期在霜雪。"]'),
('c2ec7c98-2004-4b9c-a35c-3977ae4bc5e0','讀蔡絛雜書有感','周密','宋','宋诗','song-poetry','','[]','私史由來不可馮，老奸危國亦危身。',64,'全唐诗/poet.song.236000.json','["私史由來不可馮，老奸危國亦危身。", "趙奢既已明知子，石碏當求義滅親。", "鐵馬釀成天寶禍，銅駝空想汴都春。", "九京未正鞭尸罪，尚欲欺天罔後人。"]'),
('95367dde-deac-434a-a347-c0464b785aa4','三衢道中','周密','宋','宋诗','song-poetry','','[]','舊遊重過處，倒指七年間。',48,'全唐诗/poet.song.236000.json','["舊遊重過處，倒指七年間。", "水後人家少，時荒客路艱。", "雨聲愁夜店，雲影占春山。", "景物關心事，無成愧往還。"]'),
('4c8f166b-fc5f-4e52-ad4d-8b3cbfa00397','馮唐廟','周密','宋','宋诗','song-poetry','','[]','自古英雄遇者稀，爲郎未是不逢時。',32,'全唐诗/poet.song.236000.json','["自古英雄遇者稀，爲郎未是不逢時。", "江湖亦有如公者，兩鬢蒼蒼理釣絲。"]'),
('f368dc00-d9c5-4d91-9117-b3e9a378c8da','秋晚懷歸','周密','宋','宋诗','song-poetry','','[]','逝水歸雲日夜流，倚欄心事共悠悠。',64,'全唐诗/poet.song.236000.json','["逝水歸雲日夜流，倚欄心事共悠悠。", "黄棲露畝稻粱晚，紅染霜林橡栗秋。", "日月不閑雙鬢老，風埃長滿百年愁。", "故山薇長無人采，有媿平生馬少游。"]'),
('41c83d50-0a99-4898-b6dc-e0de74c0dce2','山行即事','周密','宋','宋诗','song-poetry','','[]','小艇輕輿野興長，澗芹山蕨入奩香。',64,'全唐诗/poet.song.236000.json','["小艇輕輿野興長，澗芹山蕨入奩香。", "雨銷蝶粉何郎瘦，日醉蜂脾小杜狂。", "科斗水肥春浸穀，杜鵑花發曉剶桑。", "詩成自寫村家壁，底用奚奴負錦囊。"]'),
('7e04d1cd-d567-4cbc-980e-9cc3b119f4e0','春閨怨','周密','宋','宋诗','song-poetry','','[]','斜立倚東風，雙眉對春怯。',24,'全唐诗/poet.song.236000.json','["斜立倚東風，雙眉對春怯。", "何處卜歸期，花邊數飛蝶。"]'),
('6e02c8ea-6fbe-453a-993e-8b45639fd1a7','夢仙','周密','宋','宋诗','song-poetry','','[]','有美人兮山之陽，步秋翠兮搴孤芳。',180,'全唐诗/poet.song.236000.json','["有美人兮山之陽，步秋翠兮搴孤芳。", "姿綽約兮瑩冰霜，珮珊珊兮摇明璫。", "婉相顧兮袂載揚，聞語笑兮春風香。", "口授余兮長生方，將俾爾兮壽而康。", "黄鵠舞兮白雲翔，殷空半兮鳴琳琅。", "隔一水兮遥相望，欲往從之兮無津梁。", "天風吹髮兮毛骨凉，萬籟發兮響笙篁。", "恍身世兮俱相忘，驚夢幻兮意自傷。", "覺山川兮阻且長，感遊子兮思故鄉。", "白露滴兮月在牀，五湖秋晚兮木葉黄。", "蘭可佩兮荷可裳，仰天一笑兮歌滄浪。"]'),
('d8d9eb4e-7193-496f-87a0-689797f0ce2d','春晴散策','周密','宋','宋诗','song-poetry','','[]','閉門十日雨，芳塵作泥淖。',132,'全唐诗/poet.song.236000.json','["閉門十日雨，芳塵作泥淖。", "晚窗見晴霞，恍如夢初覺。", "平生野放意，山水乃所樂。", "駕言出幽尋，風前放輕棹。", "千峰沐新翠，仍着微雲罩。", "紅碧達勾萌，剸裁出天巧。", "閒知物情適，靜覺生意閙。", "一鳥啼芳陰，悠然識春貌。", "俛仰成古今，人生多踸踔。", "要當了此理，外物非所撓。", "醉中歌長歌，萬事不足校。"]'),
('fa4c9d03-db44-475b-9f4f-3e0eff6fcc13','春夜','周密','宋','宋诗','song-poetry','','[]','晚煙歸柳綠條苗，客館春寒夜寂寥。',32,'全唐诗/poet.song.236000.json','["晚煙歸柳綠條苗，客館春寒夜寂寥。", "夢又不成花又落，月明分付可憐宵。"]'),
('093cba4e-8d2a-4843-b16b-90a1b3aab1be','鷗汎','周密','宋','宋诗','song-poetry','','[]','苕邊鷗汎處，浄綠晝愔愔。',48,'全唐诗/poet.song.236000.json','["苕邊鷗汎處，浄綠晝愔愔。", "老柳花狼藉，新秧水淺深。", "煙生遥岸白，雲過半溪陰。", "容與歸橈晚，閑鶑相棹吟。"]'),
('964c625a-7ff9-403f-a576-8bd358d09771','吳季子墓闕','周密','宋','宋诗','song-poetry','','[]','百世人傳十字碑，春秋聖筆著褒辭。',32,'全唐诗/poet.song.236000.json','["百世人傳十字碑，春秋聖筆著褒辭。", "龜趺十丈知何用，徒使劉叉笑退之。"]'),
('ec624494-8d61-4290-8ee6-3b9500b94a44','魯公乞米帖','周密','宋','宋诗','song-poetry','','[]','當年食粥老尚書，乞米長安李大夫。',32,'全唐诗/poet.song.236000.json','["當年食粥老尚書，乞米長安李大夫。", "饑死只今誰裹飯，可憐曼倩羨侏儒。"]'),
('1d1e0b81-54d2-402b-b229-a802a515f8fc','幽居春晚','周密','宋','宋诗','song-poetry','','[]','幽棲塵不到吟邊，閑愛抄書靜愛禪。',64,'全唐诗/poet.song.236000.json','["幽棲塵不到吟邊，閑愛抄書靜愛禪。", "墨本雙鈎臨曲水，素琴三疊憶斜川。", "筍簪雨足初抽玉，柳繭春寒未漂綿。", "病懶不生槐蟻夢，西疇種秫北窗眠。"]'),
('353fbd96-e7ca-4735-b336-93e040f64c25','小遊仙七首  其一','周密','宋','宋诗','song-poetry','','[]','金母雲軿宴紫樓，露寒仙掌漢宮秋。',32,'全唐诗/poet.song.236000.json','["金母雲軿宴紫樓，露寒仙掌漢宮秋。", "笑渠劉徹無仙骨，種得桃成已白頭。"]'),
('8499a003-a55d-473b-ba1b-8715ae2f77bc','小遊仙七首  其二','周密','宋','宋诗','song-poetry','','[]','紫霧彤雲滃九關，玉庭侵曉引仙班。',32,'全唐诗/poet.song.236000.json','["紫霧彤雲滃九關，玉庭侵曉引仙班。", "東皇奏罷回寅疏，放散春光下世間。"]'),
('1996faf1-ca22-427c-8eed-244b62501655','小遊仙七首  其三','周密','宋','宋诗','song-poetry','','[]','西池宴罷夜深歸，風露森森濕羽衣。',32,'全唐诗/poet.song.236000.json','["西池宴罷夜深歸，風露森森濕羽衣。", "雲外鳳皇棲未穩，一聲鐵笛又驚飛。"]'),
('90ba8c20-074e-450f-8aa5-79c834a61fcf','小遊仙七首  其四','周密','宋','宋诗','song-poetry','','[]','拋了天官作散仙，却來雲外種瓊田。',32,'全唐诗/poet.song.236000.json','["拋了天官作散仙，却來雲外種瓊田。", "洞中日月無拘管，閒引青龍耕翠煙。"]'),
('c9d2d15a-7231-4468-8355-65010b72c95a','小遊仙七首  其五','周密','宋','宋诗','song-poetry','','[]','一徑松花滿路香，琤琤玉杵搗玄霜。',32,'全唐诗/poet.song.236000.json','["一徑松花滿路香，琤琤玉杵搗玄霜。", "有時騎鶴月中去，流水白雲生晚凉。"]'),
('babc54eb-b996-46a5-ad3e-8f843cd88853','小遊仙七首  其六','周密','宋','宋诗','song-poetry','','[]','一笛吹雲鶴夜歸，九天清露冷仙衣。',32,'全唐诗/poet.song.236000.json','["一笛吹雲鶴夜歸，九天清露冷仙衣。", "琪花千樹風零落，應去人間作雪飛。"]'),
('9dc1ea2e-7800-4365-a8d4-9ebaba91c400','小遊仙七首  其七','周密','宋','宋诗','song-poetry','','[]','碧海沉沉海上山，山頭樓觀五雲間。',32,'全唐诗/poet.song.236000.json','["碧海沉沉海上山，山頭樓觀五雲間。", "人間方士多無頼，故把釵鈿戲阿環。"]'),
('f4a23985-1cbe-481d-9961-794e54562cce','金陵懷古','周密','宋','宋诗','song-poetry','','[]','遠岸商歌不忍聽，恨隨纖草滿沙汀。',64,'全唐诗/poet.song.236000.json','["遠岸商歌不忍聽，恨隨纖草滿沙汀。", "春歸王謝空堂燕，風散齊梁廢苑螢。", "紫蓋黄旗人寂寞，瓊枝璧月事飄零。", "新亭風景時時異，惟有垂楊似舊青。"]'),
('9cca21f6-ab09-4dca-95a4-4c14030264b0','次韵玉臺體二首  其一','周密','宋','宋诗','song-poetry','','[]','一點傷春恨，東風罨畫樓。',24,'全唐诗/poet.song.236000.json','["一點傷春恨，東風罨畫樓。", "不知緣底事，敲碎玉搔頭。"]'),
('b31ac789-a0d1-456f-b792-1a2b857c8cb9','次韵玉臺體二首  其二','周密','宋','宋诗','song-poetry','','[]','柳陰隨意綠，花片惱人香。',24,'全唐诗/poet.song.236000.json','["柳陰隨意綠，花片惱人香。", "靜院無來客，遊絲百尺長。"]'),
('ba3bdf4d-69c7-4bcd-b893-584ab3ba5919','烟脂井','周密','宋','宋诗','song-poetry','','[]','急奏留床下，君王醉未看。',24,'全唐诗/poet.song.236000.json','["急奏留床下，君王醉未看。", "應嫌江表窄，不及井中寬。"]'),
('7214bc47-5040-4a55-bb42-89a1373ce9d8','西余秋晚','周密','宋','宋诗','song-poetry','','[]','豐年雞犬飽，斜日閉柴荆。',48,'全唐诗/poet.song.236000.json','["豐年雞犬飽，斜日閉柴荆。", "父祖自三代，耕桑了一生。", "病梨山蟻聚，落葉野禽驚。", "喜客來城市，新蔬薦早秔。"]'),
('1a91bf8b-ccd1-47c2-9a6c-a364871b81a1','挽顧徵君','周密','宋','宋诗','song-poetry','','[]','白髮蒼眉古典刑，著書未省出山扃。',64,'全唐诗/poet.song.236000.json','["白髮蒼眉古典刑，著書未省出山扃。", "嘗從康節傳三易，頗效河汾續五經。", "方喜朝頒遺逸詔，忽聞月犯少微星。", "大書誰草徂徠傳，豐碣新添貞曜銘。"]'),
('1bb53917-3ced-4e0f-ad7f-a41a73a8c7e2','挽王茂悅提舶二首  其一','周密','宋','宋诗','song-poetry','','[]','清氣鍾全蜀，風流壓盛唐。',48,'全唐诗/poet.song.236000.json','["清氣鍾全蜀，風流壓盛唐。", "騷香薰屈宋，筆艷映鍾王。", "麾節平生夢，人琴一旦亡。", "卜居方有賦，埋玉重堪傷。"]'),
('95272c49-ba37-4b51-ae0c-49a3df793483','挽王茂悅提舶二首  其二','周密','宋','宋诗','song-poetry','','[]','洛社忘年契，惟公最己知。',48,'全唐诗/poet.song.236000.json','["洛社忘年契，惟公最己知。", "誦言司馬賦，喜說項斯詩。", "問字時携酒，鉤玄共訂碑。", "豈期三日別，遽作百年悲。"]'),
('288b4450-ee99-4c2a-8a43-fe6940dbcb8e','挽趙子真別駕','周密','宋','宋诗','song-poetry','','[]','赫奕諸王後，清貧一士同。',48,'全唐诗/poet.song.236000.json','["赫奕諸王後，清貧一士同。", "樓成召長吉，山裂夢虛中。", "及子員郎澤，能詩伯氏風。", "琅玕嗟早折，魂不到安東。"]'),
('1d2d71ac-50c1-4e26-a801-4ad1e00db8a7','聞鵑','周密','宋','宋诗','song-poetry','','[]','帝魂應識少陵憂，十二山高萬里愁。',32,'全唐诗/poet.song.236000.json','["帝魂應識少陵憂，十二山高萬里愁。", "一自海棠妖血染，玉垣移治在渝州。"]'),
('a8e6d8ac-96a2-422c-96ec-0c0527dd0e40','游下竺示僧','周密','宋','宋诗','song-poetry','','[]','野褐芒鞋六尺藤，好溪山處幾番登。',32,'全唐诗/poet.song.236000.json','["野褐芒鞋六尺藤，好溪山處幾番登。", "明朝又復歸城市，百畝松風屬老僧。"]'),
('4a09d281-7bfc-4989-9e94-28278be736bf','閶門夜發','周密','宋','宋诗','song-poetry','','[]','春露霑衣夜氣濃，吳波不動柳無風。',32,'全唐诗/poet.song.236000.json','["春露霑衣夜氣濃，吳波不動柳無風。", "倚篷覓句清無寐，一片蛙聲月色中。"]'),
('502d64b4-6d96-4280-b889-a26264a10187','紫霞翁觴客東園列燭花外秋林散影高堂素壁皆粲然李成韋偃寒林畫圖發新奇於摇落前所未有因作歌以紀之','周密','宋','宋诗','song-poetry','','[]','隋園剪綵未足奇，秋林燭彩光參差。',160,'全唐诗/poet.song.236000.json','["隋園剪綵未足奇，秋林燭彩光參差。", "龍蛇四壁不可捕，顛張醉墨驚淋漓。", "齊奴金谷珊瑚樹，如意擊碎光陸離。", "阿環錦院織綃手，連機隠出千花枝。", "迷樓鏡屏照前後，宮釵舞袂相紛披。", "月中老桂冷轇轕，山河影滿玉兔悲。", "江潭無風映雲樹，水藻漾日浮漣漪。", "初疑營丘擅工妙，細玩自笑真兒嬉。", "世間無物非幻化，露電泡影何足疑。", "誰能喚起洪谷子，寫此清絕圖屏帷。"]'),
('b14e1177-3797-4346-bc44-9dcf4a3f0c8c','泛舟','周密','宋','宋诗','song-poetry','','[]','老火濁不流，熱惱無可避。',288,'全唐诗/poet.song.236000.json','["老火濁不流，熱惱無可避。", "駕言清谿濱，濯纓稅塵轡。", "扁舟無定遊，放纜任其至。", "蕩槳三匯交，空明發清思。", "摘鮮得野實，釣水投香餌。", "碧筩注芳酒，湘匳薦新芰。", "主賓略酬酢，冷暖隨所嗜。", "須臾月輪上，煙水合空翠。", "清風真可人，意厚萬金施。", "露葉生輝光，水華多嫵媚。", "欲拍洪崖肩，欲挽湘君帔。", "雖無管絃樂，一洗世俗僞。", "清彈發鄰舸，暗攪潛虬睡。", "應作蜩蛙觀，亦足助幽致。", "豈惟家山樂，要是會心地。", "熱官豈辦此，未易輕擬議。", "我年未四十，齒髮已顦顇。", "往者不可追，來者何可覬。", "富貴難幸求，歲月不少置。", "於此貧賤中，此樂已不啻。", "鶴長與鳬短，造物正兒戲。", "功名類蟻夢，身世等萍寄。", "百年幾良晤，何暇計榮悴。", "縱有身後名，不博今夕醉。"]'),
('7dd86b10-0d02-428f-b049-2c6119b68a9e','嘲少年','周密','宋','宋诗','song-poetry','','[]','步障飛韉事俊遊，錦圍簫鼓按凉州。',32,'全唐诗/poet.song.236000.json','["步障飛韉事俊遊，錦圍簫鼓按凉州。", "海棠枝上千枝蠟，肯信人間有暮愁。"]'),
('96f972a0-e745-45a3-827d-d0031298163d','塘西秋晚','周密','宋','宋诗','song-poetry','','[]','野市維梢處，長天弄夕陰。',48,'全唐诗/poet.song.236000.json','["野市維梢處，長天弄夕陰。", "蟹寒依客柁，鴉晚集神林。", "苕老飄吳雪，橙香墜楚金。", "浩然湖海思，重賦故山吟。"]'),
('b2ca798b-8c10-438c-9965-12d098c92fca','春寒','周密','宋','宋诗','song-poetry','','[]','柘葉煙濃乍起蠶，楝花風冷已聞鵑。',32,'全唐诗/poet.song.236000.json','["柘葉煙濃乍起蠶，楝花風冷已聞鵑。", "病來應被垂楊笑，三月春衣未褪綿。"]'),
('337665de-5038-4fb8-9faf-853577f9e2cf','元夕被雨病中有感  其一','周密','宋','宋诗','song-poetry','','[]','病懷惟與靜相便，盡把歡遊乞少年。',32,'全唐诗/poet.song.236000.json','["病懷惟與靜相便，盡把歡遊乞少年。", "沉水一爐詩一卷，細聽春雨枕書眠。"]'),
('540ae3a2-2829-45a6-a0c2-7be98fe172b7','元夕被雨病中有感  其二','周密','宋','宋诗','song-poetry','','[]','鄰簫街鼓遠相聞，猶憶天街五夜春。',32,'全唐诗/poet.song.236000.json','["鄰簫街鼓遠相聞，猶憶天街五夜春。", "二十年間遊冶事，青燈閑照白頭人。"]'),
('0ef99c02-1e0d-4ea6-82b4-0f83fc991328','沈仁可惠看燈蟹','周密','宋','宋诗','song-poetry','','[]','君不見天上妖蟆食天目，怪語空號玉川客。',166,'全唐诗/poet.song.236000.json','["君不見天上妖蟆食天目，怪語空號玉川客。", "萬古何傷明月明，可笑妖蟆終受磔。", "又不見人間癡蝶掩夜燈，焦頭爛額恃己能。", "烹煎不免取奇禍，虧蔽徒取人之憎。", "二蟲何知乃至此，飛走不能逃一死。", "附炎觸熱正可憐，喘殺人間褦襶子。", "草泥夜黑溪火明，挺矛衷甲方橫行。", "舉烽止博褒姒笑，投穽何異長平坑。", "我憐公子本無罪，人之不仁非自致。", "便爲移封到酒泉，喚取麴生同一醉。"]'),
('47ff3272-9980-4f2c-a9ce-94473f6f0107','題惠崇並禽圖','周密','宋','宋诗','song-poetry','','[]','雪盡江南二月初，並禽高下自相呼。',32,'全唐诗/poet.song.236000.json','["雪盡江南二月初，並禽高下自相呼。", "靜中樂意無人見，一片春聲在畫圖。"]'),
('42aa719e-189c-489c-92cc-ebc57d74ad33','挽吳承務二首  其一','周密','宋','宋诗','song-poetry','','[]','種德勤穮蔉，終能穫歲康。',48,'全唐诗/poet.song.236000.json','["種德勤穮蔉，終能穫歲康。", "經傳韋氏業，善著鄭公鄉。", "議論參諸老，功名付二郎。", "美哉天目水，流作慶源長。"]'),
('7a358079-cfb0-4272-96f0-208401d69b02','挽吳承務二首  其二','周密','宋','宋诗','song-poetry','','[]','道義真堪貴，弓旌不受招。',48,'全唐诗/poet.song.236000.json','["道義真堪貴，弓旌不受招。", "五全洪範福，四見太平朝。", "問絕趨庭對，愁聞祖道簫。", "哀榮無一憾，豐碣在山椒。"]'),
('a7fb57f7-f616-4c26-ab3e-3dea75ce6e5d','寫懷偶成二首  其一','周密','宋','宋诗','song-poetry','','[]','少不如人奈老何，早衰多病鬢雙皤。',64,'全唐诗/poet.song.236000.json','["少不如人奈老何，早衰多病鬢雙皤。", "無親可共耕緜上，有子堪同讀善和。", "妄想不生騎鶴夢，高情時有飯牛歌。", "釣遊閑事無人見，長剪漁竿短結莎。"]'),
('90c3f29b-b44a-47e7-9bf6-fc0f9bf61944','寫懷偶成二首  其二','周密','宋','宋诗','song-poetry','','[]','夢裏區區較短長，雞蟲得失最堪傷。',64,'全唐诗/poet.song.236000.json','["夢裏區區較短長，雞蟲得失最堪傷。", "不知貞觀凌烟閣，何似南柯審雨堂。", "暮四朝三齊得喪，左蠻右觸幾興亡。", "正須痛飲中山酒，細讀南華第二章。"]'),
('2d7eab8b-5d34-4a85-b425-4470cec2e903','花朝溪上有感昔遊  其一','周密','宋','宋诗','song-poetry','','[]','枕上鳴鳩喚曉晴，綠楊門巷賣花聲。',32,'全唐诗/poet.song.236000.json','["枕上鳴鳩喚曉晴，綠楊門巷賣花聲。", "探芳走馬人雖老，歲歲東風二月情。"]'),
('1ab35558-c36a-49f4-b87e-bcefdd3aa1d2','花朝溪上有感昔遊  其二','周密','宋','宋诗','song-poetry','','[]','畫舫笙簫張水嬉，小紅嬌翠鬭新眉。',32,'全唐诗/poet.song.236000.json','["畫舫笙簫張水嬉，小紅嬌翠鬭新眉。", "多情頼有河橋柳，猶認當年杜牧之。"]'),
('b849edc6-ba8f-418d-8cfd-d1de7829eac3','友人話京都舊游戲成','周密','宋','宋诗','song-poetry','','[]','江湖落魄憶芳年，曾賦名都結客篇。',64,'全唐诗/poet.song.236000.json','["江湖落魄憶芳年，曾賦名都結客篇。", "九陌舞香元夜燭，六橋歌月禁烟船。", "紅簾顧曲纏頭錦，紫陌尋芳買笑錢。", "老去風情渾減盡，一窗聽雨對花眠。"]'),
('13539e2d-e4ca-4278-8411-49eb9650180b','漁臺山','周密','宋','宋诗','song-poetry','','[]','楓葉蘆花外，閑磯带短汀。',48,'全唐诗/poet.song.236000.json','["楓葉蘆花外，閑磯带短汀。", "風翻荷淺白，霜隕柳殘青。", "機事鷗浮沒，生涯酒醉醒。", "暮榔和夜笛，餘韵最堪聽。"]'),
('1e7511fe-d544-4df7-a418-671d0db920ad','南郊慶成口號二十首  其一','周密','宋','宋诗','song-poetry','','[]','親郊詔下半年前，正是咸淳第二年。',32,'全唐诗/poet.song.236000.json','["親郊詔下半年前，正是咸淳第二年。", "執玉奉璋來萬國，息烽歸馬靜三邊。"]'),
('a9619d70-9617-4a1b-acab-8bcb9c1e0ee0','南郊慶成口號二十首  其二','周密','宋','宋诗','song-poetry','','[]','別殿齋居極敬嚴，外庭職祭亦精虔。',32,'全唐诗/poet.song.236000.json','["別殿齋居極敬嚴，外庭職祭亦精虔。", "事天以實無科擾，應辦全支內帑錢。"]'),
('518a27c9-8ad0-452c-b0e0-517396852239','南郊慶成口號二十首  其三','周密','宋','宋诗','song-poetry','','[]','上界鉤陳護屬車，繡衣鹵簿列旌旟。',32,'全唐诗/poet.song.236000.json','["上界鉤陳護屬車，繡衣鹵簿列旌旟。", "駕頭已近鳴鞭急，一路迎鑾奏起居。"]'),
('e64b66e6-daf9-45bd-a5ed-758a184a31b6','南郊慶成口號二十首  其四','周密','宋','宋诗','song-poetry','','[]','行門贊唱似吹笙，號諾連珠繞禁城。',32,'全唐诗/poet.song.236000.json','["行門贊唱似吹笙，號諾連珠繞禁城。", "五使按臨嚴柝靜，夜深初聽警場聲。"]'),
('529c961e-6c95-4d3c-8473-6b617b96b2e6','南郊慶成口號二十首  其五','周密','宋','宋诗','song-poetry','','[]','和氣排冬午夜春，列星呈瑞午階明。',32,'全唐诗/poet.song.236000.json','["和氣排冬午夜春，列星呈瑞午階明。", "千官執玉蕭薌遠，靜聽登歌奏六成。"]'),
('09641c57-09f0-48d9-80db-0165c376c9cb','南郊慶成口號二十首  其六','周密','宋','宋诗','song-poetry','','[]','蒼璧黄琮藉白茅，圜壇八陛際雲高。',32,'全唐诗/poet.song.236000.json','["蒼璧黄琮藉白茅，圜壇八陛際雲高。", "景光下燭天心享，萬歲三呼祝聖堯。"]'),
('14689091-a802-44fa-9981-b4391ec174ba','南郊慶成口號二十首  其七','周密','宋','宋诗','song-poetry','','[]','瑞靄烘春夜不寒，駿奔冠珮擁回環。',32,'全唐诗/poet.song.236000.json','["瑞靄烘春夜不寒，駿奔冠珮擁回環。", "景鐘奏徹升煙起，又報端誠立賀班。"]'),
('70d47553-17b4-4275-be82-f4e944233ca2','南郊慶成口號二十首  其八','周密','宋','宋诗','song-poetry','','[]','黄道宮羅瑞腦香，衮龍陞降珮鏘鏘。',32,'全唐诗/poet.song.236000.json','["黄道宮羅瑞腦香，衮龍陞降珮鏘鏘。", "大安輦奏乾安曲，萬點明星簇紫皇。"]'),
('a4795ec5-9634-42e3-9574-4e052d7818f4','南郊慶成口號二十首  其九','周密','宋','宋诗','song-poetry','','[]','一夜東風斗柄回，紫壇葱蒨若春臺。',32,'全唐诗/poet.song.236000.json','["一夜東風斗柄回，紫壇葱蒨若春臺。", "熙熙萬宇風光暖，盡入君王飲福杯。"]'),
('6f414dea-2f99-4a3c-8e3f-7bab51b3fb77','南郊慶成口號二十首  其一○','周密','宋','宋诗','song-poetry','','[]','衙前口號奏諧和，日映龍顔喜氣多。',32,'全唐诗/poet.song.236000.json','["衙前口號奏諧和，日映龍顔喜氣多。", "六轡暫停鸞輅穩，鳳韶新奏慶成歌。"]'),
('9cfcdd78-695d-46ca-97e9-f30694ef5713','南郊慶成口號二十首  其一一','周密','宋','宋诗','song-poetry','','[]','錦幕千家盡貴豪，萬花呈曉翠簾高。',32,'全唐诗/poet.song.236000.json','["錦幕千家盡貴豪，萬花呈曉翠簾高。", "數聲掣電驚清蹕，一點紅雲認御袍。"]'),
('fa56e865-793c-431f-bdc5-53d37ed10257','南郊慶成口號二十首  其一二','周密','宋','宋诗','song-poetry','','[]','喜看回仗自青城，十里東風五色雲。',32,'全唐诗/poet.song.236000.json','["喜看回仗自青城，十里東風五色雲。", "露布西來天一笑，輿圖新復廣安軍。"]'),
('30ee77ed-b310-415d-966e-68b943503b50','南郊慶成口號二十首  其一三','周密','宋','宋诗','song-poetry','','[]','萬騎雲從簇錦圍，內官排辦馬如飛。',32,'全唐诗/poet.song.236000.json','["萬騎雲從簇錦圍，內官排辦馬如飛。", "九重閶闔開清曉，太母登樓望駕歸。"]'),
('df96b650-808c-42fc-8c93-04d9decc1110','南郊慶成口號二十首  其一四','周密','宋','宋诗','song-poetry','','[]','換輦登門捲御簾，侍中承制舍人宣。',32,'全唐诗/poet.song.236000.json','["換輦登門捲御簾，侍中承制舍人宣。", "鳳書乍脫金雞口，一派懽聲下九天。"]'),
('dbaa3984-6530-491d-a933-1fde58eaf69f','南郊慶成口號二十首  其一五','周密','宋','宋诗','song-poetry','','[]','祝史無私本爲民，大和丕應泰階平。',32,'全唐诗/poet.song.236000.json','["祝史無私本爲民，大和丕應泰階平。", "昕庭未受羣臣賀，先過東朝謝禮成。"]'),
('111a67c7-432b-45f2-8912-985efdfb1032','南郊慶成口號二十首  其一六','周密','宋','宋诗','song-poetry','','[]','啟蟄而郊月建寅，新元頒赦又頒春。',32,'全唐诗/poet.song.236000.json','["啟蟄而郊月建寅，新元頒赦又頒春。", "端闈拜了熙成表，朝會移班賀紫宸。"]'),
('e6bb491f-d875-497e-81c6-5e61aff2c55e','南郊慶成口號二十首  其一七','周密','宋','宋诗','song-poetry','','[]','子雲無分從甘泉，留滯猶勝敘史遷。',32,'全唐诗/poet.song.236000.json','["子雲無分從甘泉，留滯猶勝敘史遷。", "瑞應可書郊祀志，熙功宜被奉常絃。"]'),
('29b2636e-b0f6-4b12-8eba-d110d33cec33','南郊慶成口號二十首  其一八','周密','宋','宋诗','song-poetry','','[]','曾聞寶慶老人言，不見親郊四十年。',32,'全唐诗/poet.song.236000.json','["曾聞寶慶老人言，不見親郊四十年。", "何幸聖時瞻盛舉，詠歌留作畫圖傳。"]'),
('5d15da39-8259-4d89-95d5-30cb77357e8d','南郊慶成口號二十首  其一九','周密','宋','宋诗','song-poetry','','[]','我將清廟周詩頌，泰畤汾陰漢史書。',32,'全唐诗/poet.song.236000.json','["我將清廟周詩頌，泰畤汾陰漢史書。", "獻賦可無徐穆伯，貢諛何取馬相如。"]'),
('ce334940-96d5-4e2e-861c-72a790343067','南郊慶成口號二十首  其二○','周密','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','太平寰海扇皇風，千載風雲喜際逢。',32,'全唐诗/poet.song.236000.json','["太平寰海扇皇風，千載風雲喜際逢。", "行見版圖恢舊宇，泰山父老徯東封。"]'),
('98ea7241-a57e-4f7c-9bce-9f98796635f0','水仙謠爲趙子固賦','周密','宋','宋诗','song-poetry','','[]','九歌討群珍，遺此橫道寶。',48,'全唐诗/poet.song.236000.json','["九歌討群珍，遺此橫道寶。", "雪光射初月，靜夜纖裳縞。", "雲護白珊瑚，風蜚碧龍腦。", "招得湘娥魂，千年化瑶草。"]'),
('480155af-d249-4d47-8a22-37b54aaaaa25','次李秋崖見寄韻','周密','宋','宋诗','song-poetry','','[]','東風過雁带春聲，半紙依然舊雨情。',64,'全唐诗/poet.song.236000.json','["東風過雁带春聲，半紙依然舊雨情。", "生事就荒拋橘隠，交情耐久有梅兄。", "鶴歸不記千年表，馬老空慚萬里名。", "閑想蘋花谿上笛，扁舟應許白鷗盟。"]'),
('79061e98-e683-488c-a169-a22c3e76683e','次程儀父遊清溪','周密','宋','宋诗','song-poetry','','[]','谿上垂垂雨又晴，淚荷顰柳滿沙汀。',64,'全唐诗/poet.song.236000.json','["谿上垂垂雨又晴，淚荷顰柳滿沙汀。", "水聲不洗千年恨，山色空餘六代青。", "感慨有詩懷故國，英雄無淚泣新亭。", "孤忠耿耿人誰會，酹酒鍾山試乞靈。"]'),
('e60ec18f-8638-4fda-a845-391f20e7f22b','蔣山次徐君寅韻','周密','宋','宋诗','song-poetry','','[]','佛屋千年古木中，遺民猶有六朝風。',32,'全唐诗/poet.song.236000.json','["佛屋千年古木中，遺民猶有六朝風。", "騎馿宰相何人見，試問玄關十八公。"]'),
('c2cf8c1a-24c8-43df-b285-717da3a7c967','半山次韻','周密','宋','宋诗','song-poetry','','[]','吹香照影白谿灣，覓句逃禪去復還。',32,'全唐诗/poet.song.236000.json','["吹香照影白谿灣，覓句逃禪去復還。", "晚歲既知三字誤，終身只合兩山間。"]'),
('5be2435e-898b-4192-b3fb-f1be9bb1969c','秋懷','周密','宋','宋诗','song-poetry','','[]','浩浩門外塵，今古無二岐。',120,'全唐诗/poet.song.236000.json','["浩浩門外塵，今古無二岐。", "車痕遍九陌，得喪何已時。", "商飆動地來，萬葉辭故枝。", "游子感摇落，忽起流年悲。", "玄髮日以槁，素衣日以緇。", "天衢九萬里，加以剛風吹。", "歲月不我私，壯志安可期。", "激昂賦七啟，清壯歌五噫。", "采采秋原花，對酒聊自怡。", "佳人隔明河，相望長相思。"]'),
('317ffedc-5419-44dc-8a03-9224f172e95a','秋晚懷歸','周密','宋','宋诗','song-poetry','','[]','摇落江空雁影沉，樓高愁近怕登臨。',64,'全唐诗/poet.song.236000.json','["摇落江空雁影沉，樓高愁近怕登臨。", "雙溪秋晚碧苕老，三徑雨多紅葉深。", "燈火未忘年少夢，蓴鱸偏惱客中心。", "且尋籬下黄花約，莫倚西風學楚吟。"]'),
('6813f76d-ff29-4c11-9cb0-245692791e93','種花五言','周密','宋','宋诗','song-poetry','','[]','花發一朝喜，花落一夕愁。',24,'全唐诗/poet.song.236000.json','["花發一朝喜，花落一夕愁。", "不如不種花，不喜亦不憂。"]'),
('53aa2449-354e-4140-bad5-0e1fc4318781','湖亭雨後','周密','宋','宋诗','song-poetry','','[]','罨畫樓臺著色山，雨餘濯錦未全乾。',32,'全唐诗/poet.song.236000.json','["罨畫樓臺著色山，雨餘濯錦未全乾。", "遊船醉眼迷歌舞，不似閒人靜處看。"]'),
('3fae8a27-544d-46bd-8752-7cc8b47773cd','春日感懷寄修門從遊','周密','宋','宋诗','song-poetry','','[]','華年錦瑟事誰論，燕社鷗盟半不存。',64,'全唐诗/poet.song.236000.json','["華年錦瑟事誰論，燕社鷗盟半不存。", "三月鶑花張緒宅，十年詩酒孟嘗門。", "東風不染吳霜鬢，舊雨難招楚水魂。", "欲把清愁換沉醉，月明花落幾黄昏。"]'),
('3e1d19d7-5a17-4531-8a50-92c74e8ce76d','友人山房','周密','宋','宋诗','song-poetry','','[]','自笑勞勞塵滿襟，羨君卜隠在山深。',64,'全唐诗/poet.song.236000.json','["自笑勞勞塵滿襟，羨君卜隠在山深。", "清谿過雨知魚樂，秋漢無雲快鶴心。", "與世相忘千日酒，謀生甚簡一絃琴。", "不須物外求知己，明月清風自賞音。"]'),
('a60885ea-257f-4cbf-a628-bf7831de3357','夜歸','周密','宋','宋诗','song-poetry','','[]','夜深歸客倚筇行，冷燐依螢聚土塍。',32,'全唐诗/poet.song.236000.json','["夜深歸客倚筇行，冷燐依螢聚土塍。", "村店月昏泥徑滑，竹窗斜漏補衣燈。"]'),
('3614ae65-83b3-4eb2-a232-9ca3ae8a2b3a','西塍秋日即事','周密','宋','宋诗','song-poetry','','[]','絡緯聲聲織夜愁，酸風吹雨水邊樓。',32,'全唐诗/poet.song.236000.json','["絡緯聲聲織夜愁，酸風吹雨水邊樓。", "堤楊脆盡黄金線，城裏人家未覺秋。"]'),
('273076c7-2ff5-473f-8978-f9f4d981e3d2','贈別三首  其一','周密','宋','宋诗','song-poetry','','[]','歲晚日云暮，朔吹鳴枯枝。',48,'全唐诗/poet.song.236000.json','["歲晚日云暮，朔吹鳴枯枝。", "迢迢萬里道，遊子奚所之。", "前置酒一樽，于以紓別離。", "人生盡岐路，流轉勿自悲。"]'),
('a86073cf-0084-48cc-a9a1-59ec8bc3835a','贈別三首  其二','周密','宋','宋诗','song-poetry','','[]','野梅發崇岡，寒日慘不舒。',48,'全唐诗/poet.song.236000.json','["野梅發崇岡，寒日慘不舒。", "單車騁長道，悵悵無安居。", "夢寐日以勞，晤語日以疎。", "邊城足飛雁，因寄江南書。"]'),
('5acf1f3d-ae91-4a78-9e78-3ec054d710fb','贈別三首  其三','周密','宋','宋诗','song-poetry','','[]','行行重行行，送子江之涯。',48,'全唐诗/poet.song.236000.json','["行行重行行，送子江之涯。", "把手不忍分，涕淚俱漣洏。", "客途無西東，良會胡可期。", "努力爲功名，世道多嶮巇。"]'),
('5f5e1aff-4b35-433b-93c8-2327f6c32106','宿感慈僧舍','周密','宋','宋诗','song-poetry','','[]','刻刻數殘更，依依夢未成。',48,'全唐诗/poet.song.236000.json','["刻刻數殘更，依依夢未成。", "不堪孤客耳，當此萬蛩聲。", "霜葉矜秋色，風林碎月明。", "旅懷多自感，景物況關情。"]'),
('906b63b1-d617-455e-9c1a-562fb90cab58','病中','周密','宋','宋诗','song-poetry','','[]','一番春又老，長日病厭厭。',48,'全唐诗/poet.song.236000.json','["一番春又老，長日病厭厭。", "黄馘從清減，華顛任白添。", "鼠頑翻藥竈，蛛嬲罥書籤。", "門巷無來客，冠簪亦懶拈。"]'),
('bf7f6f0e-c78e-4d47-8ed3-e5fb45e0d69d','春晚簡溪友','周密','宋','宋诗','song-poetry','','[]','楚烟新百五，漢禊古重三。',48,'全唐诗/poet.song.236000.json','["楚烟新百五，漢禊古重三。", "節序正如此，情懷自不堪。", "蜜香蜂蛻蛹，綿老柳飄蠶。", "有約谿邊去，觀魚共劇談。"]'),
('7f2cb680-71eb-4278-a334-c28a1c461a64','遊法華瑶阜蜃洞以糝徑楊花鋪白氈點溪荷葉疊青錢分韻余既有作復各賦古詩一以紀遊事  其一','周密','宋','宋诗','song-poetry','','[]','青旂倏南指，灑灑風日澹。',60,'全唐诗/poet.song.236000.json','["青旂倏南指，灑灑風日澹。", "伯勞與飛燕，相對如有憾。", "餘春在何許，青苔綴紅糝。", "繁華逐流水，使我意殊慘。", "把酒延孤芳，舉之不盈攬。"]'),
('68f78217-9d65-4de0-879e-ddddfa68697f','遊法華瑶阜蜃洞以糝徑楊花鋪白氈點溪荷葉疊青錢分韻余既有作復各賦古詩一以紀遊事  其二','周密','宋','宋诗','song-poetry','','[]','此身如虛舟，所至不維矴。',60,'全唐诗/poet.song.236000.json','["此身如虛舟，所至不維矴。", "聞奇即勇往，豈暇尋捷徑。", "同行二三子，委曲逐孤磬。", "甘清嗽寒齒，醉夢爲甦醒。", "睠睠泉石幽，歸榜煙欲暝。"]'),
('05cc602d-fd7b-47c4-90fe-23aff5a11f78','遊法華瑶阜蜃洞以糝徑楊花鋪白氈點溪荷葉疊青錢分韻余既有作復各賦古詩一以紀遊事  其三','周密','宋','宋诗','song-poetry','','[]','坎坎樂蛙鼓，誰爲歌折楊。',60,'全唐诗/poet.song.236000.json','["坎坎樂蛙鼓，誰爲歌折楊。", "朅來散幽憂，因之弁之陽。", "山雲正可怡，澗碧尤可湘。", "他年乞一壑，我欲築草堂。", "所不踐斯言，寧不愧德璋。"]'),
('a2cf626b-8310-4974-9dbf-f77a2bafad8d','遊法華瑶阜蜃洞以糝徑楊花鋪白氈點溪荷葉疊青錢分韻余既有作復各賦古詩一以紀遊事  其四','周密','宋','宋诗','song-poetry','','[]','白雲鎖蒼弁，爽氣日夕佳。',60,'全唐诗/poet.song.236000.json','["白雲鎖蒼弁，爽氣日夕佳。", "平生幾兩屐，放浪山水涯。", "行樂當及時，矧復鬢已華。", "浮名豈足玩，不異空中花。", "君其味吾言，戇語非浮誇。"]'),
('80fd3e34-e928-4d16-9388-2db80e00909f','遊法華瑶阜蜃洞以糝徑楊花鋪白氈點溪荷葉疊青錢分韻余既有作復各賦古詩一以紀遊事  其五','周密','宋','宋诗','song-poetry','','[]','芳時不遊適，真可謚以愚。',60,'全唐诗/poet.song.236000.json','["芳時不遊適，真可謚以愚。", "得失愁雞蟲，百歲良區區。", "卿法自用卿，吾亦自忘吾。", "狂歌雜歈些，醉語從嘲呼。", "我欲藉落花，長簟毋庸鋪。"]'),
('2b51b021-c98e-44ff-afa6-23a47794fd5f','遊法華瑶阜蜃洞以糝徑楊花鋪白氈點溪荷葉疊青錢分韻余既有作復各賦古詩一以紀遊事  其六','周密','宋','宋诗','song-poetry','','[]','似聞蒼弁西，下有蛟蜃宅。',60,'全唐诗/poet.song.236000.json','["似聞蒼弁西，下有蛟蜃宅。", "躍然動遊情，朝來蠟吾屐。", "披荆不憚嶮，高下倚孤策。", "斯遊亦不惡，俗士或嘖嘖。", "路轉松風長，隴首孤雲白。"]'),
('73e95c39-41df-4928-9edc-8ae411538b07','遊法華瑶阜蜃洞以糝徑楊花鋪白氈點溪荷葉疊青錢分韻余既有作復各賦古詩一以紀遊事  其七','周密','宋','宋诗','song-poetry','','[]','東皇駕春去，遺我綠滿川。',60,'全唐诗/poet.song.236000.json','["東皇駕春去，遺我綠滿川。", "窗前一徑苔，珍重如青氈。", "閑門斷來人，剝啄惟啼鵑。", "山房萬書卷，相對皆聖賢。", "滔滔一世中，此道殊孤鶱。"]'),
('872ca52e-636f-41a3-b5fc-28cae4072e90','遊法華瑶阜蜃洞以糝徑楊花鋪白氈點溪荷葉疊青錢分韻余既有作復各賦古詩一以紀遊事  其八','周密','宋','宋诗','song-poetry','','[]','中洲有蘼蕪，芳意香荏苒。',60,'全唐诗/poet.song.236000.json','["中洲有蘼蕪，芳意香荏苒。", "東風有歸心，相對老冉冉。", "依依未能采，我抱殊有慊。", "禽魚自飛泳，生意何可揜。", "樂哉舞雩遊，千載吾與點。"]'),
('ec8f08f6-888c-4a78-a685-bf4042652151','遊法華瑶阜蜃洞以糝徑楊花鋪白氈點溪荷葉疊青錢分韻余既有作復各賦古詩一以紀遊事  其九','周密','宋','宋诗','song-poetry','','[]','諸公垂天鵬，俊翮何可齊。',60,'全唐诗/poet.song.236000.json','["諸公垂天鵬，俊翮何可齊。", "老生抱區區，舞甕如醯雞。", "輕鷗邀我盟，十里蘋華溪。", "長謠快清釂，嶮韻分新題。", "春去我自留，一任林鶑啼。"]'),
('7f069a62-7a5a-4656-9ac4-260fe50b6204','遊法華瑶阜蜃洞以糝徑楊花鋪白氈點溪荷葉疊青錢分韻余既有作復各賦古詩一以紀遊事  其一○','周密','宋','宋诗','song-poetry','','[]','花柳有老色，選芳事蹉跎。',60,'全唐诗/poet.song.236000.json','["花柳有老色，選芳事蹉跎。", "泠然語清揚，彼美山之阿。", "離離珮紉蘭，楚楚衣製荷。", "我欲往從之，皎如隔明河。", "相見不相親，發我臨風歌。"]'),
('3d0389db-84ad-44d5-9c06-28e889c3027e','遊法華瑶阜蜃洞以糝徑楊花鋪白氈點溪荷葉疊青錢分韻余既有作復各賦古詩一以紀遊事  其一一','周密','宋','宋诗','song-poetry','','[]','人生巧聚散，不定如風葉。',60,'全唐诗/poet.song.236000.json','["人生巧聚散，不定如風葉。", "況我同襟人，一笑意已浹。", "吳音戲趼足，巴語嘲長鬣。", "盧胡泛大白，痛釂不嚅囁。", "二孺彼何爲，我醉從喋喋。"]'),
('a0c27463-6a33-4054-8bbc-88e7e3d9ed5f','遊法華瑶阜蜃洞以糝徑楊花鋪白氈點溪荷葉疊青錢分韻余既有作復各賦古詩一以紀遊事  其一二','周密','宋','宋诗','song-poetry','','[]','止止歌楚吟，已已彈長鋏。',60,'全唐诗/poet.song.236000.json','["止止歌楚吟，已已彈長鋏。", "及茲綠陰初，快躡尋山屧。", "富貴正何用，寒暑若交睫。", "誰將金谷詩，欲擬山陰帖。", "一笑不復云，長歌自三疊。"]'),
('1ed5dcab-b216-45b6-be30-9a9ad130f967','遊法華瑶阜蜃洞以糝徑楊花鋪白氈點溪荷葉疊青錢分韻余既有作復各賦古詩一以紀遊事  其一三','周密','宋','宋诗','song-poetry','','[]','子長有遊癖，訪古來林坰。',60,'全唐诗/poet.song.236000.json','["子長有遊癖，訪古來林坰。", "不到餘十年，歷歷記所經。", "豈惟物推移，抑亦人飄零。", "憂來欲誰語，一醉將忘形。", "我鬢非垂楊，安得長青青。"]'),
('7a305c93-4f62-4832-a0f3-fb212f8a1c4e','遊法華瑶阜蜃洞以糝徑楊花鋪白氈點溪荷葉疊青錢分韻余既有作復各賦古詩一以紀遊事  其一四','周密','宋','宋诗','song-poetry','','[]','陶公晚知琴，得意不在絃。',60,'全唐诗/poet.song.236000.json','["陶公晚知琴，得意不在絃。", "虞卿老著書，信道差似賢。", "壯哉奴命騷，陋矣兄事錢。", "玉暉或潤木，寶氣嘗干天。", "浩然在存養，吾黨當勉旃。"]'),
('7f6b43df-0da7-49a5-b24b-93099c592427','重過東園興懷知己二首  其一','周密','宋','宋诗','song-poetry','','[]','東園桃李記春時，杖屨相從日日嬉。',64,'全唐诗/poet.song.236000.json','["東園桃李記春時，杖屨相從日日嬉。", "烏帽插花籌艷酒，碧蓮探韻賦新詩。", "廣陵散絕清彈苦，峴首碑空雨淚垂。", "物色已非知己盡，一回臨眺一懷悲。"]'),
('50c9ca0a-bc98-44f3-bcf7-a7c1ce835fcf','重過東園興懷知己二首  其二','周密','宋','宋诗','song-poetry','','[]','俛仰悲歡了不同，回頭已隔五春風。',64,'全唐诗/poet.song.236000.json','["俛仰悲歡了不同，回頭已隔五春風。", "兔葵燕麥情何恨，雁柱鯤絃事已空。", "自分此生無鮑叔，敢期後世有揚雄。", "西州門外羊曇老，淚染斜陽濕晚紅。"]'),
('3493b89d-0132-4b4b-a0f2-9776478c0b15','遊繡谷以柳塘春水慢花塢夕陽遲分韻得水字','周密','宋','宋诗','song-poetry','','[]','維暮春之初，風日清以美。',288,'全唐诗/poet.song.236000.json','["維暮春之初，風日清以美。", "駕言清苕濱，行行問春事。", "居然得幽勝，去郭纔數里。", "亭臺護脩竹，橫橋带流水。", "高堂敞山椒，虛楹宜小倚。", "群山若米聚，孤塔如筆峙。", "枰棋列疇疃，培塿見城市。", "行舟類飄葉，遊人若移螘。", "始知宇宙大，眼豁意爲起。", "脩廊走秋蛇，蜿蜒徹山趾。", "遠近蒸紅霞，川谷成錦綺。", "東風寵芳草，新晴侈嘉蘤。", "天機巧繪寫，眼纈眩朱紫。", "躍然見春心，生意何可已。", "逶迤群玉林，青蒼森齒齒。", "詭然搴鯤鯨，巋然踞犀兕。", "幽深若可探，嶮絕疑無底。", "神鑱與鬼運，奇怪不可擬。", "元章見之拜，奇章見之喜。", "昌黎南山詩，品狀或可比。", "清漪泛芳藻，絕谷多幽芷。", "陰森蘚華滑，蒙茸薜蘿委。", "冥搜意逾遠，欲去棹還檥。", "何必天海涯，然後足奇詭。"]'),
('7bc534c9-db2c-44d2-b446-f456c8b15336','是日因游春谷園池復以所分題五平韻賦六言五首  其一','周密','宋','宋诗','song-poetry','','[]','楊柳薰風池閣，桃花流水橫塘。',28,'全唐诗/poet.song.236000.json','["楊柳薰風池閣，桃花流水橫塘。", "魚浪晴吹絮暖，燕泥雨過芹香。"]'),
('db117bea-2cac-4933-bdb3-3a6574554456','是日因游春谷園池復以所分題五平韻賦六言五首  其二','周密','宋','宋诗','song-poetry','','[]','三月三日天氣，一觴一詠閑人。',28,'全唐诗/poet.song.236000.json','["三月三日天氣，一觴一詠閑人。", "大黠小癡俱夢，百年幾度尋春。"]'),
('34276e15-ff54-441b-b641-f01a9e18b357','是日因游春谷園池復以所分題五平韻賦六言五首  其三','周密','宋','宋诗','song-poetry','','[]','沉香亭木芍藥，玄都觀碧桃花。',28,'全唐诗/poet.song.236000.json','["沉香亭木芍藥，玄都觀碧桃花。", "幽事偏供吟屐，好春多在侯家。"]'),
('4e59e0d9-eb9c-4221-9e92-8505c0fb1186','是日因游春谷園池復以所分題五平韻賦六言五首  其四','周密','宋','宋诗','song-poetry','','[]','飛絮帽簷風軟，落花酒面春香。',28,'全唐诗/poet.song.236000.json','["飛絮帽簷風軟，落花酒面春香。", "蛙噪野塘殘水，鶑啼遠樹斜陽。"]'),
('3a500e12-6f07-4185-ab80-493c18bc35fc','是日因游春谷園池復以所分題五平韻賦六言五首  其五','周密','宋','宋诗','song-poetry','','[]','踏踏曳東郭履，行行誦北山移。',28,'全唐诗/poet.song.236000.json','["踏踏曳東郭履，行行誦北山移。", "閑望白雲心遠，細尋芳草歸遲。"]'),
('047f1d7a-7a39-4531-a6c0-46685094dd88','讀靖康雜書有感','周密','宋','宋诗','song-poetry','','[]','誤國狂奸亦可悲，國危身亦蹈危機。',64,'全唐诗/poet.song.236000.json','["誤國狂奸亦可悲，國危身亦蹈危機。", "燕山復地功何有，海上尋盟事已非。", "太宰忍乘黄屋誑，都人空望翠華歸。", "東都節義惟劉李，頸血猶能濺帝衣。"]'),
('34b96f86-cf09-421f-b0a2-750fd97a926a','掃松山中愴然霜露之感','周密','宋','宋诗','song-poetry','','[]','風露感我心，使我秋衣單。',60,'全唐诗/poet.song.236000.json','["風露感我心，使我秋衣單。", "郎忙索衾裯，驚歎歲月殘。", "忍哉使吾親，重壤侵肌寒。", "松風日蕭瑟，幽澗鳴悲酸。", "愯然起中宵，淚血流闌干。"]'),
('24d2b44f-fc53-4347-8945-02db875b4267','題秋崖小隠圖','周密','宋','宋诗','song-poetry','','[]','萬壑秋明一徑斜，滿川霜葉勝春花。',32,'全唐诗/poet.song.236000.json','["萬壑秋明一徑斜，滿川霜葉勝春花。", "何人結屋松風裏，丁卯橋邊處士家。"]'),
('2483f5a8-75a3-467a-9b8d-d6a08210ff47','次張斗南有懷方崖舊遊韻','周密','宋','宋诗','song-poetry','','[]','猶記聯鑣度曉關，幽尋曾到五雲山。',64,'全唐诗/poet.song.236000.json','["猶記聯鑣度曉關，幽尋曾到五雲山。", "敢忘白石清泉約，空羨輕鷗野鶴閒。", "寤寐嘯歌前日事，死生契闊數年間。", "當時詩草今猶在，何日重遊共細刪。"]'),
('3f0a03b2-1972-4c5c-addc-377bcc5f5acc','程儀父求石鼓文作歌贈之','周密','宋','宋诗','song-poetry','','[]','宣王東征獵岐下，頌美聲詩足雄詫。',224,'全唐诗/poet.song.236000.json','["宣王東征獵岐下，頌美聲詩足雄詫。", "神模鬼劃不可名，斯冰後出何爲者。", "日皴雪剝三千年，絕無僅有爭流傳。", "龍鱗鳳咮敢求備，頌秦詛楚難參肩。", "退之倔强少假借，咄咄誇奇補風雅。", "逸詩闕史不可知，要爲吉日車攻亞。", "宣和內府輯衆珍，氈韜駝負填泥金。", "昆明夜半經劫火，六丁下取無由尋。", "醉翁集古一千卷，此碣居然膺首選。", "菖蒲土炭嗜不同，知味幾人嘗鼎臠。", "我生癖古亦太癡，訂音考義忘寒饑。", "君今迂緩尤可笑，不寶金帛求殘碑。", "感君此意何敢靳，妙處難言君自領。", "丈夫意氣當相期，會勒奇勳上鍾鼎。"]'),
('c995e03b-1590-4975-8192-6bd10893551d','夏日同盟遊玉湖分韻得柳字','周密','宋','宋诗','song-poetry','','[]','澤國秋早凉，谿山喜招誘。',240,'全唐诗/poet.song.236000.json','["澤國秋早凉，谿山喜招誘。", "扁舟以遨遊，嘉與同志友。", "菡萏池百弓，花竹園五畝。", "左映碧浪湖，右带浮玉阜。", "當年經鉏翁，依水開戶牖。", "游鱗習吾伊，飛鳥謝揮手。", "牙籤卷三萬，散漫今何有。", "斑斑屋壁間，僅見詩數首。", "萬事正如此，何以圖不朽。", "得喪類蕉鹿，功名等芻狗。", "古今聊復爾，紛華亦非久。", "人生匪金石，安得百年壽。", "矧余蒲柳姿，髮白慚老醜。", "蹣跚笑鱉跛，緩慢羞牛後。", "因循負壯圖，漫浪若聱叟。", "鷗盟倏焉聚，一笑夫豈偶。", "溪翁饋魚蟹，野老分蓮藕。", "高詠甫里篇，滿飲烏程酒。", "清狂君勿嗤，嵇阮未易不。", "蘋風送回橈，殘虹掛高柳。"]'),
('2e5ffb65-dd27-458c-ae5f-a836aaa20c11','瀟湘八景 平沙落雁','周密','宋','宋诗','song-poetry','','[]','沙閣凍痕吹折葦，淡日黄雲照灘水。',64,'全唐诗/poet.song.236000.json','["沙閣凍痕吹折葦，淡日黄雲照灘水。", "風翻斜陣下滄茫，一笛漁歌又驚起。", "翩翩弄影聲號寒，帛書萬里來長安。", "稻粱多處有矰弋，何如煙月江湖寬。"]'),
('b6292665-4308-405c-99d9-d24c0b234bdd','瀟湘八景 遠浦歸帆','周密','宋','宋诗','song-poetry','','[]','空江沄沄鳥飛疾，別浦斜陽帆影直。',64,'全唐诗/poet.song.236000.json','["空江沄沄鳥飛疾，別浦斜陽帆影直。", "水程依約雁前回，日日沙頭候風色。", "江蘺摇落三湘秋，雲中烟樹誰歸舟。", "危檣數盡碧雲合，人倚高樓生暮愁。"]'),
('5b2e2976-746b-4f8a-9044-845708105578','瀟湘八景 山市晴嵐','周密','宋','宋诗','song-poetry','','[]','黄陵廟前湘竹春，鼓聲坎坎迎送神。',64,'全唐诗/poet.song.236000.json','["黄陵廟前湘竹春，鼓聲坎坎迎送神。", "包茶裹鹽作小市，雞鳴犬吠東西鄰。", "賣薪博米魚換酒，幾處青帘扶醉叟。", "趁虛人散渡船閑，一抹晴烟隔高柳。"]'),
('5d67e376-3c4c-41d4-93e0-ec5793543575','瀟湘八景 江天暮雪','周密','宋','宋诗','song-poetry','','[]','雁吹斷字沙草黄，奇寒栗栗吹連檣。',64,'全唐诗/poet.song.236000.json','["雁吹斷字沙草黄，奇寒栗栗吹連檣。", "簑翁晚歸絕空闊，雨花零亂春茫茫。", "白天四垂楚山老，薄暮瓊瑶失洲島。", "燎衣閉戶且醉眠，誰肯扁舟訪安道。"]'),
('d7a19b26-3c25-4beb-b412-d9c12ba43362','瀟湘八景 洞庭秋月','周密','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','西風始波木葉下，廣樂誰張洞庭野。',64,'全唐诗/poet.song.236000.json','["西風始波木葉下，廣樂誰張洞庭野。", "玉光千頃浸明河，露泫珠房冷鉛瀉。", "飛吟一劍風泠泠，桂香倒射魚龍腥。", "何人扁舟弄孤笛，尚疑鼓瑟聞湘靈。"]'),
('655ed8d8-a36c-4ec8-8046-57a2e601f4ef','瀟湘八景 瀟湘夜雨','周密','宋','宋诗','song-poetry','','[]','蘋花夜黑水鳥鳴，橋危路滑無人行。',64,'全唐诗/poet.song.236000.json','["蘋花夜黑水鳥鳴，橋危路滑無人行。", "酸風蕭瑟浪鏜鞳，濕螢熠熠漁燈明。", "飛蓬入葦響洲渚，暗憶西窗剪燈語。", "書船穩繫聽秋聲，倦客吟騷夢三楚。"]'),
('7cc4a563-7b98-4f45-ae6f-199869179113','瀟湘八景 煙寺晚鐘','周密','宋','宋诗','song-poetry','','[]','半空蘭若嵐翠霏，千點萬點林鴉歸。',64,'全唐诗/poet.song.236000.json','["半空蘭若嵐翠霏，千點萬點林鴉歸。", "疎烟滅沒冷旛影，沉沉綠樹生春暉。", "孤鐘殷殷度殘霧，響透松梢慘將暮。", "山椒暝色失浮圖，隔岸殘僧尚呼渡。"]'),
('132dd507-e6bf-43f2-b3ea-5ba7ee89118d','瀟湘八景 漁村晚照','周密','宋','宋诗','song-poetry','','[]','瀟湘二水波相連，魚梁蟹舍西風前。',64,'全唐诗/poet.song.236000.json','["瀟湘二水波相連，魚梁蟹舍西風前。", "斜陽兩岸山紫翠，村村網罟懸秋煙。", "漁家釣水無徵稅，日日得魚供晚醉。", "世塵不到一絲邊，中有唐虞千古意。"]'),
('9600539c-6954-4f87-ace1-0a5dc662ed5b','送友人歸吳','周密','宋','宋诗','song-poetry','','[]','吳船花外發，欲去重躊躇。',48,'全唐诗/poet.song.236000.json','["吳船花外發，欲去重躊躇。", "後會定何日，相思頻寄書。", "曉林啼帝魄，春網薦王餘。", "笠澤維梢處，因尋魯望居。"]'),
('27504c5d-7daa-4c7a-98d7-39e7fa551420','月上人退居','周密','宋','宋诗','song-poetry','','[]','不受諸方供，枯禪入遠林。',48,'全唐诗/poet.song.236000.json','["不受諸方供，枯禪入遠林。", "水涵清浄影，月印去來心。", "夕炷黄蓮冷，雲寮碧草深。", "淡然遺世慮，松籟起清音。"]'),
('8481188c-2dfb-4556-85cf-7b827aa7b3e2','山房首夏','周密','宋','宋诗','song-poetry','','[]','花過園池日漸長，嫩陰青子蔭苔牆。',64,'全唐诗/poet.song.236000.json','["花過園池日漸長，嫩陰青子蔭苔牆。", "四簷笋戟排庭綠，一畝荷簪發野芳。", "熟選已無青紫夢，命騷猶愛簡編香。", "惡圓用拙從吾好，傲懶從人笑漫郎。"]'),
('8dc5fb03-e2b9-4690-a5a2-91e08d859bc5','餘杭道中','周密','宋','宋诗','song-poetry','','[]','檥舟山水縣，暝靄翳孤篷。',48,'全唐诗/poet.song.236000.json','["檥舟山水縣，暝靄翳孤篷。", "斷港苕花雨，疎籬柿葉風。", "炭煙迷塢黑，稻色入炊紅。", "野興資遊事，閒情幾處同。"]'),
('cd4b7abe-c000-4c8e-8a3d-da3a3e239787','遊冷泉次陳體忠二十韻','周密','宋','宋诗','song-poetry','','[]','地僻多清事，林深遠暑威。',240,'全唐诗/poet.song.236000.json','["地僻多清事，林深遠暑威。", "短橈浮曉漲，瘦策破烟霏。", "討勝穿雲嶠，尋幽入翠微。", "澗沙金作色，池水玉生肥。", "小立評詩板，遲留坐釣磯。", "洗苔題石壁，愛竹款山扉。", "訪古尋唐記，逃禪下梵幃。", "慮空流水凈，情懶片雲飛。", "遠壑風聲合，幽崖日影稀。", "峻攀時倚杖，野涉屢褰衣。", "桂子雙峯聳，薝香一徑崎。", "新蜩響清晝，孤鶴唳斜暉。", "古蔓虹千尺，靈杉翠十圍。", "壑雷晴亦雨，花露午方晞。", "松老飄殘粉，蘭芳遞暗菲。", "鳥鳴知自樂，猿下爲忘機。", "泉上亭尤古，山椒塔更巍。", "身閑發深省，心靜悟前非。", "何日辭塵鞅，終當脫世鞿。", "舊盟泉石在，我欲賦來歸。"]'),
('80f76fa3-c3d6-4df4-a1f7-073246124953','病愈即事','周密','宋','宋诗','song-poetry','','[]','病懶空憐負壯圖，盛年齒髮已凋疎。',64,'全唐诗/poet.song.236000.json','["病懶空憐負壯圖，盛年齒髮已凋疎。", "棲遲轅下如老驥，展轉書間似蠹魚。", "瞑目自持存息法，閉門重廣絕交書。", "花開頓覺身强健，行藥窗前喜自如。"]'),
('f30bccc2-75cd-4ad4-bf5f-f34933c4f08f','宮詞八首  其一','周密','宋','宋诗','song-poetry','','[]','十仞雕牆千步廊，宮槐簇簇柳行行。',32,'全唐诗/poet.song.236000.json','["十仞雕牆千步廊，宮槐簇簇柳行行。", "落花已被春分付，紫禁門深又夕陽。"]'),
('00d2f071-e796-49a5-a6d0-fb4cc2b8d83c','宮詞八首  其二','周密','宋','宋诗','song-poetry','','[]','寂寂長門白日長，容華銷盡不成妝。',32,'全唐诗/poet.song.236000.json','["寂寂長門白日長，容華銷盡不成妝。", "深深下却鮫綃帳，怕引楊花入繡牀。"]'),
('b2104438-63a8-401d-8810-a766050885f7','宮詞八首  其三','周密','宋','宋诗','song-poetry','','[]','舜殿薰風拂五絃，午陰斜轉御廊前。',32,'全唐诗/poet.song.236000.json','["舜殿薰風拂五絃，午陰斜轉御廊前。", "幾多長養生成意，盡入吾皇解慍篇。"]'),
('8bf24b53-5167-4618-8383-cfdc821498cd','宮詞八首  其四','周密','宋','宋诗','song-poetry','','[]','翦翦輕寒入夾衣，夜深不語倚金扉。',32,'全唐诗/poet.song.236000.json','["翦翦輕寒入夾衣，夜深不語倚金扉。", "珠簾半下疎疎雨，聽得笙歌小殿歸。"]'),
('26a2efc2-4ea1-4046-9ed3-18c63d7bd7c4','宮詞八首  其五','周密','宋','宋诗','song-poetry','','[]','沈沈禁漏蠟花殘，侍宴歸時午夜闌。',32,'全唐诗/poet.song.236000.json','["沈沈禁漏蠟花殘，侍宴歸時午夜闌。", "新燕乍來人獨睡，夜深風雨作新寒。"]'),
('643c6d91-d526-4f53-9236-42cf7893b89a','宮詞八首  其六','周密','宋','宋诗','song-poetry','','[]','宮梅千樹照瑶池，香玉浮春泛寶巵。',32,'全唐诗/poet.song.236000.json','["宮梅千樹照瑶池，香玉浮春泛寶巵。", "喜聽梨園新口號，後宮今日命昭儀。"]'),
('a464dc75-96e4-4217-b370-b7fb4e9c096f','宮詞八首  其七','周密','宋','宋诗','song-poetry','','[]','排當初開喜雪筵，近臣表賀玉墀前。',32,'全唐诗/poet.song.236000.json','["排當初開喜雪筵，近臣表賀玉墀前。", "君王最念三邊冷，賞賜全支內庫錢。"]'),
('d8c57df1-67d0-457c-aa66-d9ffe3f60f92','宮詞八首  其八','周密','宋','宋诗','song-poetry','','[]','雁霜寒透水晶簾，燭短香殘不喜添。',32,'全唐诗/poet.song.236000.json','["雁霜寒透水晶簾，燭短香殘不喜添。", "忍負玉樓今夜月，寶箏閑理十三絃。"]'),
('77d47e17-9bb8-4e84-be64-f2f4df4e3ead','隠居','周密','宋','宋诗','song-poetry','','[]','深杜衡門謝往還，不將名字落人間。',64,'全唐诗/poet.song.236000.json','["深杜衡門謝往還，不將名字落人間。", "地偏仲蔚蓬蒿徑，塵遠淵明松菊關。", "事有難言惟袖手，人無可語且看山。", "幾年不到門前樹，相對清溪盡日閑。"]'),
('6856cb5a-2322-41c4-b740-9519cec176e9','宿僧房','周密','宋','宋诗','song-poetry','','[]','宿寄禪房靜，雲深路暗通。',48,'全唐诗/poet.song.236000.json','["宿寄禪房靜，雲深路暗通。", "冷煙凝夜白，秋葉學春紅。", "虎嘯三更月，僧禪一榻風。", "境清不成寐，竟夕共談空。"]'),
('b7dc988f-8946-4fea-ae59-4f14dc1f7cdf','對月吟傚白體','周密','宋','宋诗','song-poetry','','[]','前宵有酒無月明，昨宵有月樽無酒。',96,'全唐诗/poet.song.236000.json','["前宵有酒無月明，昨宵有月樽無酒。", "世間二美尚難并，萬事紛紛復何有。", "有酒無月醉不成，有月無酒月笑人。", "今宵月好酒亦好，舉酒屬月酬青春。", "青春難留月易缺，月下高歌天地闊。", "開樽對月月入樽，只愁醉殺樽中月。"]'),
('c8c6a26d-0f55-48ea-8403-b35728f3d20c','征婦怨','周密','宋','宋诗','song-poetry','','[]','夢魂夜夜在天涯，連歲音書不到家。',32,'全唐诗/poet.song.236000.json','["夢魂夜夜在天涯，連歲音書不到家。", "萬里征人成白骨，春閨猶自卜燈花。"]'),
('79b597b6-8aae-436d-a158-64e4fcb42a50','次韻山莊雜詠十首 東嘯','周密','宋','宋诗','song-poetry','','[]','長年如蠹魚，書底兀兀坐。',60,'全唐诗/poet.song.236000.json','["長年如蠹魚，書底兀兀坐。", "人皆笑其迂，吾計未爲左。", "𪡧然一舒嘯，萬籟相應和。", "廬豈真吾廬，我亦自忘我。", "淵明千載人，身世一鳥過。"]'),
('3b36b6e8-d3d7-4864-b195-f695abf59f14','次韻山莊雜詠十首 西爽','周密','宋','宋诗','song-poetry','','[]','昔人去手版，拂袖歸故山。',60,'全唐诗/poet.song.236000.json','["昔人去手版，拂袖歸故山。", "圉然魚縱淵，快若馬脫閑。", "白石真可煮，黄菊亦可餐。", "與世雖異轍，對山無赧顔。", "爽氣不在山，在我方寸間。"]'),
('fef02f6f-c869-4d0d-93f0-1864efa9e0c1','次韻山莊雜詠十首 商樂','周密','宋','宋诗','song-poetry','','[]','秦儒避書烟，逃難商山下。',60,'全唐诗/poet.song.236000.json','["秦儒避書烟，逃難商山下。", "安劉亦謾耳，後世巧模寫。", "智瓊果何人，一笑示幻化。", "蠻觸聊寓言，此亦何足訝。", "未知采芝人，何如種桃者。"]'),
('a29f1b71-636a-408f-832f-eaf1e33f9653','次韻山莊雜詠十首 自閑','周密','宋','宋诗','song-poetry','','[]','子牟魏闕心，身在江湖外。',60,'全唐诗/poet.song.236000.json','["子牟魏闕心，身在江湖外。", "安知山林隠，不若居廛大。", "心苟無所覊，居然謝塵械。", "莞然碧山笑，贅甚愚溪對。", "無處寫閑情，意與雲俱在。"]'),
('0548e4fe-71f1-4c21-a8ce-155d8e0aa586','次韻山莊雜詠十首 蒼翠','周密','宋','宋诗','song-poetry','','[]','衡湖足秋水，結屋秋水邊。',60,'全唐诗/poet.song.236000.json','["衡湖足秋水，結屋秋水邊。", "水邊復何有，翠壁森吾前。", "采之美可茹，釣之食有鮮。", "彼美山中人，霞裾正孤搴。", "山色無四時，相對惟蒼然。"]'),
('4c3d8ba3-f588-4baf-bbaa-a0edc182b866','次韻山莊雜詠十首 幽碧','周密','宋','宋诗','song-poetry','','[]','平池落金雨，野徑棲綠雲。',60,'全唐诗/poet.song.236000.json','["平池落金雨，野徑棲綠雲。", "泠泠九天風，月底吹清馨。", "暇日足勝遊，臨池結鷗盟。", "相期在歲寒，抱節同孤貞。", "君能賦招隠，我欲記墨君。"]'),
('d67e19dd-0cf4-4178-b68b-6528ccfacc25','次韻山莊雜詠十首 春意','周密','宋','宋诗','song-poetry','','[]','天上種碧桃，結實歲八千。',60,'全唐诗/poet.song.236000.json','["天上種碧桃，結實歲八千。", "人間蒔花柳，春逐時序遷。", "何如庭前草，風月長無邊。", "囿身化國中，物物熙熙然。", "至人觀物初，獨立春風前。"]'),
('47425747-bd4c-4bd0-884c-54a0269ebd95','次韻山莊雜詠十首 生香','周密','宋','宋诗','song-poetry','','[]','勾萌日條達，生意腔子滿。',60,'全唐诗/poet.song.236000.json','["勾萌日條達，生意腔子滿。", "一氣自流行，色香有先晚。", "刻楮信徒勞，剪綵初無本。", "天機造群物，四序長衮衮。", "散我胸中春，八荒無間斷。"]'),
('48564a3e-1ed2-4d66-b6c2-01e901536f0e','次韻山莊雜詠十首 流憩','周密','宋','宋诗','song-poetry','','[]','目視足不隨，高山徒仰止。',60,'全唐诗/poet.song.236000.json','["目視足不隨，高山徒仰止。", "何能强筋力，進銳退亦銳。", "萬里未爲遠，一息亦當至。", "徐行則不倦，寘足平穩地。", "策策更勉旃，閑雲隨步起。"]'),
('c12078a2-b41d-4ba1-b424-a04f772c9f03','次韻山莊雜詠十首 懷新','周密','宋','宋诗','song-poetry','','[]','我不如老農，綢繆先牖戶。',60,'全唐诗/poet.song.236000.json','["我不如老農，綢繆先牖戶。", "萬寶忽已新，見此離離黍。", "田家終歲勞，一飽天所許。", "細誦七月詩，仁意森莫禦。", "年登而民貧，未諗何以故。"]'),
('b5112168-87d3-4271-803a-108c835f6a49','中秋登樓','周密','宋','宋诗','song-poetry','','["\u592a\u6e56"]','酌酒對孤月，今宵中半秋。',48,'全唐诗/poet.song.236000.json','["酌酒對孤月，今宵中半秋。", "古今嗟逝水，天地入高樓。", "宿鳥摇花影，輕雲趁水流。", "何當太湖上，散髮棹扁舟。"]'),
('da59d608-6e6b-497e-b7e2-74bdea5ffe9e','山行用轆轤韻','周密','宋','宋诗','song-poetry','','[]','青山迎馬首，翠靄溼征衣。',48,'全唐诗/poet.song.236000.json','["青山迎馬首，翠靄溼征衣。", "前路柳俱綠，行人柳外歸。", "殘陽千里暮，閏歲百花遲。", "不是貪程客，時時認酒旗。"]'),
('9d466dd8-2846-49b6-946c-7e25a6adcbea','睡起','周密','宋','宋诗','song-poetry','','[]','體安一榻虛，晝夢有倫序。',72,'全唐诗/poet.song.236000.json','["體安一榻虛，晝夢有倫序。", "微風薰而清，泠然破輕暑。", "南窗數十竹，一一翠相語。", "簷玉聲琤然，疾徐合商呂。", "鳴禽不避人，飛蝶自得侶。", "悠哉會吾心，一笑忘爾汝。"]'),
('a4c0520a-8c1b-4873-bf60-8c2583a55f4d','春寒','周密','宋','宋诗','song-poetry','','[]','連日春寒不上樓，畫屏斜掩夢悠悠。',32,'全唐诗/poet.song.236000.json','["連日春寒不上樓，畫屏斜掩夢悠悠。", "梅花吹盡成香雪，簾外東風未肯休。"]'),
('72fafed4-e4c2-447f-bf90-6f8d4ff111d8','暑夜','周密','宋','宋诗','song-poetry','','[]','薄薄疎雲漏月明，礎根收潤晚風清。',32,'全唐诗/poet.song.236000.json','["薄薄疎雲漏月明，礎根收潤晚風清。", "空庭泥溼鳴螻蟈，夜氣如秋夢不成。"]'),
('8e8fb6b2-0ee9-480f-8362-de247c0bd051','荒塚','周密','宋','宋诗','song-poetry','','[]','荒塚漫漫長野蒿，老狐啼雨樹蕭蕭。',32,'全唐诗/poet.song.236000.json','["荒塚漫漫長野蒿，老狐啼雨樹蕭蕭。", "子孫已盡山移主，空剩殘碑補斷橋。"]'),
('39045bd3-0ee8-4784-9875-e93c2d05f1e0','還自奉口','周密','宋','宋诗','song-poetry','','[]','倚柁西風順，舟行勢若趨。',48,'全唐诗/poet.song.236000.json','["倚柁西風順，舟行勢若趨。", "山平初月蚤，市遠晚煙孤。", "客況三秋葉，鄉心兩岸蘆。", "歸期何日穩，趁得菊花無。"]'),
('26479c2c-8763-4fc2-8272-1e60483594ca','野望懷思','周密','宋','宋诗','song-poetry','','[]','微風起微波，燕燕飛差池。',48,'全唐诗/poet.song.236000.json','["微風起微波，燕燕飛差池。", "雨餘野色靚，萬綠皆紛披。", "汀洲多芳蘭，采采今其時。", "所思在遠道，日暮將誰遺。"]'),
('89811bbb-f546-4829-8ac0-05fe501f197a','買航歸霅','周密','宋','宋诗','song-poetry','','[]','身世飄浮嘆逝波，登瀛超海事蹉跎。',64,'全唐诗/poet.song.236000.json','["身世飄浮嘆逝波，登瀛超海事蹉跎。", "風燈颭浪摇鄉夢，夜櫓鳴霜雜棹歌。", "元子一官真漫耳，曾參三釜奈貧何。", "歸來好覓玄真子，浮玉山前理釣簑。"]'),
('40e0a4a9-5505-4957-b839-e1be9d3ace61','挽李太監二首  其一','周密','宋','宋诗','song-poetry','','[]','人間五福最難全，壽考康寧八十年。',64,'全唐诗/poet.song.236000.json','["人間五福最難全，壽考康寧八十年。", "賀監酒船空鑑曲，贊皇吟屋冷平泉。", "庭前玉樹呈三秀，架上香芸續□□。", "生死哀榮無一恨，御風歸作玉樓仙。"]'),
('87427cff-6b2a-416f-b6f2-93f2248214ff','挽李太監二首  其二','周密','宋','宋诗','song-poetry','','[]','摳衣猶欠日熙堂，僅拜儀刑振鷺行。',64,'全唐诗/poet.song.236000.json','["摳衣猶欠日熙堂，僅拜儀刑振鷺行。", "洛社舊人無狄監，貞元朝士失劉郎。", "新丘已隔三秋月，老圃空驚一夜霜。", "腸斷素車三百兩，簫笳不數漢南陽。"]'),
('926b78fc-1838-4a71-854a-ede72f37afb0','春閨','周密','宋','宋诗','song-poetry','','[]','嫩柳拖春眼眼愁，怨春人立柳邊樓。',32,'全唐诗/poet.song.236000.json','["嫩柳拖春眼眼愁，怨春人立柳邊樓。", "芳心已被流鶑說，手撚花枝暗點頭。"]'),
('9061784d-24c6-4c01-948c-4759035f67aa','夢覺','周密','宋','宋诗','song-poetry','','[]','夢覺花陰過數磚，一庭輕雨溼湘簾。',32,'全唐诗/poet.song.236000.json','["夢覺花陰過數磚，一庭輕雨溼湘簾。", "碧桃蜚盡鸝黄老，萬樹青陰屬杜鵑。"]'),
('9b6bba41-fc2f-49fa-9d4c-054a56fea3a4','夏夜水亭','周密','宋','宋诗','song-poetry','','[]','月滿方湖夜氣凉，曲欄吟罷自徜徉。',32,'全唐诗/poet.song.236000.json','["月滿方湖夜氣凉，曲欄吟罷自徜徉。", "飛螢照水驚魚躍，露滴荷心動細香。"]'),
('f5f7388a-f007-4352-817b-a1c6ff815a78','送謝景暉之澧陽','周密','宋','宋诗','song-poetry','','[]','揚舲從此別，千里水程寬。',48,'全唐诗/poet.song.236000.json','["揚舲從此別，千里水程寬。", "舊夢池生草，新吟澧有蘭。", "楚鄉春酒薄，湘浦雨燈寒。", "定有吟騷作，因風寄一看。"]'),
('647bf9b5-7b19-49fd-883e-e00523822fe2','訪全獨翁吟居','周密','宋','宋诗','song-poetry','','[]','蘋花谿上屋，牢落似深村。',48,'全唐诗/poet.song.236000.json','["蘋花谿上屋，牢落似深村。", "壞壁穿秋漲，空窗沁雨痕。", "靜通詩境界，醉到古乾坤。", "除却吟友外，何人扣竹門。"]'),
('70f75682-8a55-4a4e-9cda-609e0f497b11','山房春晚','周密','宋','宋诗','song-poetry','','[]','蘋花吹香柳花落，秭歸清啼答姑惡。',32,'全唐诗/poet.song.236000.json','["蘋花吹香柳花落，秭歸清啼答姑惡。", "午簾睡思逐晴絲，靜聽新篁墮春籜。"]'),
('6bcb482c-14a4-480d-ac3e-57ee5c3fea1e','酒邊次韻','周密','宋','宋诗','song-poetry','','[]','葉間雙顆綻紅肥，漸次春光到紫薇。',32,'全唐诗/poet.song.236000.json','["葉間雙顆綻紅肥，漸次春光到紫薇。", "可是楝花風訊惡，堤邊怪得畫船稀。"]'),
('0dd65cbf-8ed5-4e28-9bc8-2020dd7843d6','秋晚郊行即事','周密','宋','宋诗','song-poetry','','[]','籬豆垂花隴麥齊，炊紅篘綠小春時。',32,'全唐诗/poet.song.236000.json','["籬豆垂花隴麥齊，炊紅篘綠小春時。", "田家處處豐年樂，畫出豳風七月詩。"]'),
('338c6750-4174-40da-93ba-6de572b75a4d','雲山萬里圖','周密','宋','宋诗','song-poetry','','[]','山無重數水無邊，浩浩春風萬里天。',32,'全唐诗/poet.song.236000.json','["山無重數水無邊，浩浩春風萬里天。", "老矣少文空有志，披圖閑續卧游編。"]'),
('f6be24fa-335c-4f9a-ae3c-a23cec816c0d','賦愚隠園次陳伯芳韵','周密','宋','宋诗','song-poetry','','[]','故王臨賞地，幽榭带橫塘。',48,'全唐诗/poet.song.236000.json','["故王臨賞地，幽榭带橫塘。", "喬木傳家遠，高荷過檻長。", "琴書千古意，花竹四時香。", "永日無塵事，心清境亦凉。"]'),
('9b828d3e-1980-4d5c-a860-2057b83730c0','越日伯芳又有長句又次之','周密','宋','宋诗','song-poetry','','[]','萬綠深藏碧玉壺，清游閑日意舒徐。',64,'全唐诗/poet.song.236000.json','["萬綠深藏碧玉壺，清游閑日意舒徐。", "小山桂發吟招隠，杜曲花濃賦遂初。", "門隔軟紅人逐鹿，湖分新淥我知魚。", "飛花落葉成幽趣，底事清風爲掃除。"]'),
('8e7bfd15-996d-4354-a2a4-d08c467b103a','入宿太倉次黄汝濟韻','周密','宋','宋诗','song-poetry','','[]','紙帳梅花夢，空齋夜氣侵。',48,'全唐诗/poet.song.236000.json','["紙帳梅花夢，空齋夜氣侵。", "壯懷中歲感，遊子五更心。", "月轉花陰直，春隨柳色深。", "無人知此意，欹枕自微吟。"]'),
('ed849a6e-859b-4564-b401-0bd21c083fd6','賦養拙園桐丘','周密','宋','宋诗','song-poetry','','[]','誅茅得奇賞，結石成岑崟。',120,'全唐诗/poet.song.236000.json','["誅茅得奇賞，結石成岑崟。", "曲折行青蛇，只尺藏幽深。", "蘭風與桂露，芬郁雲崖陰。", "湖山不待招，秀色窺青林。", "怡顔一舒嘯，萬象供登臨。", "永歌逍遥遊，靜悅吾伊吟。", "榮枯驗草木，飛躍觀魚禽。", "老桐被天風，吹作太古音。", "何勞出庭戶，一笑會我心。", "居然悟天籟，毋事絃吾琴。"]'),
('89c68ae9-8457-459b-9dc2-ac26384d1c72','夢遊紫霞寤而感愴','周密','宋','宋诗','song-poetry','','[]','紫霞當日按凉州，曾到仙家十二樓。',64,'全唐诗/poet.song.236000.json','["紫霞當日按凉州，曾到仙家十二樓。", "秋影滿堂花外燭，冷香飛句柳邊舟。", "冰絃泛月傳新譜，芳檻移春接俊遊。", "授簡梁園人老去，年年葵麥長新愁。"]'),
('c7a909ae-94b3-4c45-b353-402911b2ea20','寄謝就道','周密','宋','宋诗','song-poetry','','["\u897f\u6e56"]','當年遊事記西湖，歲月飄零舊雨疎。',64,'全唐诗/poet.song.236000.json','["當年遊事記西湖，歲月飄零舊雨疎。", "剡曲暮雲頻入夢，長安落葉正愁予。", "春前有客徵梅賦，霜後無人寄橘書。", "回首青雲故人遠，滯留惟有老相如。"]'),
('aa148d52-08a9-49a7-84d1-5222c8d6e19e','瞰碧雨後即事','周密','宋','宋诗','song-poetry','','[]','清漪閑照影，凉意滿闌干。',48,'全唐诗/poet.song.236000.json','["清漪閑照影，凉意滿闌干。", "湖近秋聲早，廊虛月影寬。", "鶴棲庭翠濕，魚動水香寒。", "欲放雲來去，移將竹數竿。"]'),
('2624044c-1e94-405b-8cb6-48f13d5063df','次李監見寄韻二首  其一','周密','宋','宋诗','song-poetry','','[]','一曲長謠酒一樽，平生幽事在田園。',64,'全唐诗/poet.song.236000.json','["一曲長謠酒一樽，平生幽事在田園。", "孤雲野鶴閑情遠，流水青山古意存。", "愛竹每思眠白屋，種瓜已分老青門。", "短衣掩骭長竿釣，最憶南谿與北村。"]'),
('ad1a3966-d0bf-4798-ac2f-c18da46fb2a0','次李監見寄韻二首  其二','周密','宋','宋诗','song-poetry','','[]','竹色松聲入夢凉，屐痕猶記印山廊。',64,'全唐诗/poet.song.236000.json','["竹色松聲入夢凉，屐痕猶記印山廊。", "娟娟秋水芙蓉屋，采采芳洲薜荔裳。", "招隠幾時尋舊約，懷人此日各他方。", "溟鯤林鷃知誰樂，欲把南華問老莊。"]'),
('f51acfea-805e-464a-8a04-e6f79b3d7bd2','積慶山訪金蓀壁','周密','宋','宋诗','song-poetry','','[]','松香竹粉午陰清，閑玩幽芳靜聽鶑。',32,'全唐诗/poet.song.236000.json','["松香竹粉午陰清，閑玩幽芳靜聽鶑。", "誰在白雲堆裏住，忽聞山半讀書聲。"]'),
('ce79986c-f7e1-4f83-a586-4283f8e29bab','次牟德範客中即事','周密','宋','宋诗','song-poetry','','[]','華胥槐國夢中名，鍾鼎山林孰重輕。',32,'全唐诗/poet.song.236000.json','["華胥槐國夢中名，鍾鼎山林孰重輕。", "爭似東臯新雨足，短秧微月聽蛙聲。"]'),
('bdea956c-5dc9-46d3-915f-32999ef411a3','挽雪林李和父二首  其一','周密','宋','宋诗','song-poetry','','[]','燈雨蘋洲憶舊盟，遊仙賦就五雲深。',64,'全唐诗/poet.song.236000.json','["燈雨蘋洲憶舊盟，遊仙賦就五雲深。", "梁園授簡春風醉，吳苑敲詩夜雪吟。", "貧病一生無舊業，江湖八十有知音。", "隻雞斗酒梅邊屋，九辯空招不可尋。"]'),
('cd448c9b-c28e-4e41-85c5-262cd7081040','挽雪林李和父二首  其二','周密','宋','宋诗','song-poetry','','[]','生際斯文極盛時，乾淳諸老盡心知。',64,'全唐诗/poet.song.236000.json','["生際斯文極盛時，乾淳諸老盡心知。", "四朝菏澤遺民傳，千首吳興處士詩。", "頗怪淵明生自些，絕憐和靖老無兒。", "死生遇合真難偶，奇事人傳貞曜碑。"]'),
('2dd428aa-28d8-4c5e-8c72-6a9ccf50a43a','贈李若虛','周密','宋','宋诗','song-poetry','','[]','江湖游遍到長安，自寫名山作畫看。',64,'全唐诗/poet.song.236000.json','["江湖游遍到長安，自寫名山作畫看。", "蟬腹祇便風露飽，鶴心偏喜水雲寬。", "袖中六甲三關式，肘後千金九鍊丹。", "更約小窗松月夜，素琴重爲作猗蘭。"]'),
('058040d8-c050-4a5a-b5d4-ea384cdd2e03','懷施仲山','周密','宋','宋诗','song-poetry','','[]','春來日日兩堤邊，醒即狂吟醉即眠。',64,'全唐诗/poet.song.236000.json','["春來日日兩堤邊，醒即狂吟醉即眠。", "午飲每賒新路酒，晚歸多喚裏湖船。", "生逢坡老憐詞客，死共花翁配水仙。", "一點梅魂招不得，愁來時展詠香編。"]'),
('4b46d671-2d11-44a1-ab87-01193e48fa6f','感秋雜興十解  其一','周密','宋','宋诗','song-poetry','','[]','清映臨澄淵，孤嘯躋絕嶺。',48,'全唐诗/poet.song.236000.json','["清映臨澄淵，孤嘯躋絕嶺。", "片雲開太虛，約略見秋影。", "銛飆刮浮翳，洗此玉萬頃。", "飛冰點空青，淅灑發深省。"]'),
('3fd3d29b-4d3e-4376-bafe-446f52c2df35','感秋雜興十解  其二','周密','宋','宋诗','song-poetry','','[]','千山脫木瘦，四壁號蟲瘖。',48,'全唐诗/poet.song.236000.json','["千山脫木瘦，四壁號蟲瘖。", "每於動靜間，窺見天地心。", "水落澤國秋，薦稻登川禽。", "一醉吾事畢，毋作嗚嗚吟。"]'),
('bb885830-4181-48fd-8c84-e700984773c6','感秋雜興十解  其三','周密','宋','宋诗','song-poetry','','[]','露泫草併白，霜肅山弄黄。',48,'全唐诗/poet.song.236000.json','["露泫草併白，霜肅山弄黄。", "蜩螿底須哀，寒燠乃其常。", "蒲蓮弄凉影，蘭茝發野芳。", "獨立天壤間，萬籟供吟吭。"]'),
('79dc566c-d677-4787-a92a-3c726c3bd862','感秋雜興十解  其四','周密','宋','宋诗','song-poetry','','[]','語大類迂誕，語小徒咿優。',48,'全唐诗/poet.song.236000.json','["語大類迂誕，語小徒咿優。", "據梧默不發，此心與天游。", "年運不假人，迅逝如川流。", "所歎道不昌，貧賤非所羞。"]'),
('406a6826-8446-4c03-b87b-14f1370c1aee','感秋雜興十解  其五','周密','宋','宋诗','song-poetry','','[]','衝風挾新寒，激射窗紙破。',48,'全唐诗/poet.song.236000.json','["衝風挾新寒，激射窗紙破。", "寸心集百憂，驚嘆中夕坐。", "豈無激昂志，蹇步多跌蹉。", "平治付聖賢，白雲政堪卧。"]'),
('d6014f48-1ab5-4ef6-a8ca-064c4791aa4c','感秋雜興十解  其六','周密','宋','宋诗','song-poetry','','[]','翳翳螢影微，札札蟲羽振。',48,'全唐诗/poet.song.236000.json','["翳翳螢影微，札札蟲羽振。", "一雁從西來，坐覺秋事進。", "漫游亦何有，所得雪滿鬢。", "老我一卷書，風燈剔凉燼。"]'),
('025b60a8-daa1-4e15-91e7-8b88db01e105','感秋雜興十解  其七','周密','宋','宋诗','song-poetry','','[]','矮屋病秋暍，內熱燒中腸。',48,'全唐诗/poet.song.236000.json','["矮屋病秋暍，內熱燒中腸。", "濯濯雨露姿，心眼生奇凉。", "鄉來翕翕威，奄忽歸何方。", "天時且如此，人事安可常。"]'),
('654fbed0-c952-461c-bf6d-c4a976ed129a','感秋雜興十解  其八','周密','宋','宋诗','song-poetry','','[]','有有必有無，無無乃無迹。',48,'全唐诗/poet.song.236000.json','["有有必有無，無無乃無迹。", "憧憧一世中，草草百年客。", "何能强解事，穿鑿辨堅白。", "醉卧蓬蓽秋，落葉深一尺。"]'),
('87474534-e31c-445a-8988-9f9693b17c1e','感秋雜興十解  其九','周密','宋','宋诗','song-poetry','','[]','萬壑開青瑶，一雨凉意足。',48,'全唐诗/poet.song.236000.json','["萬壑開青瑶，一雨凉意足。", "空明發遐想，八極歸一矚。", "意行不知遠，路轉雲幾曲。", "悠哉復悠哉，孤吟竚秋綠。"]'),
('11c46a9a-af9d-4a03-be92-0e6122ce9517','感秋雜興十解  其一○','周密','宋','宋诗','song-poetry','','[]','激激泉底石，謖謖松下風。',48,'全唐诗/poet.song.236000.json','["激激泉底石，謖謖松下風。", "天籟生泬寥，地籟號崆峒。", "清響來無時，吹萬有不同。", "忽得千古心，元自一噫中。"]'),
('cad1bf86-b511-4bdf-9dfe-8a5d2a8f4d51','訪簡上人退居不遇','周密','宋','宋诗','song-poetry','','[]','一菴秋影外，水竹自逶迤。',48,'全唐诗/poet.song.236000.json','["一菴秋影外，水竹自逶迤。", "愛靜多辭客，因禪忽悟詩。", "蘚香侵坐具，花凈入軍持。", "杖錫何方去，雲邊有鶴知。"]'),
('3afd401d-3f97-40a0-97e4-f0747608afc2','殘暑','周密','宋','宋诗','song-poetry','','[]','殘暑有歸意，倦遊猶異鄉。',48,'全唐诗/poet.song.236000.json','["殘暑有歸意，倦遊猶異鄉。", "不知何處雨，頓覺夜來凉。", "老樹摇黄落，秋花弄白香。", "登樓正多感，一笛起山陽。"]'),
('6d69e3e2-8df5-4f03-be6d-4239cd25d47e','孫岳從軍後歸吳','周密','宋','宋诗','song-poetry','','[]','秋入金瘡祇自悲，十年弓劍老西陲。',32,'全唐诗/poet.song.236000.json','["秋入金瘡祇自悲，十年弓劍老西陲。", "不須更賦從軍樂，且和田園雜興詩。"]'),
('d2d19086-e3fc-4df9-bbd5-f760fdc34188','愁望','周密','宋','宋诗','song-poetry','','[]','竹枝裊裊采香舟，桃葉依依罨畫樓。',32,'全唐诗/poet.song.236000.json','["竹枝裊裊采香舟，桃葉依依罨畫樓。", "一種垂楊芳草色，江南江北盡供愁。"]'),
('b4cc20b8-c8a5-491c-b986-cf78b1f36a6f','歸航夜雨有感','周密','宋','宋诗','song-poetry','','[]','扣舷何處起吳歌，客思由來入夜多。',64,'全唐诗/poet.song.236000.json','["扣舷何處起吳歌，客思由來入夜多。", "感憤詩篇偏跌宕，飄浮身世任蹉跎。", "風摇岸火如飛電，雨打溪蓬似滴荷。", "十載別鷗成底事，依然西塞曬漁簑。"]'),
('e8b98de8-e0a3-4a93-8546-d48899fa5191','飛來峰','周密','宋','宋诗','song-poetry','','[]','九里松香古寺邊，嶺雲深處湧青蓮。',64,'全唐诗/poet.song.236000.json','["九里松香古寺邊，嶺雲深處湧青蓮。", "何年佛始入中國，此日山移自五天。", "僧定白猿吟夜月，客遊蒼鷲舞秋烟。", "幽人最怕山歸去，自宿空亭聽冷泉。"]'),
('c714ab18-464d-45ae-b3f7-96346c75cf5b','觀潮','周密','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','一線微茫遠未分，鼓行漸出海山門。',64,'全唐诗/poet.song.236000.json','["一線微茫遠未分，鼓行漸出海山門。", "六鰲玉界移天柱，萬騎冰河渡夜軍。", "天上虧盈隨月魄，人間忠憤感胥魂。", "吳兒不怕蛟龍怒，踏浪翻旗入陣雲。"]'),
('18a4ee8c-73ef-475d-b892-622c4cf1e82c','問梅北山','周密','宋','宋诗','song-poetry','','[]','風行萬里道，冰落千仞淵。',72,'全唐诗/poet.song.236000.json','["風行萬里道，冰落千仞淵。", "草木凘欲盡，寂寂無華妍。", "彼美含章姿，炯炯方孤鶱。", "始知春風心，元在天地先。", "六陰忽已復，生意森無邊。", "因之得道妙，花與詩俱玄。"]'),
('a8cbad1e-42bb-4a29-a677-64a334c5b5fc','題雪谿圖四言','周密','宋','宋诗','song-poetry','','[]','宇宙無聲，天地一色。',40,'全唐诗/poet.song.236000.json','["宇宙無聲，天地一色。", "扁舟何人，去來無迹。", "言雖不傳，意自有得。", "千古真清，萬里虛白。"]'),
('cb28b2b9-9a10-41e1-9399-cfa7793ab98a','春夜','周密','宋','宋诗','song-poetry','','[]','九曲欄干六曲屏，翠窗羅薄護寒輕。',32,'全唐诗/poet.song.236000.json','["九曲欄干六曲屏，翠窗羅薄護寒輕。", "空堂燕子歸期誤，分付梨花管月明。"]'),
('06254d36-9a6f-498a-aa27-3e4b74ea6e27','有感次韻','周密','宋','宋诗','song-poetry','','[]','底用人前誦子虛，子安知我不知魚。',32,'全唐诗/poet.song.236000.json','["底用人前誦子虛，子安知我不知魚。", "最思萬竹香中隠，剩采春薇讀好書。"]'),
('57751c50-c06b-46c2-8d14-fedc11061640','江南怨','周密','宋','宋诗','song-poetry','','[]','徐庾風流恨未銷，東風腸斷冶城橋。',32,'全唐诗/poet.song.236000.json','["徐庾風流恨未銷，東風腸斷冶城橋。", "臨春結綺空千尺，不及王家燕子巢。"]'),
('dded283a-855c-4585-ad80-ef14940368cc','秋碪怨','周密','宋','宋诗','song-poetry','','[]','風泠泠，月明明，風月誰家碪杵聲。',64,'全唐诗/poet.song.236000.json','["風泠泠，月明明，風月誰家碪杵聲。", "聲聲思遠道，少婦朱顔老。", "不但擣衣愁，愁在無衣擣。", "不擣月下碪，欲擣遊子心。", "遊子心非鐵，聞之寧不折。"]'),
('e337b874-2088-44da-8cc5-94d114a1c666','訪客南山僧舍','周密','宋','宋诗','song-poetry','','[]','入門都是竹，景象自然幽。',48,'全唐诗/poet.song.236000.json','["入門都是竹，景象自然幽。", "愛此千竿碧，因成竟日留。", "月移山欲近，雲起塔如浮。", "煙水秋城暮，疎鐘送去舟。"]'),
('de997bfd-6b40-43a2-8709-a12549edb82a','白蓮','周密','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','移根來太華，楚楚翠綃裳。',48,'全唐诗/poet.song.236000.json','["移根來太華，楚楚翠綃裳。", "玉冷擎仙掌，珠明滴露房。", "秋涵雲影淡，水印月痕香。", "好結廬山社，輕塵避夜凉。"]'),
('47c92101-eb90-402e-b5fb-b1019e74bd29','目眚','周密','宋','宋诗','song-poetry','','[]','多緣因暑毒，或謂是肝虛。',48,'全唐诗/poet.song.236000.json','["多緣因暑毒，或謂是肝虛。", "徼福黄連劑，羞明暗室居。", "醫云宜戒酒，兒勸莫看書。", "頗遠紛華事，觀心得自如。"]'),
('ee40b3ae-de4d-44da-bb27-6a7f8bd53091','試秋衣有感','周密','宋','宋诗','song-poetry','','[]','鬢霜吹不去，三見雁南飛。',48,'全唐诗/poet.song.236000.json','["鬢霜吹不去，三見雁南飛。", "落葉已如此，倦游猶未歸。", "愁生慈母線，塵化主家衣。", "耕釣真良策，初心不可違。"]'),
('0c59211a-5273-4678-8d8b-667349111f01','神山行題澄江仙刻','周密','宋','宋诗','song-poetry','','[]','空光不流八紘凈，巀嶭神鼇開海鏡。',160,'全唐诗/poet.song.236000.json','["空光不流八紘凈，巀嶭神鼇開海鏡。", "蓬萊八萬四千門，琲琲珠房照仙影。", "琪花撲天天地香，天吳清海海不揚。", "鳥飛不度水沉羽，隔花安得窺漁郎。", "白霓仙人按仙曲，七十二鬟吟冷玉。", "鵝簫小品未成聲，幾度秋蝸換蠻觸。", "簾花宮葉春不同，江妃一一金芙蓉。", "劉郎骨朽夢不到，五雲空廓吟饑龍。", "靈霞漾紅春苒苒，犀彩玉光摇寶燄。", "元君正坐鬰蕭臺，笑指神州烟九點。"]'),
('d4f24c76-a7f0-4a67-9b36-9a48d4260d1e','愚隠適興','周密','宋','宋诗','song-poetry','','[]','錦雲照空明，蒼烟貯閑靜。',144,'全唐诗/poet.song.236000.json','["錦雲照空明，蒼烟貯閑靜。", "中有曲曲廊，幽眇入詩境。", "小山懸秋香，澄淵度雲影。", "流觴有古意，坐久苔石冷。", "展我架上書，萬卷牙籤整。", "撫我膝上琴，坐覺白日永。", "升高得孤嶠，汲古有甘井。", "居然謝囂𡏖，宛若處幽屏。", "豈惟寄遊息，端可事修省。", "何當佳月夕，來此步清景。", "此趣非言傳，真樂當自領。", "野語質不華，聊以寓微警。"]'),
('c2062f85-cb9a-4f44-84c7-dd62b9e1ee4b','六言二首  其一','周密','宋','宋诗','song-poetry','','[]','笑殺楦中青紫，從他皮裏陽秋。',28,'全唐诗/poet.song.236000.json','["笑殺楦中青紫，從他皮裏陽秋。", "白首潛郎不調，青雲妄尉皆侯。"]'),
('0a11836c-8c01-414d-a56c-38f4d4293d70','六言二首  其二','周密','宋','宋诗','song-poetry','','[]','蕉鹿夢疑非夢，木雁材與不材。',28,'全唐诗/poet.song.236000.json','["蕉鹿夢疑非夢，木雁材與不材。", "與其封一萬戶，何如飲三百杯。"]'),
('f97673e4-7620-4f40-b570-db7c54044537','奉寄朔翁','周密','宋','宋诗','song-poetry','','[]','苕風蘋月隔吳波，尚想追隨寤寐歌。',32,'全唐诗/poet.song.236000.json','["苕風蘋月隔吳波，尚想追隨寤寐歌。", "花外小車遊甚處，春風三十六行窩。"]'),
('e1837193-4de6-47d2-aab3-09e9a10a8164','穀日野步','周密','宋','宋诗','song-poetry','','[]','過了梅花第一風，東臯南陌漸融融。',32,'全唐诗/poet.song.236000.json','["過了梅花第一風，東臯南陌漸融融。", "柔桑弱柳俱青眼，看見春歸阿堵中。"]'),
('c9397fa9-ea46-4506-89d6-5770cc00aa8e','姚灣別墅','周密','宋','宋诗','song-poetry','','[]','別墅有幽事，閒移書畫船。',48,'全唐诗/poet.song.236000.json','["別墅有幽事，閒移書畫船。", "白田吹落雁，紅樹咽衰蟬。", "詩酒消閑日，功名負壯年。", "此中如可隠，何用買山錢。"]'),
('2accd603-9676-4db7-8edc-45865fbaec4a','送友人及第後歸','周密','宋','宋诗','song-poetry','','[]','賈生年正少，危掇奉常科。',48,'全唐诗/poet.song.236000.json','["賈生年正少，危掇奉常科。", "拾第便堪貴，讀書何用多。", "御黄聞喜酒，宮綠上方羅。", "見謂清流選，歸鳴里巷珂。"]'),
('f9e6e34a-5bb6-4962-bc9f-81332b8dd7de','桂','周密','宋','宋诗','song-poetry','','[]','小山招隠樹，獨占九秋凉。',48,'全唐诗/poet.song.236000.json','["小山招隠樹，獨占九秋凉。", "清對月中影，靜聞天上香。", "露侵犀透粟，雲染麝生黄。", "莫待吹金雨，花邊把一觴。"]'),
('6510f41a-4446-49b6-8fd3-76171ba1e8a6','元日口號','周密','宋','宋诗','song-poetry','','[]','侵晨書吉向門楣，願得新正事事宜。',32,'全唐诗/poet.song.236000.json','["侵晨書吉向門楣，願得新正事事宜。", "手把屠蘇揩睡眼，燈前吟足隔年詩。"]'),
('8ec3d07c-ace1-4c2d-bde7-2e0ac1bf9ccb','香奩','周密','宋','宋诗','song-poetry','','[]','寬損羅裙疊損眉，芳年心事有誰知。',32,'全唐诗/poet.song.236000.json','["寬損羅裙疊損眉，芳年心事有誰知。", "朱門鎖合春宵雨，獨立空堂燭暗時。"]'),
('2e2fcf7e-71d7-4ea2-b33d-4931a30dde32','春宵怨','周密','宋','宋诗','song-poetry','','[]','華缸摇燄飄金蟲，愁鉛墮睫鮫綃紅。',64,'全唐诗/poet.song.236000.json','["華缸摇燄飄金蟲，愁鉛墮睫鮫綃紅。", "瓊窗塵鎖十三雁，春庭月暗梨花空。", "城烏鴉鴉怨孤宿，誰倚東風叫橫玉。", "寶屏掩夢蜀雲輕，野蒿開盡菖蒲綠。"]'),
('37715073-522f-4271-bf1c-98abb144d496','春夜懷張去非','周密','宋','宋诗','song-poetry','','[]','芳事將三月，虛堂近二更。',48,'全唐诗/poet.song.236000.json','["芳事將三月，虛堂近二更。", "薄霒禁害月，小雨護持春。", "靜得琴書味，閒知草木情。", "薄篘今日熟，洗杓待幽人。"]'),
('ca11c029-c6a2-409e-be03-f48582bc2921','病後窺園','周密','宋','宋诗','song-poetry','','[]','柳已成花草上階，一程多病不曾來。',32,'全唐诗/poet.song.236000.json','["柳已成花草上階，一程多病不曾來。", "春寒定似知人意，要勒花枝未盡開。"]'),
('e47a6c6e-b29e-4f1f-b736-af482aac43e0','宋季實爲作山水清遠圖','周密','宋','宋诗','song-poetry','','[]','綠雲漲脩堤，紅霧迷橫橋。',84,'全唐诗/poet.song.236000.json','["綠雲漲脩堤，紅霧迷橫橋。", "烟村近城郭，樓臺鬰岧嶢。", "春風二三月，一舸浮清苕。", "枕水何人居，倚戶看輕橈。", "回頭見南山，孤塔峨山椒。", "耕牛引閑犢，秧水浮新苗。", "悠然愛吾廬，楚語何待招。"]'),
('3d3774ca-bbe0-4801-9064-c0fb982dc02a','枕上','周密','宋','宋诗','song-poetry','','[]','一櫺霜月一篝燈，殘夢新詩兩不成。',32,'全唐诗/poet.song.236000.json','["一櫺霜月一篝燈，殘夢新詩兩不成。", "喚醒少年湖海意，五更枕上聽潮聲。"]'),
('63661a2b-1833-46e4-8ec0-ca77e3c21131','毗山晚歸','周密','宋','宋诗','song-poetry','','[]','短榜歸來晚，船頭對夕陽。',48,'全唐诗/poet.song.236000.json','["短榜歸來晚，船頭對夕陽。", "亂鐘城市近，一雁水天長。", "草眼矜春碧，梅心弄晚香。", "霜風吹酒醒，繫纜欲昏黄。"]'),
('85e4c921-0336-4de4-a9f6-7e091a06bdfa','觸熱行','周密','宋','宋诗','song-poetry','','[]','役役復役役，連山草頭赤。',92,'全唐诗/poet.song.236000.json','["役役復役役，連山草頭赤。", "千里無寸陰，赫日蒸砂石。", "黄塵瞇我眼，白汗流我綌。", "僕羸渴欲死，馬瘏喘而瘠。", "觸熱者何人，京華利名客。", "何如歸去卧北窗，桃笙八尺晝夢長。", "素琴枕籍書數卷，受用不盡南風凉。"]'),
('2cc23131-d452-4505-b097-701acfe5a70a','錦带花','周密','宋','宋诗','song-poetry','','[]','化工機杼未能休，織出東風錦一篝。',32,'全唐诗/poet.song.236000.json','["化工機杼未能休，織出東風錦一篝。", "雙蝶舞春猶未竟，亂紅飛下爲纏頭。"]'),
('47a10d84-4663-43be-972a-6ad3a349b0d9','和親老蒼玉洞韻','周密','宋','宋诗','song-poetry','','[]','去郭僅數里，巖關忽深秀。',289,'全唐诗/poet.song.236000.json','["去郭僅數里，巖關忽深秀。", "人工莫窺測，天巧自成就。", "瑶草覆蓬萊，箭砂藏勾漏。", "如入萬寶山，如坐羣玉囿。", "贔屭撐巨鼇，回翔舞飛鷲。", "肉醉猛虎卧，雷轟懶蛟走。", "遠絕人世塵，靜閲古今宙。", "或若赴壑蛇，或如回顧獸。", "噴者如鯨呿，𠹛者如龍吼。", "詭然足變幻，不可窮步驟。", "土清多芷蘭，石瘦少薪槱。", "松柏森古姿，寒暑不得寇。", "風靜柳新梳，雲收山免胄。", "石鏡磨古詩，玉釵瀉寒溜。", "郊原遍紅紫，川谷成錦繡。", "玄猿叫老木，石乳滴嵌竇。", "寺建開平初，亭剏宣和後。", "客屨踏花香，僧衣卧雲縐。", "碧蘿暗雨意，綠陰靚春晝。", "高吟領景趣，玩物驚節候。", "晴箔收早蠶，烟蓑正初耨。", "暇日多勝游，嘉賓從賢守。", "歌聲振林木，妝影摇漣甃遊。", "鳥啼覺山靜，湍急和雲漱。"]'),
('0dfdccb9-da9a-49aa-b942-1b6092cd4160','九日','周密','宋','宋诗','song-poetry','','[]','轉頭還九日，風雨阻登臨。',48,'全唐诗/poet.song.236000.json','["轉頭還九日，風雨阻登臨。", "綠酒自醒醉，黄花無古今。", "凄凉三徑意，感慨百年心。", "喚醒斜川夢，持盃且一吟。"]'),
('8274eda8-bdb5-44e2-aaba-901eaaf8c1f2','江樓晚眺','周密','宋','宋诗','song-poetry','','[]','樓外千帆送夕陽，水烟山色共滄茫。',64,'全唐诗/poet.song.236000.json','["樓外千帆送夕陽，水烟山色共滄茫。", "吳蟬已老豆花落，江雁欲賓蘆葉黄。", "簾影夢回千里月，鬢絲愁染九秋霜。", "紅蘭珮古荷裳冷，澤畔行吟賦短章。"]'),
('4642a7a6-986a-422e-9369-84fa416c9527','花邊小勺雜言','周密','宋','宋诗','song-poetry','','[]','我花今日開，我酒今日熟。',72,'全唐诗/poet.song.236000.json','["我花今日開，我酒今日熟。", "我今適無事，可以歌我曲。", "花意向我紅，酒意向我綠。", "重此花酒意，一醉不翅足。", "富貴如飛埃，歲月如轉轂。", "醉舞君勿嗤，一笑未易卜。"]'),
('cedd86c5-8dda-46da-b6d7-120beb99c0f2','晚氣','周密','宋','宋诗','song-poetry','','[]','晚氣吹澄鮮，幽碧弄秋卉。',24,'全唐诗/poet.song.236000.json','["晚氣吹澄鮮，幽碧弄秋卉。", "得意雙蜻蜓，竟日掛竹尾。"]'),
('81c3ae1d-d5db-4e9b-9f4d-6ef6ed5fcaf0','秋夜讀書','周密','宋','宋诗','song-poetry','','[]','翦燭聽秋雨，新凉入簡編。',48,'全唐诗/poet.song.236000.json','["翦燭聽秋雨，新凉入簡編。", "心能無一事，意可到千年。", "治亂無今古，扶持有聖賢。", "鄰翁應笑我，漏斷未成眠。"]'),
('41e73ede-480c-40f1-951b-591f8f2e72a7','夜雨泊雙林','周密','宋','宋诗','song-poetry','','[]','疎雨滴秋篷，扁舟宿葦叢。',48,'全唐诗/poet.song.236000.json','["疎雨滴秋篷，扁舟宿葦叢。", "水燈寒聚蟹，霜櫓夜驚鴻。", "夢入滄茫外，詩成慘淡中。", "無成空白首，來往愧溪翁。"]'),
('e7c37b25-9c2a-4ac6-80f9-8276707e0d32','湖邊逢陳高父','周密','宋','宋诗','song-poetry','','[]','湖邊重見處，柳下共聽蟬。',48,'全唐诗/poet.song.236000.json','["湖邊重見處，柳下共聽蟬。", "人老如前度，詩工似往年。", "醉鄉消白日，身事付蒼天。", "自得吟千首，他時定可傳。"]'),
('69093c0e-ab3f-4ec4-8f46-4d9350e3e505','繡谷即事','周密','宋','宋诗','song-poetry','','[]','春苦無多已綠陰，重來泉石快幽尋。',32,'全唐诗/poet.song.236000.json','["春苦無多已綠陰，重來泉石快幽尋。", "碧桃一院無人到，獨自聞鶑獨自吟。"]'),
('c5a0c5ca-5e6d-4a12-8e02-b2d223493ffb','度小嶺','周密','宋','宋诗','song-poetry','','[]','前山青未了，又踏翠千尋。',48,'全唐诗/poet.song.236000.json','["前山青未了，又踏翠千尋。", "衣冷度雲影，耳清聞澗音。", "早衰占足力，多嶮見人心。", "切勿臨高望，三吳草色深。"]'),
('0f512a48-3cff-46b8-b4d4-001360aced42','黄巢戰場','周密','宋','宋诗','song-poetry','','[]','腐儒階亂亦堪傷，故老猶傳古戰場。',32,'全唐诗/poet.song.236000.json','["腐儒階亂亦堪傷，故老猶傳古戰場。", "怨血已銷朝代遠，平岡春草似人長。"]'),
('06b7485d-46a6-43d8-a989-64606658d2d4','野步','周密','宋','宋诗','song-poetry','','[]','麥隴風來翠浪斜，草根肥水噪新蛙。',32,'全唐诗/poet.song.236000.json','["麥隴風來翠浪斜，草根肥水噪新蛙。", "羨他無事雙蝴蝶，爛醉東風野草花。"]'),
('c925bfd6-224c-4645-8d2a-dc1d67579ad0','古別怨','周密','宋','宋诗','song-poetry','','[]','吳王高城棲暮鴉，江南草綠人離家。',32,'全唐诗/poet.song.236000.json','["吳王高城棲暮鴉，江南草綠人離家。", "流黄空織不成匹，門前莫種菖蒲花。"]'),
('17d60ffa-3b15-41cf-a254-474e1fccd13f','奉還山西詩卷','周密','宋','宋诗','song-poetry','','[]','詩腸抱饑饞，嗜句如嗜炙。',168,'全唐诗/poet.song.236000.json','["詩腸抱饑饞，嗜句如嗜炙。", "長年齚雞跖，有味如啖蔗。", "轑釜轟腹雷，每遭丘嫂駡。", "辛勤謀一飽，索米誰肯借。", "忽來五侯鯖，心目爲驚詫。", "大羹足真味，禁臠增重價。", "仙露承金莖，天漿灧瓊斝。", "何修乃得此，咀嚼日不暇。", "每擬賦老饕，欲作口屢嗄。", "錦鯨出光怪，把玩涉秋夏。", "珍重十襲藏，常恐六丁下。", "每思隨𥊍御，不足攀逸駕。", "清晨呼墨卿，爲我再四謝。", "莫能贊一辭，泚顙慚久假。"]'),
('83eb6e14-ca91-4f1d-8867-5df7ff74b86f','湘江風雨圖','周密','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','黯黯秋空漠漠雲，瑟聲依約聽湘靈。',32,'全唐诗/poet.song.236000.json','["黯黯秋空漠漠雲，瑟聲依約聽湘靈。", "夜篷碎滴風燈暗，猶記孤舟泊洞庭。"]'),
('c26d3822-a0be-40f3-a475-46ed0fff8ace','神絃','周密','宋','宋诗','song-poetry','','[]','棘櫟叢祠晝淒楚，隠畫廊深山鬼語。',96,'全唐诗/poet.song.236000.json','["棘櫟叢祠晝淒楚，隠畫廊深山鬼語。", "香火千年古像昏，十圍老木藏飛鼠。", "芳蘭藉地羅蕙蒸，陰風窸窣吹神燈。", "舞蠻姣服炫紅緯，雲旂飆御聲䡌䡌。", "繭甕千車麥雙穗，社主蠶姑拜神賜。", "鼓聲坎坎酒頻釃，神來不來巫自醉。"]'),
('264534f6-017f-4980-8356-1355b7cd38f0','挽菊坡趙侍制二首  其一','周密','宋','宋诗','song-poetry','','[]','貴胄才華自昔慳，如公名德世難攀。',64,'全唐诗/poet.song.236000.json','["貴胄才華自昔慳，如公名德世難攀。", "杏園新賜金花帖，荷橐高躋玉筍班。", "麾節一生多浙右，詩書千載接河間。", "感懷空抱羊曇恨，遥望西州淚雨潸。"]'),
('7ff4216e-8fc2-41a6-86b3-e35fb7a4ad67','挽菊坡趙侍制二首  其二','周密','宋','宋诗','song-poetry','','[]','一從弓劍鼎湖游，有詔王孫記玉樓。',64,'全唐诗/poet.song.236000.json','["一從弓劍鼎湖游，有詔王孫記玉樓。", "天上曉班催聽履，人閒夜壑忽移舟。", "霜殘舊菊荒三徑，雨泣新松掩一丘。", "別墅甫成清夢斷，梅花空老水空流。"]'),
('8bb4c1d8-aae6-4dac-a2d3-03277660b079','挽張運幹','周密','宋','宋诗','song-poetry','','[]','同里復同寅，相過意最親。',48,'全唐诗/poet.song.236000.json','["同里復同寅，相過意最親。", "我方賢此老，天不憖斯人。", "有記書先友，無車送後塵。", "平生交舊淚，一灑霅谿濱。"]'),
('17c2c7a7-c343-4474-83bf-1f5a246c8720','挽韓子爽戶曹二首  其一','周密','宋','宋诗','song-poetry','','[]','朋輩凋疎重可傷，不堪歌哭獻文堂。',64,'全唐诗/poet.song.236000.json','["朋輩凋疎重可傷，不堪歌哭獻文堂。", "寶燈卜夜笙簫暖，芳檻移春錦繡香。", "樂事可憐蕉夢短，哀辭忽引薤歌長。", "忍看玉樹埋黄壤，淚溼東風酒一觴。"]'),
('7fef9707-1539-439f-969f-4e8b538371b3','挽韓子爽戶曹二首  其二','周密','宋','宋诗','song-poetry','','[]','藍衣槐笏色方新，賀者纔稀弔在門。',64,'全唐诗/poet.song.236000.json','["藍衣槐笏色方新，賀者纔稀弔在門。", "驂鳳風流秦穆壻，停鸞高爽北平孫。", "蘭階有子堪扶殯，麟窟無香可返魂。", "愁絕裏山山下路，老梅殘雪月黄昏。"]'),
('bd5d8674-c6b1-4ccc-8667-c07c07641396','小滄浪亭','周密','宋','宋诗','song-poetry','','[]','繞屋雙流碧玉交，了然清濁不相撓。',64,'全唐诗/poet.song.236000.json','["繞屋雙流碧玉交，了然清濁不相撓。", "吾心涇渭本無混，有味淄澠自莫逃。", "釃派欲箋鴻漸品，濯纓堪賦楚平騷。", "人間此是無波處，已辦天隨一葉舠。"]'),
('f71d3fac-8622-4859-9046-f0b0f5021b40','烈帝廟','周密','宋','宋诗','song-poetry','','[]','英風千載後，谿上有遺祠。',48,'全唐诗/poet.song.236000.json','["英風千載後，谿上有遺祠。", "異鵲巢神檜，靈黿集廟池。", "煙雲昏古像，苔蘚蝕豐碑。", "細把圖經考，孤忠事更奇。"]'),
('68ef015b-4a90-45ef-8d65-c117857ef837','晚泊','周密','宋','宋诗','song-poetry','','[]','清霜微月夜，紅葉古塘西。',48,'全唐诗/poet.song.236000.json','["清霜微月夜，紅葉古塘西。", "野港沿村曲，秋雲接樹低。", "蟹燈寒照水，鳬弋遠侵谿。", "未踐天隨約，詩成意自迷。"]'),
('b096ee4d-6253-4438-b3ec-b600b7f196cb','藏書示兒','周密','宋','宋诗','song-poetry','','[]','少年誦詩書，頗有稽古志。',288,'全唐诗/poet.song.236000.json','["少年誦詩書，頗有稽古志。", "中焉得良師，講說擊蒙昧。", "步趨古聖賢，千載儼如對。", "豈惟收放心，中自有樂地。", "維持識綱常，討訪極根柢。", "同異辯堅白，委曲窮瑣細。", "精微究七略，獵涉到百類。", "近求事物間，遠探天人際。", "研朱極讎校，鉤玄謹書識。", "揚子喜問奇，中郎欣得異。", "源委本六經，上下獵衆智。", "雖爲吏坌汩，此事亦不置。", "矻矻常窮年，何敢嘆勞勩。", "初非事進取，蓋亦志平治。", "庶幾致吾君，不負學古意。", "豈期事大繆，分寸不可冀。", "或病元凱癖，或嘲孝先睡。", "亦惟殖鹵莽，何敢望穫刈。", "穮蔉當益勤，會見逢有歲。", "謏聞愧博識，鈍質無强記。", "少習日寖忘，瞠若殊有愧。", "夜行笑老學，雞跖不忍棄。", "正如蠹書魚，齕紙猶有味。", "千卷善和藏，萬籤鄴侯庋。"]'),
('fb6a1186-9c8b-4a63-9373-42834b9f5620','記夢','周密','宋','宋诗','song-poetry','','[]','剛風吹翠冰，倒景浮玄樞。',276,'全唐诗/poet.song.236000.json','["剛風吹翠冰，倒景浮玄樞。", "蕭臺萬八千，上有真仙居。", "冰綃絅清氣，寶笈龕瓊書。", "至人青瑶冠，風動雲霞裾。", "顧我一笑粲，勺以青琳腴。", "泠冷徹崑崙，肝鬲生明珠。", "玉童發清謠，引鶴開金鋪。", "授我碧露牋，字字如瓊琚。", "跽受九拜起，雲氣隨捲舒。", "靈文眩五色，奧語探皇初。", "青高不可極，玄晤常集虛。", "玉苗日茂茂，珠蕊春如如。", "天妙不費言，悟解超仙衢。", "飛樓入紫翠，笑語多天姝。", "馴龍耕玉田，小鳳扶金車。", "香滿十二簾，春動紅流蘇。", "脩欄瞰雲雨，黄道通清都。", "憶昔遊五城，十載纔須臾。", "正坐一念差，不覺秋塵汙。", "華池滌凡髓，重佩三元符。", "凜凜不可留，欲去還踟躕。", "仰天發長嘯，萬竅皆笙竽。", "約我更百年，來此騎鯨魚。"]'),
('fe930b22-ff25-4517-bbce-4ba2d72372c2','春歸','周密','宋','宋诗','song-poetry','','[]','草滿閑塘絮滿谿，萬株煙柳一鵑啼。',32,'全唐诗/poet.song.236000.json','["草滿閑塘絮滿谿，萬株煙柳一鵑啼。", "開簾恰見春歸處，花片東流日景西。"]'),
('22133f84-6dfd-4321-bd8a-663f0d33b011','喜張九至','周密','宋','宋诗','song-poetry','','[]','相逢頭盡白，握手便言詩。',48,'全唐诗/poet.song.236000.json','["相逢頭盡白，握手便言詩。", "不患吟難好，翻愁世少知。", "琴書存雅道，年運有通時。", "且醉花前酒，毋勞賦五噫。"]'),
('d2d17b57-68b6-49d1-9e11-cab05c14fe94','感村晚泊有懷','周密','宋','宋诗','song-poetry','','[]','短航橋外泊，暮靄濕荷衣。',48,'全唐诗/poet.song.236000.json','["短航橋外泊，暮靄濕荷衣。", "風正千帆上，谿虛一鳥飛。", "潦黄山雨過，燒綠野春歸。", "欲寄新詩句，東風雁影稀。"]'),
('1344e1d1-1a28-4518-988a-8fba3d663138','鷲峰','周密','宋','宋诗','song-poetry','','["\u897f\u6e56"]','碧岫岧嶢若畫圖，何年西竺到西湖。',64,'全唐诗/poet.song.236000.json','["碧岫岧嶢若畫圖，何年西竺到西湖。", "猿聲带月離仙國，鰲背移山入帝都。", "松撼翠濤雙澗冷，桂飄金雨一亭孤。", "却疑舞鷲隨風去，欲把雲關鎖得無。"]'),
('5c0d5afa-0e5a-4566-ac5d-7d780e564941','寄武昌友','周密','宋','宋诗','song-poetry','','[]','楚月東隨沔水流，相思應上庾公樓。',32,'全唐诗/poet.song.236000.json','["楚月東隨沔水流，相思應上庾公樓。", "樓前一片垂楊色，中有江南萬里愁。"]'),
('26a684db-3e72-444b-be40-bab50433cc51','章臺柳','周密','宋','宋诗','song-poetry','','[]','章華臺外千株柳，翠影如雲照碧天。',32,'全唐诗/poet.song.236000.json','["章華臺外千株柳，翠影如雲照碧天。", "霜葉露條應剪盡，可憐愁殺樹頭蟬。"]'),
('d6037a9c-df7f-4f8f-8d3d-5f1f0dd29084','對月','周密','宋','宋诗','song-poetry','','[]','空寒坐庭玉，四至皆白天。',72,'全唐诗/poet.song.236000.json','["空寒坐庭玉，四至皆白天。", "千林無俗聲，一葉時琤然。", "竹高散飛霜，池冷鎔流鉛。", "月以虛而明，心以虛而玄。", "心光射月彩，炯炯徹九淵。", "高吟撼老桂，驚起秋兔眠。"]'),
('fb257fc1-6626-42a6-9f66-a38037ce486e','有以漁舟唱晚作圖命題擬試者因戲成三首  其一','周密','宋','宋诗','song-poetry','','[]','絕妙王郎句，無聲小米圖。',48,'全唐诗/poet.song.236000.json','["絕妙王郎句，無聲小米圖。", "舷歌天地闊，笠釣水烟孤。", "暮色分濃淡，餘音似有無。", "卧遊千里外，展卷欲思鱸。"]'),
('3e52ebcb-f3f0-406c-8d25-ceecddd46fc4','有以漁舟唱晚作圖命題擬試者因戲成三首  其二','周密','宋','宋诗','song-poetry','','[]','展卷身疑在，西山南浦前。',48,'全唐诗/poet.song.236000.json','["展卷身疑在，西山南浦前。", "數聲秋水笛，一葉夕陽船。", "興寄滄浪外，機忘欵乃邊。", "欲參聲畫趣，細玩濯纓篇。"]'),
('2da170bb-f916-43d2-8fc0-dae991989333','有以漁舟唱晚作圖命題擬試者因戲成三首  其三','周密','宋','宋诗','song-poetry','','[]','浦雲山雨意，都向筆端生。',48,'全唐诗/poet.song.236000.json','["浦雲山雨意，都向筆端生。", "一笛山水綠，半篙煙浪清。", "淺深天似暝，聚散雁如驚。", "誰寫無聲句，無聲勝有聲。"]'),
('eff23f18-077f-4aa1-982e-a65bd190e4ec','塞寒曲','周密','宋','宋诗','song-poetry','','[]','千里驚沙瞇人目，天愁地暗烏鳶哭。',96,'全唐诗/poet.song.236000.json','["千里驚沙瞇人目，天愁地暗烏鳶哭。", "鐵甲霜濃徹骨寒，萬馬無聲虎貔縮。", "紅弰角勁雁影高，朔風栗栗銛於刀。", "銜枚夜戰路如漆，冰鬚墮指誇粗豪。", "將軍毳幕愁春熱，獵騎如雲踏燕雪。", "何處關樓起遠思，一聲霜竹吹梅裂。"]'),
('441bf7d0-312a-4386-a34c-80852d6ec28b','春郊即事','周密','宋','宋诗','song-poetry','','[]','野步足幽事，行行柳港邊。',48,'全唐诗/poet.song.236000.json','["野步足幽事，行行柳港邊。", "鼓聲何處碓，帆影隔溪船。", "節序多風雨，鶑花動歲年。", "徘徊歸向夕，山崦起炊烟。"]'),
('c03dad08-c718-483b-9197-ab3bb2e6c0ed','挽陳體忠二首  其一','周密','宋','宋诗','song-poetry','','[]','方驚成鵩賦，忽愴絕麟經。',48,'全唐诗/poet.song.236000.json','["方驚成鵩賦，忽愴絕麟經。", "才反能爲累，天乎不與齡。", "高堂慈母淚，幽誌長公銘。", "西望哀笳發，潸然涕泗零。"]'),
('fca5fedd-23f7-450a-8c3a-057ecaf75734','挽陳體忠二首  其二','周密','宋','宋诗','song-poetry','','[]','同僚同里閈，臭味最相投。',48,'全唐诗/poet.song.236000.json','["同僚同里閈，臭味最相投。", "有暇多徵逐，無詩不唱酬。", "方欣衣尚絅，不料玉爲樓。", "欲賦招魂些，秋雲凝古愁。"]'),
('fbeb0b22-6c49-4153-a203-fe461388e30c','重遊孤山有感二首  其一','周密','宋','宋诗','song-poetry','','[]','茗碗清分六一泉，暗香曾賦月娟娟。',32,'全唐诗/poet.song.236000.json','["茗碗清分六一泉，暗香曾賦月娟娟。", "別來短鬢如梅白，閑却東風十五年。"]'),
('d8e88c30-d484-430b-b18f-e1bcc806b23e','重遊孤山有感二首  其二','周密','宋','宋诗','song-poetry','','[]','年年雲木長蒼苔，瀛嶼春寒鶴不來。',32,'全唐诗/poet.song.236000.json','["年年雲木長蒼苔，瀛嶼春寒鶴不來。", "千尺粉垣圍苑樹，野梅今日是官梅。"]'),
('c0c988ba-0170-46e9-95a9-88f289fa4f7d','次德範韵二首  其一','周密','宋','宋诗','song-poetry','','[]','客裏光陰委逝波，問奇無客肯相過。',32,'全唐诗/poet.song.236000.json','["客裏光陰委逝波，問奇無客肯相過。", "素封未辦千頭橘，野服惟消一襲荷。"]'),
('97d5d726-c174-403d-b96a-05f0ce3ac25e','次德範韵二首  其二','周密','宋','宋诗','song-poetry','','[]','萬卷牙籤負善和，秋芸香淺蠹魚多。',32,'全唐诗/poet.song.236000.json','["萬卷牙籤負善和，秋芸香淺蠹魚多。", "近來始識書真味，意倦才荒柰老何。"]'),
('dc1aeef0-1628-4f2f-833b-2b3816f9a6e3','西塍廢圃','周密','宋','宋诗','song-poetry','','["\u5199\u666f", "\u6292\u60c5", "\u79cb\u5929"]','吟蛩鳴蜩引興長，玉簪花落野塘香。',32,'全唐诗/poet.song.236000.json','["吟蛩鳴蜩引興長，玉簪花落野塘香。", "園翁莫把秋荷折，留與遊鱼蓋夕陽。"]'),
('04b1d6fd-7caa-4eac-a058-04762afe3248','暮春次韻二首  其一','周密','宋','宋诗','song-poetry','','[]','簾外殘燈照夜愁，秭歸啼夢五更頭。',32,'全唐诗/poet.song.236000.json','["簾外殘燈照夜愁，秭歸啼夢五更頭。", "捲春一夜東風緊，倒約飛花入小樓。"]'),
('868bf9e8-bc32-48bc-b610-794e370a3904','暮春次韻二首  其二','周密','宋','宋诗','song-poetry','','[]','單衣初試覺身輕，芳徑無花午氣清。',32,'全唐诗/poet.song.236000.json','["單衣初試覺身輕，芳徑無花午氣清。", "風罥斷絲庭宇靜，日長時聽打茶聲。"]'),
('5f9b890a-4893-4116-9c66-0d8f8b96a042','歸春曲次韻','周密','宋','宋诗','song-poetry','','[]','花塵瞇目日脚昏，枝頭蜀鳥吟歸魂。',96,'全唐诗/poet.song.236000.json','["花塵瞇目日脚昏，枝頭蜀鳥吟歸魂。", "噴天狂雨浣香盡，綠填紅闕春無痕。", "醉踏蒼烟古臺上，老柳無情擘殘纊。", "寂歷芳條宿孕鶑，倒盡斜霞暗悲愴。", "東風恍恍如夢中，江吳烟醉薔薇紅。", "湘簾古春喚不應，孀娥淚眼空茸茸。"]'),
('48229228-21fa-4aa4-b7c9-e2ef59a5d1f6','五更','周密','宋','宋诗','song-poetry','','[]','處處清碪砌砌蛩，客眠不着五更風。',32,'全唐诗/poet.song.236000.json','["處處清碪砌砌蛩，客眠不着五更風。", "起來推戶尋詩句，一樹秋聲月色中。"]'),
('cc55916c-401d-4e05-8222-2bb82edb1342','逸人居','周密','宋','宋诗','song-poetry','','[]','避俗入山居，孤雲意自如。',48,'全唐诗/poet.song.236000.json','["避俗入山居，孤雲意自如。", "養丹文武火，插架古今書。", "歲釀常千石，朝飱止一蔬。", "畏人知住所，草徑不曾鋤。"]'),
('48c71112-7243-4a42-9bfd-474ca21ed4d7','社日即事','周密','宋','宋诗','song-poetry','','[]','社公雨過稻花香，過了中秋早晚凉。',32,'全唐诗/poet.song.236000.json','["社公雨過稻花香，過了中秋早晚凉。", "正是故園新酒熟，橙臍微綠蟹臍黄。"]'),
('e0ca2e94-06fc-426a-98dd-40e315f907db','漏靜','周密','宋','宋诗','song-poetry','','[]','漏靜知宵永，燈昏覺夜闌。',24,'全唐诗/poet.song.236000.json','["漏靜知宵永，燈昏覺夜闌。", "隔窗響秋葉，夢不到關山。"]'),
('eb12167d-65d1-4309-a11d-9584211dbba3','隴頭水','周密','宋','宋诗','song-poetry','','[]','隴阪縈九折，一折一愁絕。',36,'全唐诗/poet.song.236000.json','["隴阪縈九折，一折一愁絕。", "涓涓隴頭水，征人眼中血。", "水流有盡時，征人無還期。"]'),
('c1b024fc-6d0d-40c1-addb-b6705078537b','婕妤怨','周密','宋','宋诗','song-poetry','','[]','金鑰封紫苔，錦茵濕紅淚。',48,'全唐诗/poet.song.236000.json','["金鑰封紫苔，錦茵濕紅淚。", "永巷無風月，深宮謾歌吹。", "恨如合歡扇，秋來共捐棄。", "願如合歡扇，薰風有時至。"]'),
('a9133ca3-7ab3-4cfc-bd29-e2241cbf74c6','入塞曲','周密','宋','宋诗','song-poetry','','[]','五年戍隴南，十年戍隴北。',72,'全唐诗/poet.song.236000.json','["五年戍隴南，十年戍隴北。", "夜雪度陰山，秋風入絕域。", "戰多寶刀缺，行苦馬蹄蝕。", "歸來見天子，功高無矜色。", "功是戰士功，德是明主德。", "小臣何所有，一心期靖國。"]'),
('cde3135e-f1b9-4c9c-a407-b946ec84feb1','首夏幽居','周密','宋','宋诗','song-poetry','','[]','一枕薰風一架書，幽居景物儘堪娛。',64,'全唐诗/poet.song.236000.json','["一枕薰風一架書，幽居景物儘堪娛。", "孤雲依石自舒卷，小雨釀梅時有無。", "粗識古今知得喪，細看草木驗榮枯。", "詩邊剩喜多生意，門外新塘長細蒲。"]'),
('3ba92f90-c894-4609-a269-f4bd0b5f5086','聞蛩','周密','宋','宋诗','song-poetry','','[]','莓苔經積雨，蟋蟀響庭陰。',48,'全唐诗/poet.song.236000.json','["莓苔經積雨，蟋蟀響庭陰。", "不特吟秋苦，長懷警世心。", "梭寒閨夢短，衣薄旅愁深。", "月冷霜清夜，閑人最賞音。"]'),
('8327e48b-e70d-4358-86bb-64dc19668baf','邂逅','周密','宋','宋诗','song-poetry','','[]','邂逅村翁語，停筇古柳邊。',48,'全唐诗/poet.song.236000.json','["邂逅村翁語，停筇古柳邊。", "相邀茅舍坐，自摘野茶煎。", "桑已抽三葉，蠶將及兩眠。", "綠蓑煙雨足，我欲賦歸田。"]'),
('6d810116-9f61-4245-9b1f-0aad79a55b13','秋日書懷寄儀父','周密','宋','宋诗','song-poetry','','[]','老盡窗前桂，三秋過二分。',48,'全唐诗/poet.song.236000.json','["老盡窗前桂，三秋過二分。", "蛩哀半庭月，雁冷一天雲。", "靜極通詩境，機疎遠世群。", "寫懷因有作，寄似鮑參軍。"]'),
('a920157f-2a89-406a-ab20-abb8137c3d21','春日書所見','周密','宋','宋诗','song-poetry','','[]','誰家翠袖倚朱樓，指畫欄干不舉頭。',32,'全唐诗/poet.song.236000.json','["誰家翠袖倚朱樓，指畫欄干不舉頭。", "蜂蝶入懷花撲面，可能全不解春愁。"]'),
('2a83cb77-9dbf-48a6-9ac5-7e498b5324f1','湘夫人畫卷','周密','宋','宋诗','song-poetry','','[]','一幅春冰寫九歌，就中愁絕是湘娥。',32,'全唐诗/poet.song.236000.json','["一幅春冰寫九歌，就中愁絕是湘娥。", "不知脩竹疎疎外，此去蒼梧路幾多。"]'),
('1ce8a7c1-908e-40bb-9541-35c1967bc943','春暮','周密','宋','宋诗','song-poetry','','[]','綠老蘭苕筍滿林，一簾輕夢晝愔愔。',32,'全唐诗/poet.song.236000.json','["綠老蘭苕筍滿林，一簾輕夢晝愔愔。", "東風已捲春歸去，空誤楊花擾亂尋。"]'),
('6fbfaded-0b06-4933-864e-718646742f50','偶題','周密','宋','宋诗','song-poetry','','[]','燒殘一篆香，睡起凭窗坐。',24,'全唐诗/poet.song.236000.json','["燒殘一篆香，睡起凭窗坐。", "靜中得新詩，研墨瓶花墮。"]'),
('1ba2f991-4e39-4546-aace-bc052f8cd42b','夜泊','周密','宋','宋诗','song-poetry','','[]','月沉江路黑，傍岸已三更。',24,'全唐诗/poet.song.236000.json','["月沉江路黑，傍岸已三更。", "知近人家宿，林西犬吠聲。"]'),
('a4968f1b-ca78-42e4-b7d0-740e90a5e1a9','伐木雜言','周密','宋','宋诗','song-poetry','','[]','庭前一雙桂，娟娟如幽人。',108,'全唐诗/poet.song.236000.json','["庭前一雙桂，娟娟如幽人。", "染我毛骨香，薰我夢寐清。", "惡木忽見妒，纍纍引繁藤。", "拘縶清風枝，不使舒芳陰。", "滋蔓日益多，惡木亦難任。", "引藤欲傷桂，豈期自傷身。", "侵晨戒僕夫，爲我持斧斤。", "論木妒桂罪，誅藤反噬心。", "嗚呼君子交，擇之貴在精。"]'),
('95894318-9503-48a0-bbbf-f813545686b3','寶山園即席次韻','周密','宋','宋诗','song-poetry','','[]','林巒藴秀玉生暉，左界樓臺近紫微。',64,'全唐诗/poet.song.236000.json','["林巒藴秀玉生暉，左界樓臺近紫微。", "畫裏江湖春浩蕩，騷中草木日芳菲。", "鶑遷錦樹香連屋，鶴唳青桐露濕衣。", "一段高寒無寫處，吟情閒逐片雲飛。"]'),
('71675260-bb39-4620-9473-813fe9570c45','次秋崖韻','周密','宋','宋诗','song-poetry','','[]','故山誰爲掃苔磯，頗喜閑門過客稀。',64,'全唐诗/poet.song.236000.json','["故山誰爲掃苔磯，頗喜閑門過客稀。", "許靖久貧惟馬磨，王章多病有牛衣。", "逢時不偶聊藏拙，漫仕無成欲賦歸。", "飲水飯蔬差省事，底須汲汲蹈危機。"]'),
('a84faa6e-c6e8-4c2a-af68-4d7dd649086a','避暑呂園','周密','宋','宋诗','song-poetry','','[]','我意不在酒，而在荷柳間。',48,'全唐诗/poet.song.236000.json','["我意不在酒，而在荷柳間。", "輕風行微波，高蟬答空山。", "邂逅同心人，共此一日閒。", "風乎詠歸歟，幽興殊未闌。"]'),
('575e1c63-414e-42cc-a976-46dbdcd5d45d','賦松山','周密','宋','宋诗','song-poetry','','[]','山中深結屋，山上併栽松。',48,'全唐诗/poet.song.236000.json','["山中深結屋，山上併栽松。", "自有冰霜意，全無塵土容。", "曉風香九里，夜月翠千峯。", "切勿汙秦爵，山林有素封。"]'),
('9bbc258f-37d8-4204-bf81-d95a239452e4','賦菊次吳竹窗韻','周密','宋','宋诗','song-poetry','','[]','西風入東籬，花事殊草草。',264,'全唐诗/poet.song.236000.json','["西風入東籬，花事殊草草。", "幽葩發孤叢，未覺芳意少。", "誰云九秋冷，孰謂三徑小。", "粲粲黄金英，采采不盈抱。", "幽深秀霜傑，不許蜂蝶到。", "正色知者誰，尚絅無外襮。", "寒香正宜晚，何事嘆秋杪。", "不逐雨餘荒，但覺霜後好。", "一見爽入脾，三嗅清徹腦。", "細參花中禪，可以入道奧。", "人生百年內，能幾花前笑。", "昌黎似未悟，頗恨生不早。", "豈無春風妍，羞與紅紫校。", "萬物各有待，此理須自了。", "不作時世粧，不顧流俗誚。", "居然處於獨，耿介類有道。", "信乎抱脩潔，終勝自炫耀。", "雖云得時晚，未肯隨秋老。", "呼童謹培溉，勿使蓬藋撓。", "泛之亦堪醉，餐之亦堪飽。", "莫賦湘纍吟，澤畔顔色槁。", "持似斜川翁，聞此當絕倒。"]'),
('8cf237a5-3448-4ca6-9c40-e4d032ed7918','元夕次松窗韻','周密','宋','宋诗','song-poetry','','[]','霽景浮燈市，春聲動樂章。',48,'全唐诗/poet.song.236000.json','["霽景浮燈市，春聲動樂章。", "翠簾流月影，黄道散天香。", "鼇蜃三山聳，魚龍陸地驤。", "醉餘天欲曙，歸路笛聲長。"]'),
('25e5d3be-df8a-41be-9cf8-6821e6e2a5c8','月下聞笙次趙元父韻','周密','宋','宋诗','song-poetry','','[]','碧桃花外聽緱笙，裊裊餘音度月明。',64,'全唐诗/poet.song.236000.json','["碧桃花外聽緱笙，裊裊餘音度月明。", "風靜囀春鶑出谷，夜深警露鶴傳更。", "十三簧冷參差影，廿四欄高縹緲聲。", "愁想嵩山歸未得，醉魂清絕夢難成。"]'),
('0ac5cb98-e239-4efb-bcb9-626b4eb482df','蓀壁惠白躑躅口占以謝','周密','宋','宋诗','song-poetry','','[]','何人種玉白雲邊，歲歲花開叫杜鵑。',32,'全唐诗/poet.song.236000.json','["何人種玉白雲邊，歲歲花開叫杜鵑。", "乞得東風一枝雪，等閑歸詫鶴林僊。"]'),
('336a01d6-5f2f-4c34-92d0-0a18074de07a','病中謝友人相問','周密','宋','宋诗','song-poetry','','[]','卧病殘春亦可嗟，蕭然一閤閉如蝸。',64,'全唐诗/poet.song.236000.json','["卧病殘春亦可嗟，蕭然一閤閉如蝸。", "尺鐺自課童煎藥，丈室應無女散花。", "患難時方知誼友，炎凉醫亦厭貧家。", "兼旬不踏門前徑，綠葉青陰漸可嘉。"]'),
('b12d650b-ad1c-450a-9ef3-e8ee43acbcdd','病起偶成','周密','宋','宋诗','song-poetry','','[]','負暄行藥小徜徉，困卧長安意自傷。',64,'全唐诗/poet.song.236000.json','["負暄行藥小徜徉，困卧長安意自傷。", "短髮怯梳霜柳脆，衰容銷鏡病梨黄。", "熊經龜息持新訣，馬勃牛溲試舊方。", "解祟送窮渾未驗，數奇應笑賈司倉。"]'),
('3991b49b-911b-4d0a-80fe-96d4bdef0b4a','送徐道士之剡六言二首  其一','周密','宋','宋诗','song-poetry','','[]','化鶴曾遊赤壁，籠鵝又過山陰。',28,'全唐诗/poet.song.236000.json','["化鶴曾遊赤壁，籠鵝又過山陰。", "带月片帆歸去，凌風一劍飛吟。"]'),
('2c9bda50-5b9f-429d-866e-522d405b173e','送徐道士之剡六言二首  其二','周密','宋','宋诗','song-poetry','','[]','倦踏長安落葉，閑尋剡曲扁舟。',28,'全唐诗/poet.song.236000.json','["倦踏長安落葉，閑尋剡曲扁舟。", "三十六灣清曉，不知何處逢秋。"]'),
('2159d435-0ccb-4a14-b2b2-f050476f70b5','小木天次曾昭陽韻','周密','宋','宋诗','song-poetry','','[]','弱水蓬萊路，人間隔幾千。',48,'全唐诗/poet.song.236000.json','["弱水蓬萊路，人間隔幾千。", "未知太倉令，何似道山仙。", "草木涵春露，池亭媚曉煙。", "靜參齊物意，小大豈其然。"]'),
('3e2e5c19-72e8-49f8-8eac-446145d4f46a','次張明叔韻','周密','宋','宋诗','song-poetry','','[]','祇今吾亦自忘吾，東里何人念葛綀。',64,'全唐诗/poet.song.236000.json','["祇今吾亦自忘吾，東里何人念葛綀。", "遁世每思盤谷隠，傳家惟有善和書。", "生平自喜一無愧，老去從嘲百不如。", "五畝桑麻三徑菊，潘郎真可賦閑居。"]'),
('5a484978-28e9-4921-b9d7-edd993000ad7','次竹窗見寄韻','周密','宋','宋诗','song-poetry','','[]','季鷹次第賦歸來，底用蓴鱸苦苦催。',64,'全唐诗/poet.song.237000.json','["季鷹次第賦歸來，底用蓴鱸苦苦催。", "顧我已如無用木，從人自笑不然灰。", "江湖空有憂時歎，朝野應多濟世才。", "不信子牟存闕意，可能全付與銜盃。"]'),
('684dcf1c-40bb-4907-9cc6-11af4376c76f','秋望','周密','宋','宋诗','song-poetry','','[]','赤日黄塵嘆倦游，長謠曾賦四宜休。',32,'全唐诗/poet.song.237000.json','["赤日黄塵嘆倦游，長謠曾賦四宜休。", "酸風小雨層梯外，半是愁痕半是秋。"]'),
('f54c9c28-c5fd-4d72-944a-00eab2a5532b','有約','周密','宋','宋诗','song-poetry','','[]','有約携樽去，同登百尺樓。',48,'全唐诗/poet.song.237000.json','["有約携樽去，同登百尺樓。", "便須乘好月，何必待中秋。", "天地能容醉，山川不貯愁。", "悠悠身世事，已付一虛舟。"]'),
('fb8e1790-ac62-4cb9-a7d1-d177acc1c011','寄牟德範九江幕府','周密','宋','宋诗','song-poetry','','[]','懷人渺渺隔風濤，湓浦爐峰夢寐勞。',64,'全唐诗/poet.song.237000.json','["懷人渺渺隔風濤，湓浦爐峰夢寐勞。", "雄堞拂雲屯萬竈，空江鎖月宿千艘。", "臨流擊楫賓朋盛，草檄飛書筆墨豪。", "楓葉荻花秋正好，琵琶休聽鬰輪袍。"]'),
('d4ad1b78-6b5a-40ad-9cb1-b286eeabf28e','苦雨','周密','宋','宋诗','song-poetry','','[]','閉門吟苦雨，誰識子桑愁。',48,'全唐诗/poet.song.237000.json','["閉門吟苦雨，誰識子桑愁。", "石破杞天漏，瓢翻后土浮。", "捲茅驚客夢，卹緯動嫠憂。", "自此開新霽，猶堪望有秋。"]'),
('fcd814dc-84d8-4362-bf80-b8fae0c864f7','甲戌七月二十七夜大雷雨有感','周密','宋','宋诗','song-poetry','','[]','驕陽煽餘威，熱惱若昏醉。',240,'全唐诗/poet.song.237000.json','["驕陽煽餘威，熱惱若昏醉。", "邀凉卧虛櫺，頓覺景象異。", "乾坤若黟漆，相對不相視。", "雷車與電鏡，雲族撐贔屭。", "如發馬陵伏，萬弩一時至。", "如河决宣房，澎湃石崩墜。", "又如入蔡州，鵝鶩雜兵騎。", "轟騰立四海，熛怒翻九地。", "兒啼抱頭竄，婢噤移足躓。", "鳥獸相號呼，雞犬競趨避。", "隠床夜九遷，穿瓦雨如釃。", "屋老欲摧壓，危慄心惴惴。", "敬此天動威，起坐不敢寐。", "哀哉昔吾親，多病易驚悸。", "每於風雨交，擁護不少置。", "九京聞不聞，生死同一致。", "不能抱冢泣，不孝天所棄。", "漫游遠墳墓，榮親願難遂。", "作誓守松楸，或可酬此志。", "白雲起瀧岡，西望揮血淚。"]'),
('35e2a87c-9fd6-45c7-a8dd-ef2a99807eae','登北高峰','周密','宋','宋诗','song-poetry','','[]','山巔復山巔，樹杪復樹杪。',72,'全唐诗/poet.song.237000.json','["山巔復山巔，樹杪復樹杪。", "白雲已摩肩，青意猶未了。", "積蘇笑壤鼠，决眥極飛鳥。", "吳濤與越樹，滅沒窺縹緲。", "洪荒本無界，所恨見者小。", "九萬逍遥遊，語大未易少。"]'),
('a0cc7122-bc45-4981-a844-800eb9e9b266','攬秀臺觀月','周密','宋','宋诗','song-poetry','','[]','吟到危梯最上層，天空星斗入杯明。',64,'全唐诗/poet.song.237000.json','["吟到危梯最上層，天空星斗入杯明。", "遊心寥廓生虛白，與世周旋忌獨清。", "冰雪四山皆月色，宮商一片是秋聲。", "廣寒今夕知何夕，欲駕銀橋上玉京。"]'),
('6c069852-8619-4eef-b0cc-31c4e74f5647','與陳君衡別','周密','宋','宋诗','song-poetry','','[]','君歸春亦去，心賞易蹉跎。',48,'全唐诗/poet.song.237000.json','["君歸春亦去，心賞易蹉跎。", "烟柳綠如此，霜髭白柰何。", "別來空作惡，醉後且高歌。", "莫把詩銷恨，詩成恨更多。"]'),
('0238c608-7cb7-4f7f-a6e9-fdf9b13617a6','甲戌八月武康安吉水禍甚慘人畜田廬漂沒殆盡賦苦雨行以紀一時之實','周密','宋','宋诗','song-poetry','','[]','雷車推翻電車折，龍鬣勞勞滴清血。',256,'全唐诗/poet.song.237000.json','["雷車推翻電車折，龍鬣勞勞滴清血。", "羲和愁抱赤烏眠，陽侯怒蹴秋潢裂。", "風寒田火夜不明，桔槔椎鼓聲彭彭。", "家家捄田如捄死，處處防隴如防城。", "丁男凍餒弱女泣，今歲催苗如火急。", "一家命寄一田中，何敢辭勞歎霑濕。", "四山湓湧地軸浮，潮聲半夜移桃州。", "千家井邑類飄葉，啾啾赤子生魚頭。", "大田積沙高數尺，南陌東阡了難識。", "死者沉湘魂莫招，生者無家歸不得。", "呼天不聞地不知，縣官不卹將告誰。", "與其饑死在溝壑，不若漂死隨蛟螭。", "何人發廩講荒政，牋天急捄生民命。", "拯溺誰無孟氏心，裹飯空憐子桑病。", "恭惟在位皆聖賢，等閑鍊石能補天。", "轉移風俗在俄頃，不歌苦雨歌豐年。"]'),
('ae7a9e24-2f04-48ec-ae85-9d8d3e80b4e7','小木天晚倚','周密','宋','宋诗','song-poetry','','[]','吟情偏向靜中生，桂影吹凉似水清。',32,'全唐诗/poet.song.237000.json','["吟情偏向靜中生，桂影吹凉似水清。", "十日雨晴秋便老，一蛩猶戀豆根鳴。"]'),
('a4d79ea8-cc20-4914-b2cb-47e252035343','次魏川聯句韵','周密','宋','宋诗','song-poetry','','[]','丹砂何日化黄金，衣上秋塵積漸深。',64,'全唐诗/poet.song.237000.json','["丹砂何日化黄金，衣上秋塵積漸深。", "生意無邊觀草色，春風有約到梅心。", "白頭自感華年瑟，俗耳誰聽太古琴。", "聯句定知思孟簡，谿邊因寄采蘋吟。"]'),
('0deb5fa4-5251-47db-a214-6a7cff838392','吟社飲桂月邊即席次韵','周密','宋','宋诗','song-poetry','','[]','白頭强逐少年遊，閑倚西風十二樓。',64,'全唐诗/poet.song.237000.json','["白頭强逐少年遊，閑倚西風十二樓。", "共醉玉壺千古月，平分香國一天秋。", "祇應李白憐吾意，不信姮娥識此愁。", "夜久高寒猶露飲，花陰傳漏已三籌。"]'),
('9bb82579-e4cf-47ce-88e2-c9108e2a075b','醉後放歌','周密','宋','宋诗','song-poetry','','[]','冷風如冰月如水，夜久霜寒倚秋桂。',224,'全唐诗/poet.song.237000.json','["冷風如冰月如水，夜久霜寒倚秋桂。", "酒樽已眠人未睡，閑與孤蛩各言志。", "宇宙寬閑容我輩，千古萬古同一致。", "天上人間好惡異，君子小人常倒置。", "不願建侯遊萬里，金印紅旗擁千騎。", "不願聞雞五更起，衮繡傳呼趨九陛。", "惟願擘畫千百歲，坐見無懷大庭氏。", "不須結繩與畫地，何者爲愚何者智。", "不蠶而衣不耕刈，不暑不寒春洩洩。", "有酒如江碧浮蟻，一瓢日日江頭醉。", "醉後長歌語流麗，歌聲透天天爲喜。", "賜我三元九霞珮，佩之乘風御清氣。", "虎豹遁迹鬼神避，意之所之身即至。", "竦身蜚出扶摇外，直到天宮三十二。"]'),
('3983a7ed-c544-4d59-aa2c-bfaab50c419f','甲戌七月','周密','宋','宋诗','song-poetry','','[]','未撤關河戍，邊聲動塞鴻。',48,'全唐诗/poet.song.237000.json','["未撤關河戍，邊聲動塞鴻。", "憂時方卹緯，聞詔忽號弓。", "兩鬢三秋雪，千林一夜風。", "寸心猶未改，何敢嘆途窮。"]'),
('3c231425-3d5a-474e-9ef2-33a0b72398d3','南園','周密','宋','宋诗','song-poetry','','[]','清芬堂下千株桂，猶是韓家舊賜園。',32,'全唐诗/poet.song.237000.json','["清芬堂下千株桂，猶是韓家舊賜園。", "白髮老翁和淚說，百年中見兩平原。"]'),
('54554d65-88b8-495c-9051-51cb5b3615f6','甘園','周密','宋','宋诗','song-poetry','','[]','小小蓬萊在水中，乾淳舊賞有遺蹤。',32,'全唐诗/poet.song.237000.json','["小小蓬萊在水中，乾淳舊賞有遺蹤。", "園林幾換東風主，留得庭前御愛松。"]'),
('84719673-f96e-4b91-8cba-23f7a55b136e','褒親崇壽寺','周密','宋','宋诗','song-poetry','','[]','鶴羽鸞綃事已空，奉華遺寺對高松。',32,'全唐诗/poet.song.237000.json','["鶴羽鸞綃事已空，奉華遺寺對高松。", "宮斜鳳去無人見，且看門前粉壁龍。"]'),
('8507b059-2ca7-4a87-b43d-884eb683cadf','西太一宮','周密','宋','宋诗','song-poetry','','[]','蕊宮廣殿號黄庭，突兀浮雲最上層。',32,'全唐诗/poet.song.237000.json','["蕊宮廣殿號黄庭，突兀浮雲最上層。", "五福貴神留不住，水堂空照九枝燈。"]'),
('2f28371c-2fef-468e-994f-ad343dcfeb97','南園香山','周密','宋','宋诗','song-poetry','','[]','舊事淒涼尚可尋，斷碑閑卧草深深。',32,'全唐诗/poet.song.237000.json','["舊事淒涼尚可尋，斷碑閑卧草深深。", "凌風閣下槎牙樹，當日人疑是水沈。"]'),
('399f257d-00f4-48d1-912e-7596cf1e569e','爲楊大芳悼亡','周密','宋','宋诗','song-poetry','','[]','帳中蝶化真成夢，鏡裏鸞孤枉斷腸。',32,'全唐诗/poet.song.237000.json','["帳中蝶化真成夢，鏡裏鸞孤枉斷腸。", "吹徹玉簫人不見，世間難覓返魂香。"]'),
('2328749d-9588-478c-9954-6970cc884579','蠟梅','周密','宋','宋诗','song-poetry','','[]','蠟本花所作，作花應更香。',48,'全唐诗/poet.song.237000.json','["蠟本花所作，作花應更香。", "月參無味禪，不作有色妝。", "未知香山白，何似江夏黄。", "坐令彼粲者，難擅春風場。"]'),
('0ce2d3fe-f525-4b13-ac87-343c94713b87','寄括蒼山人','周密','宋','宋诗','song-poetry','','[]','遥知深隠處，草木亦無塵。',48,'全唐诗/poet.song.237000.json','["遥知深隠處，草木亦無塵。", "瀑響千林雨，花浮一嶺春。", "地靈松化石，歲久樹成人。", "縱未爲仙去，何妨作逸民。"]'),
('3a30e992-7526-4e15-ba93-4d199c9d72e3','水村','周密','宋','宋诗','song-poetry','','[]','紫鷄白鳳滿秋畦，血色蜻蜓上客衣。',32,'全唐诗/poet.song.237000.json','["紫鷄白鳳滿秋畦，血色蜻蜓上客衣。", "野水近門籬落晚，擺頭蘆葦有船歸。"]'),
('ea435884-5981-4752-ad24-235fd3be319c','題高房山夜山圖爲江浙行省照磨李公略作','周密','宋','宋诗','song-poetry','','[]','郎潛暇日多冥搜，夜深獨上千尺樓。',160,'全唐诗/poet.song.237000.json','["郎潛暇日多冥搜，夜深獨上千尺樓。", "天回海立月正濕，風起雲涌山疑浮。", "縈青繚白互變滅，浮嵐飛霧寒颼颼。", "潛虯棲鶻聲磔磔，山鬼木客鳴呦呦。", "城中癡兒方囈語，有夢不到千山幽。", "遥岑寸碧目力遠，欲遡汗漫凌風游。", "高侯落筆萬象泣，寫出千古蒼茫愁。", "無聲詩與有聲畫，一夕異事傳南州。", "玉琴在膝酒在手，欲寫天籟無莊周。", "憑誰爲問華表鶴，城郭人民今是不。"]'),
('4a3c53cb-fc60-4fd9-a42c-86eca20f1c37','題高彥敬山村圖卷','周密','宋','宋诗','song-poetry','','[]','我昔遊七閩，百嶺爭𡽱嶪。',144,'全唐诗/poet.song.237000.json','["我昔遊七閩，百嶺爭𡽱嶪。", "白雲漲川原，深谷如積雪。", "又游天姥岑，幽磴緣曲折。", "長林翳寒日，十里行落葉。", "轉頭五十年，遐想正愁絕。", "開圖意忽動，戃怳生內熱。", "何當駕松广，分我翠一疊。", "弁陽我所廬，見謂山水窟。", "漂零媿楸檟，歲月老薇蕨。", "平生阮遥集，足痹屐齒折。", "何當賦歸田，初志遂所愜。", "懷哉復懷哉，清夢繞林樾。"]'),
('d6457ed0-77c6-4016-af19-f5592e61f74e','題溫日觀葡萄','周密','宋','宋诗','song-poetry','','[]','百八牟尼顆，携將萬里游。',24,'全唐诗/poet.song.237000.json','["百八牟尼顆，携將萬里游。", "歸來還自笑，何不博凉州。"]'),
('99112729-51fc-448d-b791-f98b2b94d405','古墓','周密','宋','宋诗','song-poetry','','[]','碑斷苔荒土半穿，老狐號冷穴空垣。',32,'全唐诗/poet.song.237000.json','["碑斷苔荒土半穿，老狐號冷穴空垣。", "珠襦玉碗誰携去，翁仲相看不敢言。"]'),
('2e9ed5a1-9e20-4043-90d4-1d06ac9e5449','雜詩','周密','宋','宋诗','song-poetry','','[]','萬類更變化，造物無時閑。',84,'全唐诗/poet.song.237000.json','["萬類更變化，造物無時閑。", "人生天地中，長短百年間。", "未知百年後，奄忽何時還。", "辛苦立修名，留用後世看。", "後世既無我，於我何所關。", "有如夢中游，夢覺無餘懽。", "天理正如此，一笑付達觀。"]'),
('084023b3-e358-4284-979a-04c3204f3203','跋晉王大令保母帖','周密','宋','宋诗','song-poetry','','[]','王郎擅風流，筆墨美無度。',156,'全唐诗/poet.song.237000.json','["王郎擅風流，筆墨美無度。", "殘磚與斷刻，亦有神物護。", "埋光八百載，復出疑有數。", "偉哉羲獻蹟，併見山陰路。", "抗衡丙舍帖，突過黄初賦。", "景師與陽朔，漶漫不足數。", "要須中山石，乃可與之伍。", "十行百餘字，一一生媚嫵。", "家雞與野鶩，此論吾不取。", "佳處將無同，閟妙未易語。", "我貧乃嗜此，字字若可煮。", "不知何物媼，托此傳萬古。", "却怪玉匣書，反累昭陵土。"]'),
('d829dbff-a17f-4d73-8568-40c31f8fa1f1','送西秦張仲實游大滌洞天','周密','宋','宋诗','song-poetry','','[]','玉室金堂積翠邊，舊游猶記劫灰前。',64,'全唐诗/poet.song.237000.json','["玉室金堂積翠邊，舊游猶記劫灰前。", "禽聲夜擣千年藥，花片春浮九鎖泉。", "洞府暗通滄海路，樓居何異化城仙。", "茶香筍美松醪熟，正好山中過禁烟。"]'),
('0cae2b20-33cd-4cb1-8f57-303d82a18294','句  其一','周密','宋','宋诗','song-poetry','','[]','秦邸獄成杯酒裏，烏臺禍起一詩間。',29,'全唐诗/poet.song.237000.json','["秦邸獄成杯酒裏，烏臺禍起一詩間。", "《癸辛雜識》續集卷上ff。"]'),
('4bcddcfe-e9b9-40bf-a2a0-51045d92ef43','句  其二','周密','宋','宋诗','song-poetry','','[]','山林綠髮秦宮女，風雨青萍禹廟梁。',16,'全唐诗/poet.song.237000.json','["山林綠髮秦宮女，風雨青萍禹廟梁。"]'),
('c4a0cf75-d053-4a39-8f00-846927ae8874','句  其三','周密','宋','宋诗','song-poetry','','[]','繁華不結三春夢，零落空餘寸草心。',16,'全唐诗/poet.song.237000.json','["繁華不結三春夢，零落空餘寸草心。"]'),
('43e1113b-2814-4121-aec9-bbc2015253a8','存目','周密','宋','宋诗','song-poetry','','[]','詩題：流寓雜詩五首首句：',52,'全唐诗/poet.song.237000.json','["詩題：流寓雜詩五首首句：", "甲第紛紛起畫樓。", "霸氣遥加萬乘君。", "長淮千里陣雲平。", "偃月高堂矗紫烟。", "城門壘合勢如山。"]'),
('58cee442-ba19-4ba2-ad27-7ce3fd68aa21','北山之高壽北山何先生  其一','金履詳','宋','宋诗','song-poetry','','[]','北山之高，表我東底。',40,'全唐诗/poet.song.237000.json','["北山之高，表我東底。", "惟山降神，生何夫子。", "維何夫子，文公是祖。", "是師黄父，以振我緒。"]'),
('e0835126-ef8d-45a8-b86c-89cd385491ed','北山之高壽北山何先生  其二','金履詳','宋','宋诗','song-poetry','','[]','翼翼夫子，令德在躬。',40,'全唐诗/poet.song.237000.json','["翼翼夫子，令德在躬。", "道廣心平，不外以衷。", "北山之陽，盤溪之將。", "以處以安，不驕不亢。"]'),
('5d7771a6-3198-4df3-ab06-59f44a741d1c','北山之高壽北山何先生  其三','金履詳','宋','宋诗','song-poetry','','[]','昔在理宗，維道之崇。',40,'全唐诗/poet.song.237000.json','["昔在理宗，維道之崇。", "既表程朱，亦躋吕張。", "謂爾夫子，纉程朱緒。", "卿士率連，百辟咸譽。"]'),
('8eeca10e-f190-461a-9fc8-4ed03a2f5951','北山之高壽北山何先生  其四','金履詳','宋','宋诗','song-poetry','','[]','咨爾夫子，設敎於鄉。',20,'全唐诗/poet.song.237000.json','["咨爾夫子，設敎於鄉。", "即命於家，長此泮宫。"]'),
('1beceef2-848e-4432-ab5c-a0652d11eed5','北山之高壽北山何先生  其五','金履詳','宋','宋诗','song-poetry','','[]','夫子曰辭，辭是好爵。',20,'全唐诗/poet.song.237000.json','["夫子曰辭，辭是好爵。", "玉几導揚，燕翼是託。"]'),
('ba2a70f1-6491-4f0c-8fb5-d5beef85be1f','北山之高壽北山何先生  其六','金履詳','宋','宋诗','song-poetry','','[]','明明天子，丕承皇考。',45,'全唐诗/poet.song.237000.json','["明明天子，丕承皇考。", "曰求多聞，曰咨有道。", "天子曰都。", "咨爾夫子，爲世宗儒。", "来游来歌，東觀石渠。"]'),
('43e47799-ca4b-4040-bd02-f425d7c2f9a0','北山之高壽北山何先生  其七','金履詳','宋','宋诗','song-poetry','','[]','夫子曰止，臣非索隠。',45,'全唐诗/poet.song.237000.json','["夫子曰止，臣非索隠。", "士各有志，亦既耄只。", "天子曰猷。", "咨爾夫子，汝予交修。", "講殿維帷，爾優爾游。"]'),
('62d6739b-f3a4-49d8-8a65-08a168a438e6','北山之高壽北山何先生  其八','金履詳','宋','宋诗','song-poetry','','[]','夫子曰道，惟帝之蹈。',45,'全唐诗/poet.song.237000.json','["夫子曰道，惟帝之蹈。", "臣何容力，亦聿既耄。", "天子曰吁。", "鴻飛冥冥，罔終棄予。", "廩于宫祠，寓我渠渠。"]'),
('37a01720-28c2-4aa6-aa2b-e4d1eb1e1ac5','北山之高壽北山何先生  其九','金履詳','宋','宋诗','song-poetry','','[]','夫子由由，匪詭匪隨。',40,'全唐诗/poet.song.237000.json','["夫子由由，匪詭匪隨。", "匪傲匪求，云受奚爲。", "孑孑干旌，侯伯是將。", "鳯皇于飛，亦集爰止。"]'),
('f33efadc-ca07-4420-a012-d0b46f1c39da','北山之高壽北山何先生  其一○','金履詳','宋','宋诗','song-poetry','','[]','北山之陽，優優夷夷。',40,'全唐诗/poet.song.237000.json','["北山之陽，優優夷夷。", "盤溪之流，可以樂饑。", "明明天子，肇彼四海。", "樂學師賢，有永無怠。"]'),
('a1d1e9ad-2083-4e55-a04c-994954a15d69','北山之高壽北山何先生  其一一','金履詳','宋','宋诗','song-poetry','','[]','巖巖北山，其高極天。',60,'全唐诗/poet.song.237000.json','["巖巖北山，其高極天。", "障此東南，利欲之瀾。", "敢拜稽首，天子萬年。", "充保四海，好德之端。", "敢拜夫子，眉壽無愆。", "金玉爾音，以永斯文。"]'),
('0d011fa7-bd32-480f-99a7-724c5161e4eb','華之高壽魯齋先生七十  其一','金履詳','宋','宋诗','song-poetry','','[]','金華之高，其色蒼蒼。',20,'全唐诗/poet.song.237000.json','["金華之高，其色蒼蒼。", "維華降神，生何及王。"]'),
('5ed2df19-b76b-4414-9364-ae01db3ac521','華之高壽魯齋先生七十  其二','金履詳','宋','宋诗','song-poetry','','[]','維王及何，文公孫子。',20,'全唐诗/poet.song.237000.json','["維王及何，文公孫子。", "天子是師，斯文之紀。"]'),
('00b684aa-5299-4445-aa7b-089af66bd8e0','華之高壽魯齋先生七十  其三','金履詳','宋','宋诗','song-poetry','','[]','翼翼王子，教行於東。',20,'全唐诗/poet.song.237000.json','["翼翼王子，教行於東。", "思樂東州，舞雩之風。"]'),
('30e09537-827e-489f-a6bb-90e6072998ea','華之高壽魯齋先生七十  其四','金履詳','宋','宋诗','song-poetry','','[]','東人之子，其来秩秩。',20,'全唐诗/poet.song.237000.json','["東人之子，其来秩秩。", "是追是琢，是進是服。"]'),
('db95d764-5a10-4ace-86fa-52e3b8880fff','華之高壽魯齋先生七十  其五','金履詳','宋','宋诗','song-poetry','','[]','有車班班，有来自東。',20,'全唐诗/poet.song.237000.json','["有車班班，有来自東。", "子曰予耄，落此新宫。"]'),
('52fb5213-0ac6-4b28-9d08-8ce349dc69aa','華之高壽魯齋先生七十  其六','金履詳','宋','宋诗','song-poetry','','[]','新宫巖巖，佩玉翩翩。',20,'全唐诗/poet.song.237000.json','["新宫巖巖，佩玉翩翩。", "毋曰予耄，而將閉闗。"]'),
('f5c7da4e-487f-4791-be9b-2867c50a361c','華之高壽魯齋先生七十  其七','金履詳','宋','宋诗','song-poetry','','[]','自古在昔，聖賢有作。',20,'全唐诗/poet.song.237000.json','["自古在昔，聖賢有作。", "七十之齡，德烈方恪。"]'),
('d12be4cb-8ed8-4c86-8354-ea1a88573b0e','華之高壽魯齋先生七十  其八','金履詳','宋','宋诗','song-poetry','','[]','于時阿衡，一德之書。',20,'全唐诗/poet.song.237000.json','["于時阿衡，一德之書。", "于時尚父，猶蟠之居。"]'),
('b0b18131-87e3-491a-9ae4-3e77e9031382','華之高壽魯齋先生七十  其九','金履詳','宋','宋诗','song-poetry','','[]','于時宣尼，從心不踰。',20,'全唐诗/poet.song.237000.json','["于時宣尼，從心不踰。", "六籍是正，三千其徒。"]'),
('9eda899d-29f8-4b45-8c70-c4e8cf52d777','華之高壽魯齋先生七十  其一○','金履詳','宋','宋诗','song-poetry','','[]','百里何爲，亦顯其君。',20,'全唐诗/poet.song.237000.json','["百里何爲，亦顯其君。", "武公九十，懿戒維新。"]'),
('8f1b1ad3-5c55-4aa3-9bd4-893f86051109','華之高壽魯齋先生七十  其一一','金履詳','宋','宋诗','song-poetry','','[]','屹屹王子，三壽作朋。',20,'全唐诗/poet.song.237000.json','["屹屹王子，三壽作朋。", "視彼霸侯，曾是足論。"]'),
('668616c6-347f-45f1-b22e-9dc98f8a2061','華之高壽魯齋先生七十  其一二','金履詳','宋','宋诗','song-poetry','','[]','嵬嵬王子，我人所宗。',20,'全唐诗/poet.song.237000.json','["嵬嵬王子，我人所宗。", "維北有斗，維岱在東。"]'),
('c97a685f-5492-4d4d-bfc4-e0d0bc40db3d','華之高壽魯齋先生七十  其一三','金履詳','宋','宋诗','song-poetry','','[]','亹亹王子，毋遏来學。',20,'全唐诗/poet.song.237000.json','["亹亹王子，毋遏来學。", "是潔是進，亦審亦度。"]'),
('36c85399-211d-4d60-9269-f3f8fc15ae19','華之高壽魯齋先生七十  其一四','金履詳','宋','宋诗','song-poetry','','[]','毋信其言，省其退私。',20,'全唐诗/poet.song.237000.json','["毋信其言，省其退私。", "毋晦其明，而左右咨。"]'),
('ca437a7a-99d9-4fb7-aafd-cc143d4bd4ac','華之高壽魯齋先生七十  其一五','金履詳','宋','宋诗','song-poetry','','[]','明明天子，宅此四國。',20,'全唐诗/poet.song.237000.json','["明明天子，宅此四國。", "寤寐幽人，旌旄幣帛。"]'),
('3589636d-ad9e-4361-9128-966079b9b6c9','華之高壽魯齋先生七十  其一六','金履詳','宋','宋诗','song-poetry','','[]','北山之陽，其及王子。',20,'全唐诗/poet.song.237000.json','["北山之陽，其及王子。", "毋然遁思，孤我帝祉。"]'),
('85612e3e-b0fb-4a4e-a583-5817af700ad5','華之高壽魯齋先生七十  其一七','金履詳','宋','宋诗','song-poetry','','[]','帝心孔翼，帝民孔棘。',20,'全唐诗/poet.song.237000.json','["帝心孔翼，帝民孔棘。", "盍濬其源，而沛其澤。"]'),
('56da61f1-ff5f-4a14-949c-db6d31078f7f','華之高壽魯齋先生七十  其一八','金履詳','宋','宋诗','song-poetry','','[]','穆穆王子，毋靳爾猷。',20,'全唐诗/poet.song.237000.json','["穆穆王子，毋靳爾猷。", "以永斯文，邦家之休。"]'),
('768890dd-438d-496c-8787-7c9ae2466086','華之高壽魯齋先生七十  其一九','金履詳','宋','宋诗','song-poetry','','[]','吉甫作頌，其詩孔陋。',20,'全唐诗/poet.song.237000.json','["吉甫作頌，其詩孔陋。", "相彼兕觥，以介眉壽。"]'),
