('43635f61-f293-45bb-9666-9999171ecae0','鄭北山之元孫扁其樓王適莊爲書北山之英四字求跋爲作詩  其二','金履詳','宋','宋诗','song-poetry','','[]','誕此鄭公，維國之器。',20,'全唐诗/poet.song.237000.json','["誕此鄭公，維國之器。", "有偉其才，有奇其氣。"]'),
('428eddba-8e33-4886-a386-d251bd42174c','鄭北山之元孫扁其樓王適莊爲書北山之英四字求跋爲作詩  其三','金履詳','宋','宋诗','song-poetry','','[]','不屑以潔，不震以强。',20,'全唐诗/poet.song.237000.json','["不屑以潔，不震以强。", "權不離義，鍜不柔剛。"]'),
('838c413d-9d01-43fe-a910-008f2ce2078a','鄭北山之元孫扁其樓王適莊爲書北山之英四字求跋爲作詩  其四','金履詳','宋','宋诗','song-poetry','','[]','戎始歸疆，人喜公慮。',20,'全唐诗/poet.song.237000.json','["戎始歸疆，人喜公慮。", "謂戎未覺，亟固我圉。"]'),
('b4aec385-d89d-4f2e-b29a-b209d789732d','鄭北山之元孫扁其樓王適莊爲書北山之英四字求跋爲作詩  其五','金履詳','宋','宋诗','song-poetry','','[]','既藩既宣，左秦右川。',20,'全唐诗/poet.song.237000.json','["既藩既宣，左秦右川。", "北仇方睦，西戎獨嚴。"]'),
('3e72a03e-80fb-49b6-be7b-106c938bd6d1','鄭北山之元孫扁其樓王適莊爲書北山之英四字求跋爲作詩  其六','金履詳','宋','宋诗','song-poetry','','[]','壯兹逺猷，卓兹偉志。',20,'全唐诗/poet.song.237000.json','["壯兹逺猷，卓兹偉志。", "一時之英，而不大試。"]'),
('ae2bc40f-4d41-41d5-899d-cafd81771267','鄭北山之元孫扁其樓王適莊爲書北山之英四字求跋爲作詩  其七','金履詳','宋','宋诗','song-poetry','','[]','高牙大纛，虎節銅符。',20,'全唐诗/poet.song.237000.json','["高牙大纛，虎節銅符。", "東將寛民，乃公所餘。"]'),
('a48d6c98-161b-4341-93b9-29e1241bd031','鄭北山之元孫扁其樓王適莊爲書北山之英四字求跋爲作詩  其八','金履詳','宋','宋诗','song-poetry','','[]','相維權奸，公以才忌。',20,'全唐诗/poet.song.237000.json','["相維權奸，公以才忌。", "瀕死荒陲，非公所悸。"]'),
('97744f8d-d281-4094-825b-8f010076c7fe','鄭北山之元孫扁其樓王適莊爲書北山之英四字求跋爲作詩  其九','金履詳','宋','宋诗','song-poetry','','[]','孰是叔季，而有斯人。',20,'全唐诗/poet.song.237000.json','["孰是叔季，而有斯人。", "孰是北山，而落其英。"]'),
('9383ec32-37d9-4ab8-a438-1715db8bd1d9','鄭北山之元孫扁其樓王適莊爲書北山之英四字求跋爲作詩  其一○','金履詳','宋','宋诗','song-poetry','','[]','嗟我思公，去之百歲。',20,'全唐诗/poet.song.237000.json','["嗟我思公，去之百歲。", "思莫見之，見其後裔。"]'),
('bf1950fe-cdb5-47c1-a03e-ca9cd83ec333','鄭北山之元孫扁其樓王適莊爲書北山之英四字求跋爲作詩  其一一','金履詳','宋','宋诗','song-poetry','','[]','維公之英，育多聞孫。',20,'全唐诗/poet.song.237000.json','["維公之英，育多聞孫。", "尚繼其志，而世其聲。"]'),
('4e2110d7-02dd-40a0-aa2f-4a14a7941b61','鄭北山之元孫扁其樓王適莊爲書北山之英四字求跋爲作詩  其一二','金履詳','宋','宋诗','song-poetry','','[]','亦有適莊，景爾家世。',20,'全唐诗/poet.song.237000.json','["亦有適莊，景爾家世。", "北山之英，表此大字。"]'),
('65781b28-2629-46d9-93c6-14c58c5a7aa2','鄭北山之元孫扁其樓王適莊爲書北山之英四字求跋爲作詩  其一三','金履詳','宋','宋诗','song-poetry','','[]','北山之英，鄭公之人。',20,'全唐诗/poet.song.237000.json','["北山之英，鄭公之人。", "仰止攸同，矧其後昆。"]'),
('081274e3-d9a4-4a0c-bf1e-c706a53f7444','鄭北山之元孫扁其樓王適莊爲書北山之英四字求跋爲作詩  其一四','金履詳','宋','宋诗','song-poetry','','[]','吉甫作頌，勉爾聞孫。',20,'全唐诗/poet.song.237000.json','["吉甫作頌，勉爾聞孫。", "鄭公是似，北山之英。"]'),
('0a0ea857-8894-4b38-b4f4-7b8830756e05','送金簿解官歸天台五首  其一','金履詳','宋','宋诗','song-poetry','','[]','崑崙派南條，東走欲無極。',72,'全唐诗/poet.song.237000.json','["崑崙派南條，東走欲無極。", "海氣薄回巒，清淑轉鬱積。", "嵬嵬天台山，東表千萬尺。", "其上有仙靈，其下有英特。", "伊人天一方，從往恨未即。", "渺渺隔蒼山，跂予三嘆息。"]'),
('a3fe20f6-dd6c-4e46-8d4b-8029b13d9bcc','送金簿解官歸天台五首  其二','金履詳','宋','宋诗','song-poetry','','[]','昔歲在東壁，紫氣踰蒼山。',120,'全唐诗/poet.song.237000.json','["昔歲在東壁，紫氣踰蒼山。", "金君初筮晉，趙侯亦開藩。", "下有蓮幕友，上有師帥賢。", "渾然和氣中，砥柱屹流湍。", "使我千里民，賦政兩清安。", "益知天台高，楚波浩無邊。", "一朝别流泳，先後俱東轅。", "邦民一何孤，天意一何慳。", "舟流安底止，郡政將改弦。", "嗟我千里民，生意復茫然。"]'),
('693e21eb-1f86-4fda-a641-da72ff9929cf','送金簿解官歸天台五首  其三','金履詳','宋','宋诗','song-poetry','','[]','自從夫君来，劍氣躔須女。',60,'全唐诗/poet.song.237000.json','["自從夫君来，劍氣躔須女。", "遊刃肯綮間，淬鋒滄浪浦。", "直氣浩難容，才名世所妬。", "枳棘豈棲鸞，百里非賢路。", "善刀謹自藏，大烹鼎可負。"]'),
('e9a1afc9-a33d-42d6-a9df-7bdb83f28839','送金簿解官歸天台五首  其四','金履詳','宋','宋诗','song-poetry','','[]','自從夫君来，二惠亦驂乘。',144,'全唐诗/poet.song.237000.json','["自從夫君来，二惠亦驂乘。", "天台本多賢，君門獨何盛。", "大兒十四齡，神氣極凝瑩。", "温然荆山璆，可續虞磬韻。", "小兒年十一，磊朗益自俊。", "壯氣已食牛，風蹄期奮迅。", "兩載辱交從，一朝随歸𩍐。", "相見復何時，相别涕其隕。", "美質不可恃，學問無窮盡。", "少小日易逾，德業須自竟。", "執手獨徊徨，愧無珠玉贈。", "歸哉各努力，教忠家有訓。"]'),
('bb32cae5-f3b7-41dd-bd06-356c9f28d252','送金簿解官歸天台五首  其五','金履詳','宋','宋诗','song-poetry','','[]','白雲蒼山東，歸驂邁長道。',72,'全唐诗/poet.song.237000.json','["白雲蒼山東，歸驂邁長道。", "采采斑斕衣，怡怡華萼耀。", "俯仰浩無怍，歸来豈不好。", "正疑稅駕初，已有徴車召。", "努力崇明德，勲庸良自保。", "我亦志四方，匪伊瞻旗纛。"]'),
('0806f9c8-8e4c-4c83-9bf8-bdd8e1d01f84','遊三峰','金履詳','宋','宋诗','song-poetry','','[]','九月天氣清，高飈掃虚碧。',288,'全唐诗/poet.song.237000.json','["九月天氣清，高飈掃虚碧。", "山色日嶙峋，山意亦寥閴。", "有来二三友，勸我振雙屐。", "問道始委蛇，陟巘轉深密。", "犖确礙微徑，藤蔓絆行色。", "岡阜出坡陀，重險更𡷾嵂。", "絕壁詫天造，石笋疑人立。", "上上復扳援，嵬嵬亦恂慄。", "摩蘚追舊題，捫蘿着新蹠。", "佝僂度﨑巖，盤薄踞危石。", "誰鑿丹臼深，碧瓦孰摶埴。", "云胡半空中，有此千載迹。", "中峰函劍氣，幽洞飛靈液。", "霏霏人間雨，往往此中出。", "陰崖採芝人，東岡並遊客。", "虚谷逺應聲，重崦近成隔。", "而我獨油然，振衣来千尺。", "川流一以眺，蒼莽浩無息。", "長風拂巾袂，太清可嘘吸。", "乃知艱險餘，始有高明極。", "益知身轉高，冥然氣超逸。", "登天信有基，昇仙豈無術。", "何當躡飛煙，高舉振長翮。", "倒景凌三光，逺觀天地窄。"]'),
('80f14ed4-8b59-42dd-ba3c-31b41ffc952b','逺遊篇壽立齋','金履詳','宋','宋诗','song-poetry','','[]','我歌逺遊篇，西望心悠然。',180,'全唐诗/poet.song.237000.json','["我歌逺遊篇，西望心悠然。", "孰能爲此遊，渺渺重山川。", "和鸞車班班，珩佩聲珊珊。", "塊視幾邱陵，带視幾流泉。", "正氣凝陽剛，端操凌雲煙。", "猶將徑天地，奚獨此江山。", "黄鵠以爲御，鸞鳯以爲參。", "雲旗何揚揚，八龍亦蜿蜿。", "一舉衆山小，再馳天地寛。", "三駕跨八極，高馳閶闔間。", "正陽以爲糧，六氣以爲餐。", "金丹毓天和，玉色頩脕顔。", "俯視世蚊虻，起滅甕盎邉。", "高超凌太初，達觀真後天。", "願言膏吾車，執鞭隨兩驂。"]'),
('069180ef-4dbc-47cd-b53c-3b39b6a6ec8b','題釣臺','金履詳','宋','宋诗','song-poetry','','[]','誰云孟氏死，吾道久無傳。',132,'全唐诗/poet.song.237000.json','["誰云孟氏死，吾道久無傳。", "我讀子陵書，仁義獨兩言。", "仁爲本心德，義乃制事權。", "懐輔存體用，治亂生死闗。", "迺知嚴先生，優到聖賢邊。", "歸来釣清江，夫豈長往人。", "漢道終雜霸，文叔徒幾沈。", "何如對青山，俯仰日油然。", "我来一瓣香，敬爲先生拈。", "陟彼崔嵬岡，想此仁義心。", "儼若羊裘翁，縹緲暮雲深。"]'),
('1ab24185-5ada-4479-9522-116068702cbb','龍井','金履詳','宋','宋诗','song-poetry','','[]','高峰餘洞氣，石竇通靈液。',108,'全唐诗/poet.song.237000.json','["高峰餘洞氣，石竇通靈液。", "發源已太孤，臨崖千萬尺。", "井甃回飛湍，修綆收澄碧。", "一飲清風生，膚寸寒雲出。", "山僧語似奇，老龍事無迹。", "我来翠微巔，得此寒泉食。", "東望子陵臺，連峰對𡷾嵂。", "下有十九泉，趾此相仲伯。", "因哦招隐詩，憑高三歎息。"]'),
('245c8bfb-4bfd-4f76-a82c-359923f71729','題城南塔院','金履詳','宋','宋诗','song-poetry','','[]','佳境城南勝，浮屠占十分。',48,'全唐诗/poet.song.237000.json','["佳境城南勝，浮屠占十分。", "魚釣船依竹，僧齋鉢薦芹。", "夜窗雙港月，日曉九峰雲。", "不隨人世改，千古瀫波紋。"]'),
('c2c95507-d53e-4833-ae28-c0f2adab3a38','登嚴州北高峰用韻','金履詳','宋','宋诗','song-poetry','','[]','雄蟠古睦東，俯視翠重重。',48,'全唐诗/poet.song.237000.json','["雄蟠古睦東，俯視翠重重。", "白塔清涼界，烏龍伯仲峰。", "雲連天勢近，石釀井泉濃。", "更上最高處，扳躋意勿慵。"]'),
('e62ce2ce-e172-4b73-be07-1ba5e7debb7c','輓北山子何子三首  其一','金履詳','宋','宋诗','song-poetry','','[]','道自朱黄逝，人多名利趨。',48,'全唐诗/poet.song.237000.json','["道自朱黄逝，人多名利趨。", "獨傳真統緒，惟下實工夫。", "粹德兩朝慕，清風四海孤。", "斯文端未喪，千古起廉隅。"]'),
('671ed44e-f1c4-4afe-be75-e57510b1d807','輓北山子何子三首  其二','金履詳','宋','宋诗','song-poetry','','[]','昔年夫子在，已慮曉星稀。',48,'全唐诗/poet.song.237000.json','["昔年夫子在，已慮曉星稀。", "氣運嗟辰歲，天文動少微。", "素幃兄並殯，丹旐子同歸。", "總是堪傷處，瑤琴聲更稀。"]'),
('a4f1b944-6a12-48a1-b47b-1401465e86b5','輓北山子何子三首  其三','金履詳','宋','宋诗','song-poetry','','[]','每侍圖書右，令人俗慮空。',48,'全唐诗/poet.song.237000.json','["每侍圖書右，令人俗慮空。", "隱憂惟世變，臥病亦春融。", "聖處一言敬，天然萬理中。", "音容今永已，哀痛隔幽宮。"]'),
('b76a34a4-fa01-4781-b9e8-060d0f7c8959','九月初吉永嘉蘇太古同遊金華洞夜宿鹿田寺用杜陵山館詩韻以贈','金履詳','宋','宋诗','song-poetry','','[]','携手登山處，山高風露寒。',48,'全唐诗/poet.song.237000.json','["携手登山處，山高風露寒。", "共來巖壑裏，別去海雲端。", "意重言難足，更深語未闌。", "相期最高處，志見兩俱安。"]'),
('88d5f0b8-02bf-43af-937b-e9632b81da40','苦熱和徐山甫韻','金履詳','宋','宋诗','song-poetry','','[]','地捲槁苗盡，人居沸鼎中。',24,'全唐诗/poet.song.237000.json','["地捲槁苗盡，人居沸鼎中。", "何時霖雨相，夢到武丁宮。"]'),
('6480b29f-a7fb-48a8-b203-9509d728e8a4','和王希夷廬陵觀梅','金履詳','宋','宋诗','song-poetry','','[]','歲寒堂前桂樹秋，秋風浩蕩君西遊。',150,'全唐诗/poet.song.237000.json','["歲寒堂前桂樹秋，秋風浩蕩君西遊。", "羨君充此四方志，望塵何異登瀛洲。", "人生難得心相識，況君與我心相得。", "君心誰似惟梅花，雪霜不改馨香德。", "顧我思君日幾尋，歲寒又見梅花春。", "見梅不見故人面，空詠梅花如故人。", "月明千里雖同致，疇昔追隨今少異。", "始信燈窗朝暮同，此會人生良匪易。", "噫吁嘻，安得彼此長似歲寒枝，清芬處處同襟期。"]'),
('72b7a2ef-2ebc-467b-8eef-7738c6ce2670','唐丈命玉澗僧畫金華三洞爲圖障壽母玉澗有詩約和其韻','金履詳','宋','宋诗','song-poetry','','[]','金華高哉幾千丈，翠壁重巒不可上。',160,'全唐诗/poet.song.237000.json','["金華高哉幾千丈，翠壁重巒不可上。", "上下飛潛靈液通，朝暮煙雲姿萬狀。", "我聞元女蟠金鼎，至今遺粒猶可餉。", "又聞仙姑駕銀鹿，至今瑶田印層嶂。", "金華本是東南奇，未數劍門天下壯。", "有時笙簫響青雲，猶疑幢節迎仙仗。", "自古長生端有術，飄颻羣仙尚無恙。", "祗今洞天雙龍飛，何處華表聲清喨。", "誰將此山真面目，盡收奇偉歸圗障。", "居然岡阜北堂前，未須屣履勤敖放。"]'),
('3d8a89d1-845a-4e45-919c-9f8d4190a4a5','代張起巖和清塘詩','金履詳','宋','宋诗','song-poetry','','[]','清塘佳哉，上有横霄映漢之卿雲，下有通川入海之流泉。',249,'全唐诗/poet.song.237000.json','["清塘佳哉，上有横霄映漢之卿雲，下有通川入海之流泉。", "不舍晝夜揚清清，清流迴環山奔迎。", "暮雨層波綠，朝暉山氣新。", "呼吸溪光飲山渌，人人冰玉若爲貧。", "我欲買山居其間，嚢中不靳金滿籝。", "明月清風對高士，絲桐一張酒五經。", "俯看塵世幾蚊蚋，須臾起滅敗與成。", "炎涼僅昕夕，晦朔分枯榮。", "眼前突兀徒駭俗，死後滅没杳無聞。", "孰若此地多君子，純孝千古留風聲。", "天光浮動映松柏，地望流傳光丘林。", "太鈞播羣品，生靈本一心。", "何況古人傑，由来毓地靈。", "欲爲混沌鑿七竅，須凴天工揮五丁。", "窮爲樂善之君子，達爲廟社之元勲。", "於此地靈有媿無，鄙人敢此問諸君。"]'),
('5ba9b020-34f5-4fe1-b4f0-d59484721c00','奉和魯齋先生涵古齋詩二首  其一','金履詳','宋','宋诗','song-poetry','','[]','圓融無際大無餘，萬象森然本不癯。',65,'全唐诗/poet.song.237000.json','["圓融無際大無餘，萬象森然本不癯。", "夏至聖淵源端有在，六經芳潤幾曾枯。", "人於心上知洆處，古在書中非遠圖。", "會到一源惟太極，包犧原不與今殊。"]'),
('5c5b925e-e160-4573-9f2c-a05f79a3d086','奉和魯齋先生涵古齋詩二首  其二','金履詳','宋','宋诗','song-poetry','','[]','陋巷深居世已疎，書齋幽雅更清癯。',64,'全唐诗/poet.song.237000.json','["陋巷深居世已疎，書齋幽雅更清癯。", "神徂聖伏人何在，古往今來迹易苦。", "太極運行常自若，羲皇向上可潛圖。", "渾涵妙處皆全體，大用周流自不殊。"]'),
('b6a2508a-185b-4bd6-8af8-57f03704568e','和王妙虚道士詩','金履詳','宋','宋诗','song-poetry','','[]','我愛高人巧卜居，林煙深處着精廬。',64,'全唐诗/poet.song.237000.json','["我愛高人巧卜居，林煙深處着精廬。", "煎茶石鼎客當酒，斸笋竹籬自荷鋤。", "隐几要同吾喪我，鑿池戲問子非魚。", "高山流水知音少，欲去頻聽輒駕車。"]'),
('6a895f1a-a9c0-4cbb-9762-f4e158b2ecb9','裝解卷魯齋先生置酒出詩就坐占和','金履詳','宋','宋诗','song-poetry','','[]','功名人事巧推遷，誰信此心即此天。',64,'全唐诗/poet.song.237000.json','["功名人事巧推遷，誰信此心即此天。", "三軸文章祇借徑，萬人優劣謾争先。", "豈惟科目一時重，要使勲庸後世傳。", "此意自期尤自信，端如穮蓘有豐年。"]'),
('95901223-3370-40a3-af2f-cb90a33f578c','代簡汪明卿','金履詳','宋','宋诗','song-poetry','','[]','聞道君居向紫巖，爲渠征役未遑安。',64,'全唐诗/poet.song.237000.json','["聞道君居向紫巖，爲渠征役未遑安。", "從来古語貧爲累，豈謂今時富亦難。", "六十里間無一字，幾多心事付三歎。", "秋来好着新鞭策，要把規模逺大看。"]'),
('40f8b1a3-2bee-41aa-80fd-5a4e62c8ec3f','和陳復之韻','金履詳','宋','宋诗','song-poetry','','[]','元化機緘未易知，此心之外更闗誰。',64,'全唐诗/poet.song.237000.json','["元化機緘未易知，此心之外更闗誰。", "題名本自非千佛，造物休言是小兒。", "得失天心如契鑰，古今人事等花枝。", "看来勲業皆吾分，何用諄諄詫一時。"]'),
('eaa25050-3f7a-4540-b177-09d461266a2f','奉復魯齋先生上蔡書院圗詩二首  其一','金履詳','宋','宋诗','song-poetry','','[]','生平杖履未東湖，喜自師門見畫圗。',64,'全唐诗/poet.song.237000.json','["生平杖履未東湖，喜自師門見畫圗。", "堤貫横橋分半水，規方盈尺已全模。", "衣冠上蔡存遺緒，絃誦濂溪可合符。", "此地先生開道脈，尚遲從往我非夫。"]'),
('24fd72fb-88d2-4cc5-a576-9f7c2a017ea7','奉復魯齋先生上蔡書院圗詩二首  其二','金履詳','宋','宋诗','song-poetry','','[]','臨海闗東水滿湖，書堂新上赤城圗。',64,'全唐诗/poet.song.237000.json','["臨海闗東水滿湖，書堂新上赤城圗。", "地居郊左宜芹藻，天錫奎章示楷模。", "王謝後前傳正印，東南鄒魯定同符。", "誰終濺起平湖水，雨我公田幾萬夫。"]'),
('42bf6a1f-64b2-4d22-a365-511eaf7f6a44','景定甲子夏五三日王希夷兄有弄璋之慶是時希夷尚在歲寒堂報至以曆推之日在參月在東井火在天西北魯齋先生曰此卿相之命也越七日希夷煮餅歲寒諸朋友與焉桐陽金履祥吉甫爲詩以賀','金履詳','宋','宋诗','song-poetry','','[]','七日已叨湯餅客，幾時親賞寧馨兒。',64,'全唐诗/poet.song.237000.json','["七日已叨湯餅客，幾時親賞寧馨兒。", "有崇佛子于今見，王氏多佳自古奇。", "培養慶源惟一善，流傳家學有餘師。", "異時才氣須名世，莫負先生卿相期。"]'),
('258c0d3a-ca21-4c53-bf92-5a14cc3dbec7','題富陽嚴先生祠耕春堂','金履詳','宋','宋诗','song-poetry','','[]','西望先生舊釣臺，無窮山色鎖崔嵬。',64,'全唐诗/poet.song.237000.json','["西望先生舊釣臺，無窮山色鎖崔嵬。", "閒歸故國耕春雨，遂起頽風生暮雷。", "萬事盡随江水去，千年寧幾客星来。", "北山今有何夫子，不入經筵亦草萊。"]'),
('e452616e-d817-400a-a8f9-360fcddb498f','都下會安吉姚學林作詩奉勉','金履詳','宋','宋诗','song-poetry','','[]','客裏相逢豈偶然，羨君爽氣浩無邊。',64,'全唐诗/poet.song.237000.json','["客裏相逢豈偶然，羨君爽氣浩無邊。", "世間固是少英物，吾輩當期不負天。", "撐起元龍湖海氣，撩来坡老短長篇。", "化工不盡斯文在，莫學餘人學聖賢。"]'),
('fbf8d57c-b284-4035-b513-68f48f0c0cef','後數日姚學林用前韻言别因别奉','金履詳','宋','宋诗','song-poetry','','[]','聚散雲萍有是言，與君相遇帝城邊。',64,'全唐诗/poet.song.237000.json','["聚散雲萍有是言，與君相遇帝城邊。", "共吟黄卷東風裏，相對青燈夜雨天。", "養此俊明真大器，發予沉痼有佳篇。", "贈言歸别勤渠意，别後重哦即見賢。"]'),
('0ced0051-7e29-40a1-b35b-b8439a06f0bb','三月十六日爲某初度十九日又趙寅仲誕辰俱在歲寒堂王先生皆爲之設湯餅寅仲欲往三衢雷雨大作諸兄留行置酒爲壽作詩以賀','金履詳','宋','宋诗','song-poetry','','[]','帝遣銀潢一派来，日長春老起風雷。',64,'全唐诗/poet.song.237000.json','["帝遣銀潢一派来，日長春老起風雷。", "誰知年少貴公子，儼若儒先老秀才。", "共作師門湯餅客，早期庭下綵衣萊。", "明朝又上柯山去，更問長生要術回。"]'),
('e7b23f87-a9f7-4a7e-97f2-604388a30ab9','王子可欲壽趙寅仲思成出薲嚚閩兟瞤五字令賦詩','金履詳','宋','宋诗','song-poetry','','[]','操似青松潔似薲，頌言忠信匪爲嚚。',64,'全唐诗/poet.song.237000.json','["操似青松潔似薲，頌言忠信匪爲嚚。", "水分銀漢浸江浙，城擁天台控粤閩。", "人向少時宜娓娓，德于進處更兟兟。", "聊翁聞有侯鯖味，昨夜宵人已目瞤。"]'),
('a736b8ba-d5b2-47fd-8f40-27b3e6830c07','進退格送蘇金華解官東歸','金履詳','宋','宋诗','song-poetry','','[]','勇學淵明賦歸去，豈隨巧宦效脂韋。',64,'全唐诗/poet.song.237000.json','["勇學淵明賦歸去，豈隨巧宦效脂韋。", "居官但飲雙溪水，問圃寧無三徑資。", "碧落競騰鵰鶚興，秋風獨憶鱠魚肥。", "吾皇側席思賢德，會有徵書下赤墀。"]'),
('dfe0ed6f-b863-4d83-b6f8-e0a7e943ca6b','九日書懐','金履詳','宋','宋诗','song-poetry','','[]','欲買山園種菊花，此心荏苒負年華。',64,'全唐诗/poet.song.237000.json','["欲買山園種菊花，此心荏苒負年華。", "幾時三徑成歸計，今日重陽轉憶家。", "落帽已驚微雪早，登樓爲望白雲斜。", "詩成捲起悲秋意，天濶風高未易涯。"]'),
('28be4499-358e-4107-8350-f16a7368a984','立齋静佳樓和王吉州韻','金履詳','宋','宋诗','song-poetry','','[]','層樓新扁表新功，箇裏工夫自不同。',64,'全唐诗/poet.song.237000.json','["層樓新扁表新功，箇裏工夫自不同。", "儼若思時居此敬，寂然静處感而通。", "山窺南北浮嵐小，月轉西東灝氣充。", "更植樓前佳玉樹，君家槐蔭比車攻。"]'),
('221c160c-76c0-4d92-bc56-0d3a1771f634','和徐山甫初秋韻','金履詳','宋','宋诗','song-poetry','','[]','衆口嗷然望有秋，炎威何事燦林邱。',64,'全唐诗/poet.song.237000.json','["衆口嗷然望有秋，炎威何事燦林邱。", "原田處處成焦土，江水源源亦斷流。", "連月更無甘雨應，長空惟有火雲浮。", "如今幸喜金風到，會瀉銀河洗衆憂。"]'),
('a15beabd-dab9-4d0f-9254-8e8ef2698bdc','七月三日和徐山甫喜雨','金履詳','宋','宋诗','song-poetry','','[]','饑穰誰道盡由天，治國須知類小鮮。',64,'全唐诗/poet.song.237000.json','["饑穰誰道盡由天，治國須知類小鮮。", "貪吏班車方立立，雷神振鼓已闐闐。", "宏羊既往民無事，旱魃不来書有年。", "自此皇家歌樂歲，魚麗天保永無愆。"]'),
('5daa159b-4f92-4e77-9722-221dc37a915c','題王立齋矩軒記後','金履詳','宋','宋诗','song-poetry','','[]','以矩名軒義已諧，方方尋丈自恢恢。',64,'全唐诗/poet.song.237000.json','["以矩名軒義已諧，方方尋丈自恢恢。", "勿侵四壁藩籬限，不費一天風日来。", "學者毋欺惟暗室，聖門所樂只靈臺。", "盍朋但讀立齋記，誰謂顔居曰陋哉。"]'),
('4fed4165-3fca-4479-8009-77356eae7ea1','釋弟','金履詳','宋','宋诗','song-poetry','','[]','我生半世尚茫茫，西既隔谷東如湯。',64,'全唐诗/poet.song.237000.json','["我生半世尚茫茫，西既隔谷東如湯。", "衆責今方四面至，百爲盡要一身當。", "仲兄摘實瓜幾少，伯氏刈葵根已傷。", "康叔周公本相睦，休滋俗見積參商。"]'),
('1ddbf118-aa52-4f42-ae3f-045a65f8ba91','棲真紀勝贈立公二首  其一','金履詳','宋','宋诗','song-poetry','','[]','高真棲處在山阿，古寺山靈久護訶。',64,'全唐诗/poet.song.237000.json','["高真棲處在山阿，古寺山靈久護訶。", "三洞奇峰踞龍虎，千秋喬木長藤蘿。", "泉流清澈天池近，石竇巃嵸雲氣多。", "一片飛来山更好，飛来端的自岷峩。"]'),
('9bd2ac18-24d0-444f-bda6-3b80942cfa86','棲真紀勝贈立公二首  其二','金履詳','宋','宋诗','song-poetry','','[]','閒闖秋高强入山，棲真勝地極高寒。',64,'全唐诗/poet.song.237000.json','["閒闖秋高强入山，棲真勝地極高寒。", "契泉水下人間去，靈洞雲從天半看。", "麗澤先生留姓字，穎濵元子蛻衣冠。", "典刑尚在山深處，爲宿心香不敢灌。"]'),
('80dd1a47-ceb8-43ae-a8cd-7db1f7ab0f37','壽徐山甫','金履詳','宋','宋诗','song-poetry','','[]','三春芳意徧羣葩，今日崧高肇錫嘉。',64,'全唐诗/poet.song.237000.json','["三春芳意徧羣葩，今日崧高肇錫嘉。", "西館暫爲湯餅會，北堂長奉彩衣華。", "祇今喜有莵裘約，此去仍標桂籍花。", "吉甫重歌山甫誦，由来補衮是君家。"]'),
('5b1404bc-5d7c-478b-b369-ae203bc85e0f','壽張南坡恭','金履詳','宋','宋诗','song-poetry','','[]','緑袖斑斕上慶庭，鶯鶯燕燕競新聲。',64,'全唐诗/poet.song.237000.json','["緑袖斑斕上慶庭，鶯鶯燕燕競新聲。", "庚寅初度踰三紀，丁卯秋来快一鳴。", "九十春光清晝永，百千歲頌壽星明。", "願君高舉紉蘭佩，自古悠長是令名。"]'),
('ce63d38a-0127-48c5-8d64-78915a5c58c5','輓王易巖','金履詳','宋','宋诗','song-poetry','','[]','石笋孫枝萃衆芳，少推夙慧映諸郎。',64,'全唐诗/poet.song.237000.json','["石笋孫枝萃衆芳，少推夙慧映諸郎。", "故家文獻典刑在，前輩風流氣脉長。", "誤把一編黄紙冊，未沾數寸緑袍香。", "同雲慘澹西原路，頼有遺編死不亡。"]'),
('50f73b5f-4492-4f68-ad4a-0fa62dbe1c6e','輓劉南坡','金履詳','宋','宋诗','song-poetry','','[]','憶昔端平轉化弦，公時輸委爲安邊。',64,'全唐诗/poet.song.237000.json','["憶昔端平轉化弦，公時輸委爲安邊。", "鼎成龍御方賓帝，弓墮烏號亦蛻仙。", "漫仕此情初已薄，愛君一念世逾堅。", "典刑今與丹旌去，空些哀詞咽澗泉。"]'),
('5a71eb1d-c6be-428a-8721-b02719c05355','輓徐居士二首  其一','金履詳','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','昔年澇旱苦頻仍，南北郊闗自越秦。',64,'全唐诗/poet.song.237000.json','["昔年澇旱苦頻仍，南北郊闗自越秦。", "東浙于時猶道殣，嚴邦此地況山民。", "能回涸轍西江水，頓起翳桑寒谷春。", "神理因推居上坐，壓他持秉剖符人。"]'),
('293bb7ff-607d-4be2-9bab-bea407f1cee7','輓徐居士二首  其二','金履詳','宋','宋诗','song-poetry','','[]','積善由来屬慶門，如公積善衆推尊。',64,'全唐诗/poet.song.237000.json','["積善由来屬慶門，如公積善衆推尊。", "至於垂死片言頃，猶是賙饑一念存。", "有子巳登天子學，無人不感德人恩。", "霜風慘淡禾塘路，繼志揚名在後昆。"]'),
('c7eb8f8a-9812-41cf-a90e-a263e55842bf','輓蓮塘呉孺人  其一','金履詳','宋','宋诗','song-poetry','','[]','北風吹恨入佳城，忍聽依依薤露吟。',64,'全唐诗/poet.song.237000.json','["北風吹恨入佳城，忍聽依依薤露吟。", "家世百年忠厚意，夫人一點惠慈心。", "橋横蘭渚陰功逺，山遶蓮塘地脉深。", "記取祇今埋玉處，他時青紫映丘林。"]'),
('f3fe500b-dfb0-4318-a7c7-dbf2c3d9a74c','輓蓮塘呉孺人  其二','金履詳','宋','宋诗','song-poetry','','[]','題汪功父所藏畫卷。',9,'全唐诗/poet.song.237000.json','["題汪功父所藏畫卷。"]'),
('b886d007-f857-430b-b697-fc3aee941b09','輓蓮塘呉孺人  其三','金履詳','宋','宋诗','song-poetry','','[]','細雨西窗展畫筒，江山杳靄幾重重。',32,'全唐诗/poet.song.237000.json','["細雨西窗展畫筒，江山杳靄幾重重。", "簷花飛動衣裳冷，疑在雲間第一峰。"]'),
('3f1475c5-48d5-4d3c-9993-81b759038c7f','術士求詩','金履詳','宋','宋诗','song-poetry','','[]','自分迂踈已遁思，君言造化有他奇。',32,'全唐诗/poet.song.237000.json','["自分迂踈已遁思，君言造化有他奇。", "吾生果赴功名會，不使勲庸媿鼎彛。"]'),
('d4a7f66f-1d6d-455e-80f5-b9e046c8cc17','術士求書往横山復以詩贈','金履詳','宋','宋诗','song-poetry','','[]','錢君杖履到横山，爲我傳聲談話間。',32,'全唐诗/poet.song.237000.json','["錢君杖履到横山，爲我傳聲談話間。", "術動諸君應一笑，不教垂槖怨空還。"]'),
('ea060aad-43ce-459b-a502-b3d28aa675ae','遊赤松口占','金履詳','宋','宋诗','song-poetry','','[]','蒼虬夾岸幾重重，靈液飛流碧澗通。',32,'全唐诗/poet.song.237000.json','["蒼虬夾岸幾重重，靈液飛流碧澗通。", "可是神人易忘世，人間争得此山中。"]'),
('f346e560-f3dd-4ccf-b4a3-660046890ed3','作深衣小傳王希夷有絕句索和語','金履詳','宋','宋诗','song-poetry','','[]','深衣大带非今士，考禮譚經盡古書。',32,'全唐诗/poet.song.237000.json','["深衣大带非今士，考禮譚經盡古書。", "莫把律詩較聲病，聖賢工夫不此如。"]'),
('b3093476-5c17-4b51-92d1-ef4113f8358f','題青岡時兄友山樓','金履詳','宋','宋诗','song-poetry','','[]','萬頃平疇一色春，雙溪城闕北山青。',32,'全唐诗/poet.song.237000.json','["萬頃平疇一色春，雙溪城闕北山青。", "登樓不爲閒瞻眺，此地前賢尚典刑。"]'),
