('71535886-922a-469b-bc32-24b7042d35c8','洞山十詠 老梅巖','金履詳','宋','宋诗','song-poetry','','[]','片石﨑嶔斜插澗，横枝愁絕浄無塵。',32,'全唐诗/poet.song.237000.json','["片石﨑嶔斜插澗，横枝愁絕浄無塵。", "從兹石上栽冰玉，寒谷年年遞早春。"]'),
('c1af1815-8d89-4e0b-b411-c100a3729ef4','洞山十詠 中峰','金履詳','宋','宋诗','song-poetry','','[]','高巖南下走羣龍，兩小源頭合一峰。',32,'全唐诗/poet.song.237000.json','["高巖南下走羣龍，兩小源頭合一峰。", "問道是中人不識，先生信善擇中庸。"]'),
('869a5cd9-ce60-48e3-a4db-d13660aa47e9','廣箕子操','金履詳','宋','宋诗','song-poetry','','[]','炎方之將，大地之洋。',102,'全唐诗/poet.song.237000.json','["炎方之將，大地之洋。", "波湯湯，翠華重省方，獨立回天天無光。", "此志未就，死矣死南荒。", "不作田横，横来者王。", "不學幼安，歸死其鄉。", "欲作孔明，無地空翺翔。", "惟餘箕子，仁賢之意留蒼茫，穹壌無窮此恨長。", "千世萬世，聞者徒悲傷。"]'),
('252317ea-2b9d-4cde-b1a9-dfc2a604784b','吉祥草','王相','宋','宋诗','song-poetry','','[]','得名良不惡，瀟灑在山房。',48,'全唐诗/poet.song.237000.json','["得名良不惡，瀟灑在山房。", "生意無休息，存心固久長。", "風霜徒自老，蜂蝶爲誰忙。", "歲晚何人問，山空暮雨荒。"]'),
('94f6e6a4-c8b9-4626-926c-2bcd5885329d','保應廟','董朴','宋','宋诗','song-poetry','','[]','廟食空山八百年，衣冠猶是李唐前。',32,'全唐诗/poet.song.237000.json','["廟食空山八百年，衣冠猶是李唐前。", "汴河十里垂楊柳，何似松陰數畝田。"]'),
('502a14ca-46cf-4a76-817f-bc35787d8fde','定林寺  其一','家之巽','宋','宋诗','song-poetry','','[]','山人當日濟時艱，要把唐虞作樣看。',32,'全唐诗/poet.song.237000.json','["山人當日濟時艱，要把唐虞作樣看。", "奏罷簫韶無鳳至，空教猿鶴怨盟寒。"]'),
