('fc1c479f-12e9-4d5b-8bca-5873aa35289e','定林寺  其五','家之巽','宋','宋诗','song-poetry','','[]','老屋三門山徑幽，中藏無限古今愁。',32,'全唐诗/poet.song.237000.json','["老屋三門山徑幽，中藏無限古今愁。", "新詩吟罷春雲合，塔裏金仙笑點頭。"]'),
('a5df61e9-ffce-482f-9e8b-eeda83c2b5bf','福勝院','家之巽','宋','宋诗','song-poetry','','[]','三過山中寺，勞生有底忙。',48,'全唐诗/poet.song.237000.json','["三過山中寺，勞生有底忙。", "梵書蟲蠹紙，佛界燕巢梁。", "曉日光明藏，野花知見香。", "豐碑如會意，讀罷更彷徨。"]'),
('2bc7ed67-9527-4a3d-9b0c-01a6727f98e0','艮山閣  其一','家之巽','宋','宋诗','song-poetry','','[]','樂山仁者寂不動，面壁老胡機械深。',32,'全唐诗/poet.song.237000.json','["樂山仁者寂不動，面壁老胡機械深。", "艮背行庭無別義，佛心即是伏羲心。"]'),
('5762fec8-feb4-4c24-8e4b-df2481e3778b','艮山閣  其二','家之巽','宋','宋诗','song-poetry','','[]','一丘兀硉蒼虬住，四面森嚴陣馬齊。',32,'全唐诗/poet.song.237000.json','["一丘兀硉蒼虬住，四面森嚴陣馬齊。", "却笑白雲無定相，長時逐雨過前溪。"]'),
('205f0764-3dc6-4e56-8332-9d1fb9500d4d','和三賢堂詩  其一','家之巽','宋','宋诗','song-poetry','','[]','孤峯落魄一詩人，白傅何曾號直臣。',64,'全唐诗/poet.song.237000.json','["孤峯落魄一詩人，白傅何曾號直臣。", "較似眉山敢同傳，並祠浙水恐誣神。", "人非倫擬終非偶，論貴平和不貴新。", "爭似獨尊元祐學，高堂正笏更垂紳。"]'),
('ee7c372d-c7b0-4414-ba89-de6f154d69a6','和三賢堂詩  其二','家之巽','宋','宋诗','song-poetry','','[]','誰稱三老作三山，夫子寧居季孟間。',64,'全唐诗/poet.song.237000.json','["誰稱三老作三山，夫子寧居季孟間。", "駱廄侍人多媿色，鼈頭處士若爲攀。", "辭章小技應閒事，節義千年真大閑。", "何似眉山專一壑，九京賢聖盡歡顔。"]'),
('b9fc9118-d2f8-47ba-ac83-e5bfedeec22b','視旱田賦呈上元簿楊明卿','張伯子','宋','宋诗','song-poetry','','[]','輸蹄旦旦風塵表，入眼羣山青未了。',192,'全唐诗/poet.song.237000.json','["輸蹄旦旦風塵表，入眼羣山青未了。", "刺藤迎日子先紅，蕎麥得霜花漸老。", "叢祠詭怪畫村疃，古寺騫騰出林杪。", "征衫多次逐飛鳶，下檐有時隨宿鳥。", "初晴得去恨遲遲，獨夜不眠憂悄悄。", "公如老驥暫伏櫪，我類游鱗終屈沼。", "一朝王事有期會，百里民情同探討。", "詳于禹貢辨等級，明似離婁燭幽眇。", "高依丘壟或微收，低近陂塘翻盡槁。", "凶荒有數合均一，報應于中又分曉。", "不能究實害非淺，倘使從寬恩豈小。", "茲行到處欲春風，批放莫教分數少。"]'),
('be1f54ba-a7d9-4f3e-8fe9-05beba0562e6','小蓬萊歌','王𡌴','宋','宋诗','song-poetry','','[]','僊之山兮□□，僊之水兮委陀。',219,'全唐诗/poet.song.237000.json','["僊之山兮□□，僊之水兮委陀。", "駕輕車兮□□，□扁舟兮詠歌。", "軼層巓兮□□，□□流兮白石楚楚。", "上切漢兮□□，□□□兮在下。", "崖花兮春芳，澗□□□□。", "□□澂兮縑素，冰霜結兮璆瑯。", "□□□□魚，鳥躍飛兮誰使。", "石□年兮一□，三萬里兮弱水。", "于嗟蓬萊兮仙水是室廬，世之人兮莫知其歌□。", "□□□兮披荆棘，驅虎兕兮□□□。", "□□□兮海濤白，倒光景兮□□□。", "□□□兮執華予，眇流盼兮□□□。", "□□□兮濤無期，碧荔爲衣兮□□□。", "□□埃𡏖兮不可以控摶，□□□□□□□憺忘歸。"]'),
('eeefcaa3-d7a9-4b73-88c2-aea713567d59','西禪餞董溪翁','趙時儋','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','西浦風寒水自流，迢迢行李又歸休。',64,'全唐诗/poet.song.237000.json','["西浦風寒水自流，迢迢行李又歸休。", "今宵古寺吟邊酒，明日長江客裏舟。", "溪路梅花催雪興，旗亭竹色伴雲愁。", "還家更爲明時出，莫向漁磯老釣鈎。"]'),
('ce074b91-1d0e-4dbe-9b91-791796a3fdce','己未秋登城北樓','翁泳','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','脚底江南第一州，臺城北上小淹留。',64,'全唐诗/poet.song.237000.json','["脚底江南第一州，臺城北上小淹留。", "難忘故國千年恨，不盡長江萬古流。", "目斷中原誰擊楫，秋來多雨獨登樓。", "舉頭忽見長安日，一醉能消太白愁。"]'),
('35152d68-8ec4-4feb-b6a0-7c32f7814c3b','陪周溪園登賞心亭','翁泳','宋','宋诗','song-poetry','','[]','建業城樓四面窗，賞心勝處冠南邦。',64,'全唐诗/poet.song.237000.json','["建業城樓四面窗，賞心勝處冠南邦。", "石頭西峙雲藏寺，水面南浮月滿江。", "故國秋深人自老，新河夜遁虜誰降。", "高人登眺同懷古，忽有飛來白鷺雙。"]'),
('3193cae3-cd81-427c-8fb7-a2930968fcae','遊聖水寺偶成','蔡逸','宋','宋诗','song-poetry','','[]','盡日苦征賦，公餘散霽懷。',48,'全唐诗/poet.song.237000.json','["盡日苦征賦，公餘散霽懷。", "塞雲生古石，宿雨溜懸巖。", "鳥倦晨猶伏，僧眠午未齊。", "高人莫相笑，仙尉亦吾儕。"]'),
('3dd8eec3-aa53-46e8-a913-b3202b2d4a73','遊聖水興慈寺','蔡逸','宋','宋诗','song-poetry','','[]','二月春事半，縣花無數開。',156,'全唐诗/poet.song.237000.json','["二月春事半，縣花無數開。", "江頭連騎行，江霧紹法埃。", "下馬坐清蔭，觀魚大江隈。", "行行歷山寺，金碧森樓臺。", "拂石有唐碑，字老生莓苔。", "緬想古今事，悠然一傷懷。", "解榼醉泉石，徬徨不忍回。", "辭徑下扁舟，重開賸樽罍。", "江煙暝川谷，冰輪出崔嵬。", "水面映金波，流光浮玉杯。", "蕩漾舟渚間，往來恣徘徊。", "一棹轉圓沙，燈火來相催。", "高歌賦厭厭，會須期再來。"]'),
('880a9b67-7fe7-4d50-ae07-d284b7c76d60','題浯溪二首  其一','蔣孝忠','宋','宋诗','song-poetry','','[]','好山好水占浯溪，中直磨崖一片碑。',32,'全唐诗/poet.song.237000.json','["好山好水占浯溪，中直磨崖一片碑。", "試問天齊齊幾許，從他元子賸夸毗。"]'),
('69a388da-c22a-43dd-ba62-9dd03f30eea1','題浯溪二首  其二','蔣孝忠','宋','宋诗','song-poetry','','[]','我宋中原二百州，版圖漸入掌中收。',32,'全唐诗/poet.song.237000.json','["我宋中原二百州，版圖漸入掌中收。", "只今更辦河清頌，勒向燕然最上頭。"]'),
('236b1b8c-017c-4bc1-801f-976f4fda9247','小孤山','董嗣杲','宋','宋诗','song-poetry','','[]','小孤隸舒州，誰將峭崖削。',288,'全唐诗/poet.song.237000.json','["小孤隸舒州，誰將峭崖削。", "一尖漾浩渺，藤蘿綴瓔珞。", "緑篠裹山脇，白浪沸山脚。", "向背千萬態，渾不假鎸鑿。", "危亭嵌空搆，四絕屯煙幕。", "幾點漚浮現，滅沒鷗自若。", "廟額錫惠濟，軒窗輝丹雘。", "夫人象服嚴，香燈閃踈箔。", "風露展幽扄，震撼陵虚閣。", "朱方金焦奇，莫敵此開拓。", "來時棹扁舟，兩岸成巨壑。", "所歷焉能窮，懐抱徒爾惡。", "未臨不測淵，胸次先隕穫。", "西偏磨崖上，吟句大手作。", "一來一歸興，其尚由來各。", "志曠誰推許，恐貽世所薄。", "窮冬水正縮，期傍洲沙泊。", "豈料風更横，飛帆随岸掠。", "遂令搜吟懐，汲井苦無索。", "彭浪訛彭郎，祠南顔有怍。", "相對隔津逺，知擁何封爵。", "顛船泛濤巔，何異跧屈蠖。", "埋篷且斟觚，失喜免酬酢。", "明月水禽飛，不奈栖鶻搏。"]'),
('f68f14d5-6427-4283-a93e-918b22cb43b0','次湖口','董嗣杲','宋','宋诗','song-poetry','','[]','湖水出瀾蠡，江水下巴蜀。',120,'全唐诗/poet.song.237000.json','["湖水出瀾蠡，江水下巴蜀。", "恰當相合處，清濁皆蕩沃。", "扁舟凌浩渺，渡者苦局促。", "卸帆與立桅，黄帽不須督。", "紙錢望空颺，飽肉爲相觸。", "江神昭靈休，壓浪無留矚。", "遂使驚魂甦，免得遭鬼録。", "去程天茫茫，灘過有磯續。", "磯頭熟風波，寒草失舊緑。", "所願晴風恬，遵陸脫羈束。"]'),
('7bab3876-ab26-439b-a4f8-56571256ee91','入寓雙泉寺','董嗣杲','宋','宋诗','song-poetry','','[]','大江沙岸虚，幾寸水痕落。',120,'全唐诗/poet.song.237000.json','["大江沙岸虚，幾寸水痕落。", "蕭蕭雙泉寺，佛像剥丹雘。", "紙輪轉晴鼓，灰塔斷風鐸。", "殘僧極荒怠，深得酒中樂。", "西風客子來，棲暫得矮閣。", "開窗望村疃，四下塵漠漠。", "人煙極零星，雞犬更蕭索。", "自罹開慶擾，景况恍如昨。", "周章見世態，彫瘵嘆民瘼。", "梵唄忽傳聲，飽飯且藜藿。"]'),
('1df77602-1a8d-4d6d-a68e-2b10306e6d2e','舟上感興','董嗣杲','宋','宋诗','song-poetry','','[]','飯時發雷江，倐已泊東流。',180,'全唐诗/poet.song.237000.json','["飯時發雷江，倐已泊東流。", "南北兩岸雪，蕩此無根舟。", "逺山失翠眉，近山生白頭。", "凍極方徯晴，雲沍含雨羞。", "塵境那得見，泛此如瀛洲。", "宿驚恍未定，醉疑此難留。", "落日漏微光，光暝無限愁。", "風厲萬水立，舟子惟搔頭。", "慷慨觸潜抱，行止負隠憂。", "志士亦徒苦，俗豎多不侔。", "天公釀雪甚，八荒元氣浮。", "無語坐舟尾，景與年俱遒。", "亂眼逐勝去，奔迸少自由。", "風煙下江異，髯邉漬霜稠。", "餘樽侑登臨，惜無水際樓。"]'),
('82c53508-40b3-4a4a-b252-3f78b45aecb7','出城','董嗣杲','宋','宋诗','song-poetry','','[]','驟暄試單衣，出城看荒圃。',96,'全唐诗/poet.song.237000.json','["驟暄試單衣，出城看荒圃。", "滿徑鬰纎茸，藥苖青可數。", "籬花漸吐艶，艶盛如織組。", "人煙聚營屋，随事歷勤苦。", "春沙落飛鳥，春水上層浦。", "行子晚未憇，貧樵出深塢。", "孤生真蜉蝣，頃刻即終古。", "歸途多上燈，沽店半扄户。"]'),
('42af77ef-276e-41c6-92cc-87e7b8c3bf57','泊蘄州城下晚思','董嗣杲','宋','宋诗','song-poetry','','[]','日落烏雀下，笛聲起譙樓。',144,'全唐诗/poet.song.237000.json','["日落烏雀下，笛聲起譙樓。", "舟泊倦欹枕，枕此秋江頭。", "寸心積萬思，浪寄非久留。", "斬新雉堞壯，環塹柳影稠。", "城中酒旗飛，窈窕吳姬謳。", "風傳何凄然，抑揚邈難儔。", "往時委黄茅，今此開青油。", "香凝燕寢曉，喜見鴻集秋。", "磯月照客衣，苦觸聽砧愁。", "夜深不敢語，我吟月解不。", "月落不旋踵，雲過江聲浮。", "逗曉入城步，將詩扣郡侯。"]'),
('8e906318-72c6-42dc-9b1a-21f06c7cf7b6','官舟上富池二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','富池遡流上，險在登官船。',48,'全唐诗/poet.song.237000.json','["富池遡流上，險在登官船。", "浮動不堪伏，薄命危絲懸。", "楓葉舞片輕，蘆花裊漪鮮。", "晚景自可寫，肯想濤頭顛。"]'),
('6a4fb347-6502-44c2-8c2f-589a9d38417a','官舟上富池二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','荒舟可隘守，難供渺茫泛。',48,'全唐诗/poet.song.237000.json','["荒舟可隘守，難供渺茫泛。", "忽罹風水髙，愁覩帆脚蘸。", "凉薄有身紀，平白慮此陷。", "聞說所僑地，晝夜演空梵。"]'),
('5fe81ff1-b11b-425a-a377-609e8107966c','夜泊富池','董嗣杲','宋','宋诗','song-poetry','','[]','望窮破寺樓，趁月沙岸泊。',120,'全唐诗/poet.song.237000.json','["望窮破寺樓，趁月沙岸泊。", "更深河漢淡，砧□出籬落。", "凄然不得睡，俄頃風作惡。", "遥程已不計，心膽尚隕穫。", "移舟傍深纜，穏借今宵託。", "不須嘆邅迴，所苦在離索。", "知身寄何處，只得呼樽酌。", "波濤曉方定，掀篷卸空槖。", "託目祠宇新，榱桷燦丹堊。", "共指甘王靈，古墓出林薄。"]'),
('12642f24-939f-449f-90ea-085dfeb06fbc','曉出西門問程廬山因懐雲翁','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u957f\u6c5f"]','譙樓罷傳角，將啓東方明。',240,'全唐诗/poet.song.237000.json','["譙樓罷傳角，將啓東方明。", "我欲披野衣，西出湓江城。", "整屐休遲回，徑作匡廬行。", "是時凉雲閣，茅屋雞互鳴。", "蕭蕭籬落破，已遞機杼聲。", "沿回且多趣，仰睇山崢嶸。", "湛露著草木，秋色何光榮。", "雲樹漏初曦，小立傷前程。", "岩翁樂髙褰，因知跋涉情。", "盤兹翠閣深，自照泉影清。", "聽猿步荒寂，乳竇百怪呈。", "屏障互隠見，松竹相迴縈。", "兼懐知己多，此際莫合并。", "蘿陰匝道周，野卉難辨名。", "聊從蘭若留，危闌壓飛甍。", "丘壠入悵望，牛羊踐榛荆。", "人生如浮漚，失壯良可驚。", "及時不濟勝，老去懐不平。", "瞭然看山眼，山意爭邀迎。", "窮崖由此探，大笑長江横。"]'),
('5ac3094f-9a4b-4ff8-bb02-bcc3bfb55113','阻風繫舟','董嗣杲','宋','宋诗','song-poetry','','[]','避風急投港，港狹水如線。',144,'全唐诗/poet.song.237000.json','["避風急投港，港狹水如線。", "沙頭虎跡多，此是銅陵縣。", "亂山號枯松，長風舞寒霰。", "饑鳬宿荒畈，小鴈帯飛箭。", "廢刹撞破鐘，催科走郵傳。", "娼家編棘門，村飾無釵釧。", "日納抱酒錢，夜陪縣官宴。", "有身悵此生，又復堕貧賤。", "荒譙更點差，信步空階徧。", "未昏行人絕，月色盪江面。", "啜盡茶葉苦，不與愁魔戰。", "託興入短歌，聊以記吾見。"]'),
('246b5d12-f297-4f0e-992e-ed767cf7e7c0','酒邊寫興别陳石泉','董嗣杲','宋','宋诗','song-poetry','','[]','强求斗升禄，三年困山城。',120,'全唐诗/poet.song.237000.json','["强求斗升禄，三年困山城。", "羈栖不敢恨，眼爲溪山明。", "上借臺府寛，下遂吟嘯情。", "束裝待航歸，積霖咽秋聲。", "排憂歩園徑，難捨曲折清。", "東望氣鬰葱，緑槐冒飛甍。", "緬懐交際歎，嚬笑陽春生。", "求田役夢魂，投老歸此耕。", "願心尚渺茫，别酒那忍傾。", "歸步故林月，寄梅堅斯盟。"]'),
('16093c7f-3121-41c2-8003-a9f4b7a50769','愛客有感','董嗣杲','宋','宋诗','song-poetry','','[]','在家最喜客，出外復過之。',120,'全唐诗/poet.song.237000.json','["在家最喜客，出外復過之。", "相逢旅瑣間，所恨力莫支。", "迂曠膽相照，相顧何須期。", "或者誚交泛，責我無藩籬。", "我性得之天，懐抱更坦夷。", "謗随愛憎興，而我了不知。", "義利界限分，我心石不移。", "風月賸佳趣，未易以迹窺。", "有吟莫辭和，有酒須共持。", "古道已不作，徒重旅心悲。"]'),
('f8c3114b-a11f-4ae4-93e0-66c7dc8d21d7','春遊  其一','董嗣杲','宋','宋诗','song-poetry','','[]','山童携竹杖，支我歩城頭。',48,'全唐诗/poet.song.237000.json','["山童携竹杖，支我歩城頭。", "東風撲酒香，吹醒殊鄉愁。", "江波蕩太陽，萬頃金色浮。", "土人不識此，我可専春遊。"]'),
('8918fc70-7ae0-442c-b9e7-e981bde25359','春遊  其二','董嗣杲','宋','宋诗','song-poetry','','[]','登城最凄黯，絕殢脂粉醉。',48,'全唐诗/poet.song.237000.json','["登城最凄黯，絕殢脂粉醉。", "萬里煙塵濛，掩此戰争地。", "江風蕩漁歌，便覺春光異。", "嗟我道不行，頗動乘桴志。"]'),
('de36f627-cf21-4d1a-a472-b3d539182746','春遊  其三','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','日日步春去，偶值江色晴。',48,'全唐诗/poet.song.237000.json','["日日步春去，偶值江色晴。", "楊柳翠頻蹙，不管黄鸝聲。", "歸栖官屋寒，月暗燈不明。", "獨坐想遊衍，西湖無限情。"]'),
('1186ad59-17ad-40bf-9546-b825ab98d031','春遊  其四','董嗣杲','宋','宋诗','song-poetry','','[]','買魚縷銀鱠，鱠細供春醉。',48,'全唐诗/poet.song.237000.json','["買魚縷銀鱠，鱠細供春醉。", "醉立海棠風，看山負慙愧。", "萬事可離蹤，白髪不容僞。", "我屋枕乾溪，日揖南峯翠。"]'),
('7e60e6df-6252-4f8a-95a6-1bc3aa84450c','感興','董嗣杲','宋','宋诗','song-poetry','','[]','荒菊死石罅，小梅發岩阿。',96,'全唐诗/poet.song.237000.json','["荒菊死石罅，小梅發岩阿。", "時換物色異，雨過霜晴多。", "寒烏抱枯柳，悲鳴愁網羅。", "哀哀如訴人，人豈無風波。", "風波久自定，静黙可禦魔。", "同心議否臧，有酒能消磨。", "不興短生思，奈此歲月何。", "掩門忽思歸，睡熟聞棹歌。"]'),
('d888b47c-e76b-4336-a5bc-59555f869261','予辛酉春哭鍾松巖於餘杭靈溪壬戌春於江州馬頭渡得家問知田耕月亦爲古人因述長句','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','去春哭鍾子，奔走餘杭路。',120,'全唐诗/poet.song.237000.json','["去春哭鍾子，奔走餘杭路。", "今春哭田生，棲遲九江渡。", "在家在客中，兩友兩春訃。", "伊誰奪天年，有天不可籲。", "老淚無由制，立見眼隔霧。", "風晴江氣暖，日夕山色暮。", "髣髴懐清揚，同遊散幽步。", "百年屈指頃，浮生草頭露。", "憑高悄無人，我鬢亦非故。", "何當歸西湖，往拜二公墓。"]'),
('e009c9ab-0c1a-4ce2-b336-fc6b932182dd','畏風','董嗣杲','宋','宋诗','song-poetry','','[]','病骨怯風寒，懶縱江頭步。',96,'全唐诗/poet.song.237000.json','["病骨怯風寒，懶縱江頭步。", "江頭歸船多，奈我未得渡。", "自知年尚壯，顔髪就衰暮。", "南峯山廬在，窗户掩髙樹。", "猿鶴想凄黯，應笑我出誤。", "欲退未有由，欲進且無路。", "何當探仙源，多織遊山屨。", "顧影忽傷憐，難縛歲月住。"]'),
('af970f99-e69b-496f-836f-78e602c2ba4e','讀舊書有感','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','生髪未燥時，朝晚將書劬。',144,'全唐诗/poet.song.237000.json','["生髪未燥時，朝晚將書劬。", "意可掇髙科，措世躋唐虞。", "安知齒年壯，爲計堕拙迂。", "依人遊四方，骨骼甚鶴臞。", "孤坐苦病嬰，浪走遭時拘。", "哀哉踸踔蹤，誰念嵇紹孤。", "傍新謾利口，温故真良圖。", "信歸簡編香，字字不我誣。", "饑食托飯鉢，渇飲藉水盂。", "聊以適吾天，貧富斯何殊。", "恃書志愈堅，亟返南山隅。", "歸途休云遥，長宵夢西湖。"]'),
('8892463a-4375-4870-a419-6cbc1b51b301','泊黄家渡','董嗣杲','宋','宋诗','song-poetry','','[]','艤舟黄家沙，尋酒聊自慰。',216,'全唐诗/poet.song.237000.json','["艤舟黄家沙，尋酒聊自慰。", "麥田裊露梢，果林飽霜味。", "江色射逃屋，燈焰爥斷緯。", "徘徊强展眺，清風襲腸胃。", "飲暢人痛快，說醉言不諱。", "居人甘淡薄，那復羡榮貴。", "但知安麤糲，了不辨涇渭。", "年豐村畽樂，排憂豈無謂。", "抱衾坐終夕，無事啓憤悱。", "清晨過隣舍，童孺見我畏。", "時艱賦斂重，租外有百費。", "徐徐亟開喻，喻極轉歔欷。", "自来聞打門，如冒鼎鑊沸。", "我遊興未盡，兩眼渺萬彙。", "鄰翁意度真，愛我饋饔餼。", "北風吹沙暗，大地雪積未。", "我衰易成悲，肉戰若刺蝟。", "何時洗紛争，海宇方吐氣。"]'),
('30ad002c-4791-49ae-a13d-0872c7e788d6','清虚閑步有詢吳靈耀近履者','董嗣杲','宋','宋诗','song-poetry','','[]','晚風吹山空，閑步策藜杖。',96,'全唐诗/poet.song.237000.json','["晚風吹山空，閑步策藜杖。", "紆從砂澗頭，行過崖石上。", "庵門耀金碧，中覺天地曠。", "神泉夜光燦，禽鳥互酬唱。", "黄冠扣閒趣，發語知不妄。", "因拈故人迹，流輩所欽向。", "我答亦附會，不想失宜當。", "随口誠卒然，聊紀客中况。"]'),
('bdcffbb5-aacd-40c5-96e1-abedce2ecd15','客寄寫興','董嗣杲','宋','宋诗','song-poetry','','[]','平生負奇崛，語出見肝膈。',96,'全唐诗/poet.song.237000.json','["平生負奇崛，語出見肝膈。", "栖栖離故巢，乃作富池客。", "僧廊搘瘦竹，苦吟自相索。", "不恨春雨横，但恨春懐窄。", "百花艷陽吐，枝葉未鮮澤。", "芳草極茸茸，迷盡舊轍迹。", "浮雲蔽江樹，急浪涉津石。", "掩窗引緑樽，暖此身寒瘠。"]'),
('792f37d2-b28b-44ac-8459-e18c6cc38ff5','江行遇風','董嗣杲','宋','宋诗','song-poetry','','[]','風急難開船，髙浪潑銀屋。',96,'全唐诗/poet.song.237000.json','["風急難開船，髙浪潑銀屋。", "下水輙畏之，病篙舌愈縮。", "商人貨物重，久諳風信熟。", "我舟輕抵葉，帆破無完幅。", "歸心劈箭忙，傍晚猶顛狂。", "忽將絮帽披，沙頭尋酒坊。", "欲滯兩三宵，船上無贏糧。", "轉晴頼曉霜，中夜祈彼蒼。"]'),
('6d79f427-1f58-4677-945d-04809797a68e','廬山雜興二首  其一','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','鐘聲警征人，頓者巡溪步。',72,'全唐诗/poet.song.237000.json','["鐘聲警征人，頓者巡溪步。", "轉盼失路頭，紅日生黄霧。", "看松乘西風，蕩此林影趣。", "古翠撲面老，肯放所歷住。", "幽聆采樵怨，薄言向誰訴。", "且復棲野店，低頭解芒屨。"]'),
('da488375-dc5e-4046-850d-03d8f61bab68','廬山雜興二首  其二','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','新橋迤邐去，勝迹遺仙佛。',72,'全唐诗/poet.song.237000.json','["新橋迤邐去，勝迹遺仙佛。", "想像名勝遊，題字尚髣髴。", "失笑我僕痡，偃息松鬰鬰。", "絕景借雲掩，野香趁風拂。", "看山意自消，令人厭簮紱。", "随意幽行清，無緣逢俗物。"]'),
('25a9c8d2-db69-41f7-8d6c-a884b3292414','過銀樹','董嗣杲','宋','宋诗','song-poetry','','[]','買輿過銀樹，水落見潦迹。',96,'全唐诗/poet.song.237000.json','["買輿過銀樹，水落見潦迹。", "殘雪閃斜照，籬落掩魚澤。", "鳥飛山意冥，鴈度水光碧。", "乘興覔酒壚，荒市絕殽核。", "入暮路程杳，寒皸面頰赤。", "時艱人煙稀，終日涉荒僻。", "豈獨慨風景，亦且倦行役。", "茅店投深幽，月明野田白。"]'),
('e25ff45a-d8dc-4036-a2d0-e47e54b07771','江城憶遊廬山逢隠者','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','飯餘睡相魔，啜茶即退舍。',240,'全唐诗/poet.song.237000.json','["飯餘睡相魔，啜茶即退舍。", "支藜强窺園，試此雙不借。", "逐勝思秋初，曾命廬山駕。", "飛瀑醒心眼，流派從空下。", "狂欲誅茅依，可使不知夏。", "披襟納西風，溪風蕩虚榭。", "憑闌眺夐絕，極望大田稼。", "韜光有畸士，相逢頓生訝。", "遺蹤扣地主，頗覺倦邀迓。", "失言徒自咎，其實非予詐。", "山居俗事簡，難律世情嚇。", "歸棲公宇浄，顔髪苦衰謝。", "家遥二千里，托興相慰藉。", "因晤隠者訥，天性兩難亞。", "初非釣虚名，又非求善價。", "束縳全孤貞，老欲就閒暇。", "約畧斯人心，執一不易化。", "眺此五峯雲，矍然發悲咤。", "企脚北窗坐，月漏松葉架。", "無眠親短檠，懐孤嫉遥夜。"]'),
('9b78107f-0555-4ba2-8ca5-28c8f41a9844','自曹家沙風中抛江危甚抵銅陵縣','董嗣杲','宋','宋诗','song-poetry','','[]','朔風吹沙昏，聚落風物蕃。',240,'全唐诗/poet.song.237000.json','["朔風吹沙昏，聚落風物蕃。", "劇邑此寄治，零星數軍屯。", "奸狡紛鴈鶩，生殖豐雞豚。", "獵子事兵仗，儒家扄蓽門。", "時聞讀書聲，句讀失討論。", "小舟泊洲虚，入市市不喧。", "何年弓戈戕，覩此驚心魂。", "百里餘幾户，誰肆科調繁。", "邑令率以攝，凋瘵真難言。", "俊佐覔幕檄，不洗部民寃。", "氣象日益靡，莅政幾觸藩。", "野老採野果，倚籬餵病孫。", "逢客乃靳吝，出語妄自尊。", "細故起叱咤，徒御嗤蠻村。", "失笑向此適，窒忿思倒樽。", "雲簇天沍寒，有酒無從温。", "勞生愁萬端，不語將蝨捫。", "深虞弱纜腐，浮寄蘆荻根。", "銅陵只隔江，起矴帆若奔。", "既涉庸自悔，死生歸乾坤。"]'),
('06f74382-cc4f-434a-97ed-71eb37fd1cba','聞鴈有感','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','鴈聲入泬寥，節節傳哀音。',144,'全唐诗/poet.song.237000.json','["鴈聲入泬寥，節節傳哀音。", "哀音不可聽，聽之感中襟。", "客從逺方來，幽憂久攅心。", "始爲饑寒謀，今無可棲林。", "浮生抹電如，休計升與沉。", "奈此口體累，議者何鑠金。", "爲客亦良苦，愁見積葉深。", "壯氣歸消磨，羸病力不任。", "狂走擁虚器，空卧廬山陰。", "蒙頭難禦風，煮盡石鼎葠。", "何時理晴竿，把釣花溪潯。", "思歸未可歸，床蛩自縱吟。"]'),
('a0d4d511-ca82-4fda-88ea-098737dfcc07','晚晴','董嗣杲','宋','宋诗','song-poetry','','[]','空庭斷履跡，江色揺籬門。',144,'全唐诗/poet.song.237000.json','["空庭斷履跡，江色揺籬門。", "夕陽雨忽收，晴意回乾坤。", "水零鷗鷺光，煙淡蘆葦痕。", "逺客此棲遲，敢昧元造恩。", "青衫避骨癯，白髪笑鏡昏。", "向來期嬰鱗，今委荒池村。", "眼枯莫制淚，夢破多驚魂。", "讀書不得力，乃如泛萍根。", "出門且散步，殊覺身可尊。", "時卷亦時舒，天定理自存。", "難忘懐土思，百年徒聲吞。", "徘徊月魄吐，呼燈倒清樽。"]'),
('c8e18459-7715-40a3-91dc-20dadd0f9175','舟出西門','董嗣杲','宋','宋诗','song-poetry','','[]','扁舟冒冷雨，初出安定門。',96,'全唐诗/poet.song.237000.json','["扁舟冒冷雨，初出安定門。", "天開水墨圖，濃淡迷湖村。", "漁板鬨白晝，廟鐘撞黄昏。", "客船行虚明，天淨水不渾。", "向行數十程，萬愁誰與論。", "去家幸已近，方信萍無根。", "湖歌發夜分，欸乃驚夢魂。", "江行兩月餘，不負惟酒樽。"]'),
('90ac1483-0fe3-418e-83bb-bb35dfafe69c','春遊','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','江城趁春遊，愛尋郭外圃。',120,'全唐诗/poet.song.237000.json','["江城趁春遊，愛尋郭外圃。", "煙花羃酒帘，風聲颺商鼓。", "午風蕩江面，兵船問沙浦。", "浦斷官柳陰，絮雪待晴吐。", "野花媚遊眼，紅白開晴雨。", "誰憐蕩子身，年餘滯江滸。", "徒羡廬山髙，萬峯青可數。", "朝晚挹煙霏，釋盡客懐苦。", "兹辰快移步，突覺沈痾愈。", "樹頭叫歸禽，流年如箭羽。"]'),
('50e2eb54-f3b4-4f55-9110-ad65da8858c0','過新橋','董嗣杲','宋','宋诗','song-poetry','','[]','江城局吟思，每覺心神悄。',96,'全唐诗/poet.song.237000.json','["江城局吟思，每覺心神悄。", "意行西郊曠，直渡新橋小。", "香傳酒壚異，枕此清溪窈。", "南望元公塋，峩峩翠林杪。", "宰木屯髙陰，牌門燦華表。", "風霜二百年，剥落幾昏曉。", "我來增敬心，道脉伊誰紹。", "有淚盈衣巾，舉頭聞蜀鳥。"]'),
('474003db-f472-45fb-95c0-56cead0a1a50','新橋上岸','董嗣杲','宋','宋诗','song-poetry','','[]','雨陰忽收霽，雲氣失閉封。',120,'全唐诗/poet.song.237000.json','["雨陰忽收霽，雲氣失閉封。", "纔轉横里港，西睨南北峯。", "似慰畸人歸，天亦開喜容。", "萬僝與萬僽，銷鑠無留蹤。", "近京村舍盛，年豐多堯農。", "門户餖飣新，團圞傲窮冬。", "北城入望邇，瑞靄何蔥蘢。", "敗筆亟收拾，不須寫心胸。", "入闗至急需，衣斷須先縫。", "南山故業在，此去羞迎逢。"]'),
('b5565332-16a1-4797-aa3f-efca24f1746e','梅根港欲泊不泊其况可想','董嗣杲','宋','宋诗','song-poetry','','[]','梅港絕梅根，渺莽蘆與荻。',144,'全唐诗/poet.song.237000.json','["梅港絕梅根，渺莽蘆與荻。", "蘆荻揺北風，正逢霜雪激。", "岸津只兩家，泥草落四壁。", "何人舟欲進，想懼少遮羃。", "我舟强來依，無故此涉歷。", "所嗟浮寄人，見舟甚仇敵。", "其說自和易，舉柱累梳剔。", "舟子自髙鶱，呼月吹短笛。", "同行更迂曠，索瓶倒餘瀝。", "渾忘值危途，去住尚怵愓。", "膽消羈思苦，此際誰拯溺。", "慳囊縱有金，斗升何處糴。"]'),
('a1eee2de-b5aa-4bd5-8b87-761f4a380129','次趙屯','董嗣杲','宋','宋诗','song-poetry','','[]','船沿江北行，不見江邉樹。',192,'全唐诗/poet.song.237000.json','["船沿江北行，不見江邉樹。", "颯颯蘆葦空，棲鴈泣如訴。", "波濤極衝撞，沙岸已頽仆。", "東傍趙屯來，結茅是誰住。", "簷破炊煙散，豈足禦風露。", "小兒索午飯，病婦織芒屨。", "良人糴米出，煙江未明度。", "妻兒久待歸，頸佇想回路。", "今年遷避早，寒衣不曾具。", "薄業何能問，苟且遣朝暮。", "此地多遺基，向也盛生聚。", "闗洛幾時清，徒激衝冠怒。", "客子重吁嗟，半世多窘步。", "無位進瞽言，慨此歲月誤。", "有地不可耕，有天不可籲。", "抆淚歸來休，三徑想如故。"]'),
('23228f7d-73d2-4885-81ad-cd11f01c250d','夕憇西林寺詩','董嗣杲','宋','宋诗','song-poetry','','[]','憶發德化門，飽看屏風疊。',120,'全唐诗/poet.song.237000.json','["憶發德化門，飽看屏風疊。", "五峯自孱絕，兩脚誰登躡。", "山髙白日暗，溪斷清泉接。", "閒倚迸崖松，静踏粘露葉。", "珠台勢巍巍，玉斗光燁燁。", "撞鐘警三生，聽禽愁百摺。", "聖峯足眺望，禪觀宜妥帖。", "髙蹈忘俗緣，迥處離塵劫。", "廢塔任敧仄，古碣尚岌嶪。", "歸詢打碑人，摹向齋壁貼。"]'),
('017fff9d-e411-4e4f-848f-581fb780a394','雨飲無殽','董嗣杲','宋','宋诗','song-poetry','','[]','昉見歲律更，不覺春醉厭。',96,'全唐诗/poet.song.237000.json','["昉見歲律更，不覺春醉厭。", "都來九十日，多被風雨占。", "鳴鳩肯停喚，誰測陰晴騐。", "欲問陌上花，花枝無絕艶。", "東風吹柳煙，羃緑波瀲灔。", "客子癡不歸，挂壁羞琴劍。", "獨有遊山盟，未能得斷念。", "夜飲嘆百拙，飣坐果殽欠。"]'),
('de097496-8e0e-4cc5-85bf-1f2d4d08ff5a','暑夜露飲','董嗣杲','宋','宋诗','song-poetry','','[]','夜步閑階長，月出照獨立。',96,'全唐诗/poet.song.237000.json','["夜步閑階長，月出照獨立。", "禦暑借盃酌，便欲和月吸。", "野童笑不已，散髪風露襲。", "浮生彈指頃，能幾尋勝集。", "何當脫塵垢，江湖負蓑笠。", "心知臨淵翁，豈在得魚急。", "浩歌滄浪吟，續此思雅什。", "相從苦無人，眼睨星河濕。"]'),
('9b2fa9ab-9107-4d04-bd88-7ee65be91222','飲王倅宅','董嗣杲','宋','宋诗','song-poetry','','[]','聚散有定數，悲歡能幾年。',96,'全唐诗/poet.song.237000.json','["聚散有定數，悲歡能幾年。", "年年塞鴻來，葉落霜滿天。", "黄昏癡兒閒，强勉陪秋筵。", "歲月流水外，江湖短燈前。", "載聆金玉清，未信造物偏。", "濟勝亦罕逢，思歸心謾懸。", "情深轉眷戀，不語却自憐。", "我盡今日醉，拚得三晝眠。"]'),
('43c14c67-8911-4051-88c7-afc6505ae0a0','舟發','董嗣杲','宋','宋诗','song-poetry','','[]','萬愁聚眼底，城下登江船。',144,'全唐诗/poet.song.237000.json','["萬愁聚眼底，城下登江船。", "江窮渺渺如，身堕栖栖然。", "初來情頗濃，既去情尤牽。", "縱目入虚空，順濟皆由天。", "回思發程艱，時刻多迍邅。", "本無鎮浮能，意者造物憐。", "造物相始終，百歲亦可延。", "風花鼓雪霰，飛舞帆幅前。", "未行風還嚴，既離浪更顛。", "薄命亦何辜，動自罹驚弦。", "逢人不須說，徒招譏孤鶱。", "醉歌赤壁遊，遐眺追坡仙。"]'),
('c2ce2cc8-8081-4949-abd8-469bb70e2efd','清明日晚陰','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','跧伏性易屈，口强心無主。',96,'全唐诗/poet.song.237000.json','["跧伏性易屈，口强心無主。", "今日屆清明，此身客湓浦。", "花草各自芳，誰能問園圃。", "客懐值佳時，冶遊有何覩。", "江頭風颺花，天際雲興雨。", "陰沍嘆時遷，集條燕羞舞。", "世故堕煎熬，鄉愁渺終古。", "柳色西湖隄，初更尚簫鼓。"]'),
('0b488a5c-b214-4722-9470-88afd6990c79','客來得鄰人携酒共飲','董嗣杲','宋','宋诗','song-poetry','','[]','我無膚寸能，强顔榷茶課。',96,'全唐诗/poet.song.237000.json','["我無膚寸能，强顔榷茶課。", "若是玉川子，見之生饞唾。", "客來無可款，談空面壁坐。", "雷聲繞枯腸，啜茶寧忍餓。", "鄰翁好奇甚，携酒爲我過。", "醉我我客共，随覺詩膽大。", "雲烟燦盈幅，意逺不可和。", "客去忘羈愁，寒燈照髙卧。"]'),
('ec48d8e8-7042-4400-9561-70a9c02621cd','早泊江城三首  其一','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','俗務脱始輕，病體自然愈。',48,'全唐诗/poet.song.237000.json','["俗務脱始輕，病體自然愈。", "今朝泊船早，消揺大江滸。", "前林青芒回，衆芳錦唇吐。", "廬山知幾峯，閒背曉星數。"]'),
('d31f1dd1-6e7b-4044-ba79-8fcee06377d0','早泊江城三首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','下江逢好春，入城賞新霽。',48,'全唐诗/poet.song.237000.json','["下江逢好春，入城賞新霽。", "千花春有機，四望天無際。", "老篙不語還，晦跡得少憇。", "登覽且窮探，豈顧跋涉滯。"]'),
('1bed4c4d-ec57-4477-9b76-9e88a80bec6d','早泊江城三首  其三','董嗣杲','宋','宋诗','song-poetry','','[]','歸棲藉知舊，相視絕秦越。',48,'全唐诗/poet.song.237000.json','["歸棲藉知舊，相視絕秦越。", "無言嘆生浮，塵鞅磨歲月。", "數時苦馳騖，百計學休歇。", "芒鞋走廬峯，掀泥挑笋蕨。"]'),
('84862c17-3f56-4352-b1c6-87b22c2a9841','漁郎','董嗣杲','宋','宋诗','song-poetry','','[]','儒者困章句，負抱希聖賢。',168,'全唐诗/poet.song.237000.json','["儒者困章句，負抱希聖賢。", "披緇談虚空，要悟西方禪。", "仙人說金丹，飛步學長年。", "三者亦何心，不過壽所傳。", "爭如打魚人，心契太古前。", "萬事絕無想，生計歸小船。", "晴逐白鷗去，夜傍黄蘆眠。", "青莎紉短衣，備在風雨先。", "得魚不上岸，博酒不博錢。", "相牽醉妻兒，短笛吹空煙。", "桃源共楚澤，枉爲時所憐。", "行路苦信脚，負載多赬肩。", "夕陽下西山，水雲渺無邉。", "我欲從之遊，浩歌樂其天。"]'),
('9b67c9f8-51bc-4d00-8881-f753973d0445','晚步卷雪樓基上','董嗣杲','宋','宋诗','song-poetry','','[]','客中避塵喧，惟尋幽夐憇。',96,'全唐诗/poet.song.237000.json','["客中避塵喧，惟尋幽夐憇。", "扶行趁斜日，晚色蕩沙際。", "漁湖盡數罟，營利若聚蚋。", "水退江岸落，天寒民屋敝。", "萬景眩朝暮，聊足供凝睇。", "雪翻虛空濤，吐氣嫉吞噬。", "臨江舊有樓，興吳誰此誓。", "雲樹掩荒基，靈烏趁船祭。"]'),
('0b1d2f6b-2932-4ab5-b20f-a6cda8bd4e74','廬山中聞桂香憶遊茅山時夢中遊桂花下','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我遊三茅山，月下丹光麗。',144,'全唐诗/poet.song.237000.json','["我遊三茅山，月下丹光麗。", "夢駕翠蜺車，涼雲擁金袂。", "兩耳波浪透，廣漠不可際。", "猶記摶扶揺，乘風曾問帝。", "今秋遊匡廬，身有飛舉勢。", "淩虚裹白雲，白雲鎮相衛。", "毛髪極森竦，草木露華綴。", "飛泉湧潮響，真可滌昏滯。", "向來句曲行，有遇抑何鋭。", "豈知凡骨癯，不能於彼蛻。", "西風催此遊，破我夢浮世。", "衣襟被月香，蒼巖折丹桂。"]'),
('17def726-4fc9-4fce-85de-1309318cd07b','登城樓','董嗣杲','宋','宋诗','song-poetry','','[]','登臨慰兩眼，不暇顧炎天。',120,'全唐诗/poet.song.237000.json','["登臨慰兩眼，不暇顧炎天。", "萬頃大江水，枕壓城郭邉。", "沙際少漁鼓，岸曲紛商船。", "洪波沸赤日，碧樹沈蒼煙。", "行客迷古道，遊塵眯囂廛。", "偉哉乾坤秀，聚此樓觀前。", "夕雨濯暑煩，便覺體欲仙。", "山光已滴滴，月色何娟娟。", "更深天宇净，燈火照管絃。", "歸去抱涼睡，夢裏嗟流年。"]'),
('0bb444bb-1112-4517-b737-7e4889cea523','程申叔來備言近况因與之飲','董嗣杲','宋','宋诗','song-poetry','','[]','程子過我廬，俛首發悲歎。',180,'全唐诗/poet.song.237000.json','["程子過我廬，俛首發悲歎。", "前年遭兵火，故業委塗炭。", "鄉邦更疫癘，骨肉盡離散。", "不覺兩春度，夢中度昏旦。", "昔仰茶園給，到此復牽絆。", "山荒不可摘，舊引莫反汗。", "掛官名籍在，催期有虚案。", "出江既無力，安得便離岸。", "東奔又西走，蹤跡甚鼠竄。", "我今語程子，不消苦疑難。", "爲生固艱苦，得利亦浩瀚。", "逢時縱艱險，當作順境看。", "今夜月色朗，誰將眼界換。", "呼酒聮吟句，失笑兩醉漢。", "棹舟過槃塘，身世入汗漫。"]'),
('c8033662-811f-48b7-917e-26df12c77969','飲黄池朱友龍舍','董嗣杲','宋','宋诗','song-poetry','','[]','換舟入裏港，那懼江風横。',168,'全唐诗/poet.song.237000.json','["換舟入裏港，那懼江風横。", "今夕月色朗，天下呈圓鏡。", "小艤蕃庶鄉，夜燈萬星映。", "倐逢可人情，立論不失正。", "揮毫喜相譽，筆勢自遒勁。", "酒壺不住盪，斟酌各取性。", "不强亦不辭，此醉頗入聖。", "江行苦波劫，到此昉相慶。", "豈知接談笑，春生絕囂競。", "賓筵接幾夜，殽饌抑何盛。", "酒酣月更明，拭眼萬境淨。", "清歡慰旅瑣，四體都忘病。", "怪我當此時，吻噤絕嘯詠。", "夜影横窗殊，窗外梅花靚。"]'),
('5600295b-9cab-440b-9666-76d96055c16e','舟上晚望庾樓  其一','董嗣杲','宋','宋诗','song-poetry','','[]','大江雪月燦，維舟畧無憚。',48,'全唐诗/poet.song.237000.json','["大江雪月燦，維舟畧無憚。", "天地開畫圖，付與快士看。", "幾聲塞北鴻，千里江南岸。", "篷窗引醉吟，搔首待平旦。"]'),
('799f5cf1-9143-4c87-88ae-bdc93c831b11','舟上晚望庾樓  其二','董嗣杲','宋','宋诗','song-poetry','','[]','每依小港泊，地名莫能審。',48,'全唐诗/poet.song.237000.json','["每依小港泊，地名莫能審。", "纔逢江面寛，豈顧風色凛。", "眺空强禁寒，破浪可痛飲。", "醉極忍凍眠，濤聲拍孤枕。"]'),
('307cefc9-c91d-465d-8497-b3b333dabf9b','舟上晚望庾樓  其三','董嗣杲','宋','宋诗','song-poetry','','[]','風順掠口岸，直覺市聲沸。',48,'全唐诗/poet.song.237000.json','["風順掠口岸，直覺市聲沸。", "轉瞬西門髙，晚色羃江氣。", "醉誦琵琶行，寄興豈無謂。", "撼揺黄蘆津，誰知此風味。"]'),
('38c90a40-cd30-40aa-a4cb-fa9ce02aa0f5','舟上晚望庾樓  其四','董嗣杲','宋','宋诗','song-poetry','','[]','跨城作州治，陰晴巧變幻。',48,'全唐诗/poet.song.237000.json','["跨城作州治，陰晴巧變幻。", "廬峯翠色老，逐日供逺盼。", "白雲擘碎綿，随地卷舒慣。", "春先紫烟樓，梅花雪前綻。"]'),
('12a182cf-aecc-4d90-a54f-f162efaa7b6c','吳李制屬同寓富池雙泉寺畏寒索飲因寫真愫','董嗣杲','宋','宋诗','song-poetry','','[]','秋扇已棄物，寒衣還催装。',168,'全唐诗/poet.song.237000.json','["秋扇已棄物，寒衣還催装。", "偃息覺寒侵，客况入渺茫。", "宿疢不時作，難恃筋力强。", "畏熱亦畏寒，此固人之常。", "今此露寒初，畏縮尤周章。", "共君蟄寺樓，雨話幾對床。", "布褐莫禁風，芒鞋莫抵霜。", "無聊思往時，意愜交秋涼。", "散髪醉瑶臺，濯足歌滄浪。", "悲涼所不識，安知有摧傷。", "鄰家濁酒香，鄰僧不住嘗。", "亟沽兩甆罎，連倒澆酸腸。", "敵寒固尚賒，姑遣秋宵長。", "少年挽不來，烏兔有底忙。"]'),
('1c0a7c81-7228-44b7-a8b4-eca5ee278de7','行興國宫前市中','董嗣杲','宋','宋诗','song-poetry','','[]','聚落風物古，環住神仙麓。',96,'全唐诗/poet.song.237000.json','["聚落風物古，環住神仙麓。", "魚鹽無多腥，蔬茹有餘馥。", "彼此通有無，朝昏事樵牧。", "罷市不待晚，飽聽溪聲熟。", "扶携醉山醪，醉去觀飛瀑。", "斯人甘翛翛，其識不碌碌。", "生來分已定，痛撫時光速。", "容我尋梯媒，横溪結吟屋。"]'),
('8d02d0e5-9e31-4cf5-8088-25aa0f1bb870','過林口市','董嗣杲','宋','宋诗','song-poetry','','[]','浮泥踏着軟，危坡倩誰累。',120,'全唐诗/poet.song.237000.json','["浮泥踏着軟，危坡倩誰累。", "家家翠嵐壓，此是林口市。", "山中何清孤，聚落頗填委。", "快果甘如飴，濁醪淡如水。", "祇是石眼泉，聊慰行子齒。", "此景自獻酬，此市亦清美。", "紛紜趁墟者，未曉聽鐘起。", "盛傳有畸翁，韜晦翠樾裏。", "姓名素不聞，十載安所止。", "多言風月夜，吟嘯傳逺邇。"]'),
('7e8fec37-5b52-4a77-8489-db070e3735f3','横峯港','董嗣杲','宋','宋诗','song-poetry','','[]','日落大江滸，苦無多人煙。',96,'全唐诗/poet.song.237000.json','["日落大江滸，苦無多人煙。", "風湍鳴耳根，饑鴈聲相聯。", "雪止月未上，境界太古前。", "天低平接水，水逺遥粘天。", "横峯港頭棲，客子心膽懸。", "四面渺不極，纜樹對我船。", "萬慮集雙鬢，顧影空自憐。", "哀哉行役苦，收拾歸短篇。"]'),
('db3c6af3-a938-47de-a12b-69b0f325c6a4','雨泊蘄州岸下','董嗣杲','宋','宋诗','song-poetry','','[]','連日雨滯留，孤舟坐寂歴。',96,'全唐诗/poet.song.237000.json','["連日雨滯留，孤舟坐寂歴。", "自量迂亦甚，托人尋竹笛。", "展轉耗音絕，失笑何陷溺。", "無計遣羈懐，傾壺倒餘瀝。", "小醉自不惡，篷窗未收滴。", "天陰鶴忽鳴，何時離赤壁。", "狂疑明月出，移舟出蘆荻。", "浩歌蘓仙吟，破此夜寥閴。"]'),
('17ac333a-1362-43fe-afe5-8ca0c0a3cd4c','過蘄州  其一','董嗣杲','宋','宋诗','song-poetry','','[]','清霜染岸楓，扁舟渡蘄水。',72,'全唐诗/poet.song.237000.json','["清霜染岸楓，扁舟渡蘄水。", "蘄城傍新築，無此至堅壘。", "誰憐多病苦，委命空江裏。", "艱險已備嘗，萬事謹謀始。", "追憶數年前，精神豈今比。", "酸辛賦逺遊，晚泊問沙觜。"]'),
('345ef82b-f3b1-412d-83fe-4ee71c169145','過蘄州  其二','董嗣杲','宋','宋诗','song-poetry','','[]','遊趙提幹園，有亭可洗心。',126,'全唐诗/poet.song.237000.json','["遊趙提幹園，有亭可洗心。", "亟應招呼命，蠧葉下井枯。", "空江鼓風勁，幸藉賢主人。", "尋勝愁盡屏，平生性不汚。", "惟喜眼界浄，笑睨斑竹林。", "金商遞聲應，古桂香何遲。", "黄花色最正，何當過栗里。", "把酒酹陶令，行矣又他適。", "孱質莫任病，酒酣喜索句。", "鬢改羞對鏡，寒蛩咽青莎，難制客淚迸。"]'),
('caee7ed6-a45f-40b8-956b-81e532706c95','泊江城下','董嗣杲','宋','宋诗','song-poetry','','[]','雪後抵江城，江雲轉凝沍。',96,'全唐诗/poet.song.237000.json','["雪後抵江城，江雲轉凝沍。", "我舟艤沙淺，煮酒禦沉霧。", "少年繆誤多，今繆亦如故。", "流年無藥挽，如水必東注。", "失笑白司馬，曾與商婦遇。", "空亭自水際，知機有飛鷺。", "懐想何能已，坐見暝色赴。", "襆被且入郛，衰顔更遲暮。"]'),
('b2cc8788-b9b6-4ee5-8927-d8f9585e2be1','過琴齋','董嗣杲','宋','宋诗','song-poetry','','[]','乘閒過琴齋，作意登漪嵐。',120,'全唐诗/poet.song.237000.json','["乘閒過琴齋，作意登漪嵐。", "棠湖漾其北，紫霄聳其南。", "闌干壓池芳，渌淨拖柔藍。", "行人冒遊塵，名利多沉酣。", "盡傾滄江水，莫洗濁世貪。", "出羣趙家玉，吏此長子男。", "臺府嚴且明，舉動百不堪。", "臨流自照心，謀飽無肥甘。", "景物固爾佳，何暇同清談。", "買舟過柴桑，東歸面無慙。"]'),
('efbc5ca4-8370-4bca-a56a-b48857ec1b15','下江','董嗣杲','宋','宋诗','song-poetry','','[]','下江值雲簇，水色透沙清。',120,'全唐诗/poet.song.237000.json','["下江值雲簇，水色透沙清。", "挂席風勢烈，兩岸無人行。", "野市門多闗，久絕鷄犬聲。", "時勢驅之然，茫昧嗟予生。", "興懐孤山人，種梅千古名。", "浮榮夢幻耳，世事春雲輕。", "鄰船羞小鮮，佐以紅酒烹。", "欣然暖曲身，慨此奔走情。", "退省毋悠悠，進寸徒營營。", "拄笏看西山，歸來有時成。"]'),
('804642f2-d248-4d04-bc05-a85476ef26d4','中伏','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','五世單丁家，在家亦如客。',96,'全唐诗/poet.song.237000.json','["五世單丁家，在家亦如客。", "悲歡惱客抱，每恨江海窄。", "今日初伏過，浴出易絺綌。", "樹頭來禽熟，隔水不可摘。", "明年西湖去，凉雲簮藉白。", "此時且健飯，寧耐朱炎赫。", "淮童少解事，醉拾西瓜擘。", "强笑領其真，寓吟自成癖。"]'),
('d310b596-eb47-4e53-bc5c-91dcd03e8fc2','廬山折桂一枝','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','風露木葉飛，崖谷清氣足。',72,'全唐诗/poet.song.237000.json','["風露木葉飛，崖谷清氣足。", "不知月中花，幾番破粟玉。", "深巖得秋易，香味真絕俗。", "幽人領此妙，况寄虎溪曲。", "花放怯衣單，祗嘆歲時促。", "折來浸瓦瓶，夜賞欠醽醁。"]'),
('40255617-ec5f-4cb0-8149-7bb30706f097','送李制屬入蜀','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','君從甬水來，我棄西湖走。',168,'全唐诗/poet.song.237000.json','["君從甬水來，我棄西湖走。", "共入九江城，又客富池久。", "相照道義心，不數膠漆友。", "所嗟跡漂萍，每爲世味誘。", "云何忽舍我，倉卒舉别酒。", "風霜七千里，勇往膽如斗。", "遡流幾換舟，大緊上峽口。", "誰謂此程迂，機會諒非偶。", "功名快着力，豈暇殢株守。", "西陲江山程，大閫人物藪。", "不日膽略舒，金印落吾手。", "此别不勝難，臨别忍回首。", "繼此旅中交，如君不復有。", "大笑憑江樓，折贈江頭柳。"]'),
('2cd02ff9-166f-42b7-8fd5-cfcc8439d91a','雨凉','董嗣杲','宋','宋诗','song-poetry','','[]','客中貧莫支，萬事付不理。',96,'全唐诗/poet.song.237000.json','["客中貧莫支，萬事付不理。", "今秋易覺寒，雨意猶未止。", "青青梧桐樹，蠧葉浮井水。", "秋來未爲久，俗塵已披靡。", "夜分無眠處，西風裂窗紙。", "茸裘蚤闗心，奈爲病軀使。", "雲開天宇淨，晴霞散餘綺。", "却扇披野衣，出門扣知已。"]'),
('f7f4a77f-8b4e-4e28-91bb-d738f661631d','黄池與朱一夔偕一老商款曲連日','董嗣杲','宋','宋诗','song-poetry','','[]','共客黄池鎮，各從上江來。',96,'全唐诗/poet.song.237000.json','["共客黄池鎮，各從上江來。", "恓惶見談態，僦屋傍古槐。", "商人接殷勤，期我不世才。", "曉風吹寒江，雪意又有媒。", "隔水界宣城，山路多早梅。", "旅瑣逢此清，問渡休徘徊。", "梅梢月色佳，僧房羅酒罍。", "商人亦何心，兩日相追陪。"]'),
('8e388115-a395-446e-8d83-4305e9d6df78','返察磯回望九華','董嗣杲','宋','宋诗','song-poetry','','[]','日落返察磯，無地可卓笻。',96,'全唐诗/poet.song.237000.json','["日落返察磯，無地可卓笻。", "回首池陽山，九朵金芙蓉。", "溪流出港急，樹色收雲封。", "行客快兩目，欲遊悔無從。", "依依此時心，維舟當要衝。", "山遊形夢寐，夢覺聽遥鐘。", "應有神仙居，隔此江水重。", "移棹近荻港，月出霜華濃。"]'),
('63e4256d-2a1f-40c3-b9ef-4b084bbfda2a','遊東林寺','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山白雲擁，絕似兜羅綿。',216,'全唐诗/poet.song.237000.json','["廬山白雲擁，絕似兜羅綿。", "覆得醜好盡，何啻萬萬千。", "東林香爐峯，生在寺門前。", "山陰土脉潤，草木鳴秋妍。", "意行梵廡曠，單下誰棲禪。", "主僧淮東秀，眉目稜稜然。", "談麈自髙蹈，往往來著邉。", "我遊欲結社，有愧逺師蓮。", "草堂流水環，遺像儼樂天。", "西風號萬杉，趺坐青石顛。", "野老喜我陪，談吟超極玄。", "上方僧謾多，多結粥飯緣。", "方且局諸妄，焉得安三椽。", "浮生忘有家，妙句知無傳。", "塵垢送短日，風霜侵頹年。", "斜陽透西樹，獨支竹笻堅。", "鐘鳴擬尋睡，酒至流饞涎。", "月上三笑亭，醉聽漁家眠。"]'),
('b8068d39-e9e2-46b0-96e7-efd503d233b1','重約遊山','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','江州廬山陰，萬象藴奇祕。',144,'全唐诗/poet.song.237000.json','["江州廬山陰，萬象藴奇祕。", "笑扶鬼面行，趁雲步幽邃。", "虎迹過溪明，龍氣蟠松翠。", "香爐紫烟合，燦若金布地。", "諸佛妙莊嚴，千燈燭魑魅。", "向來逺法師，絕識具聖智。", "白蓮曾結社，今古想標致。", "客子徒仰髙，可望不可企。", "山頭日落易，木陰混清閟。", "野禽叫瀑頂，預知夜無寐。", "懐抱挹仙芬，欲將世情棄。", "斯遊會重尋，直待涼風至。"]'),
('f2064dd9-e048-4736-9488-bf6dd1c459a6','酒邉見燒各賦一體','董嗣杲','宋','宋诗','song-poetry','','[]','淮山燒色起，陰剥應期約。',168,'全唐诗/poet.song.237000.json','["淮山燒色起，陰剥應期約。", "開闢界限定，蠧根不藉钁。", "焦枯燼無蹤，艷陽春有脚。", "爆烈狐兔竄，驚迫魍魎爍。", "尖危騰斜燄，汊角迸横焯。", "死卉沸沉煙，遊雲避浮虐。", "入夜光尤皎，逮曉焮自若。", "蟄蟲潜穴散，猛虎奔淵躍。", "勢欲凌虚霄，倐忽風掠綽。", "熒熒斷續見，江流颺昭灼。", "青黄數宵隕，何在事采斸。", "逺客詫希遇，俯仰發嘆噱。", "斗杓指東寅，天公又斵削。", "霜氣逼衾重，對眠向溪閣。"]'),
('964a1ae6-d0be-450e-ace0-5e7fc3bb868d','寓江州分司衙随筆五首  其一','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','街聲崇墉隔，畏客陶詩興。',72,'全唐诗/poet.song.237000.json','["街聲崇墉隔，畏客陶詩興。", "枯梅三兩株，僅有枝條剩。", "斜暉卧竹棚，疊蘚覆石磴。", "始來覬聮属，久去歸蹭蹬。", "萬丈廬山髙，苦恨無樓憑。", "此時坐寛凉，忘却船如甑。"]'),
('7f8a3c36-48ba-4607-be00-5169ac4c4cbd','寓江州分司衙随筆五首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','官榷採山利，朝廷責辦重。',72,'全唐诗/poet.song.237000.json','["官榷採山利，朝廷責辦重。", "斂散各有司，設置不爲冗。", "商人突如來，責去不旋踵。", "閒時不飬恬，且絕追胥恐。", "獨嘅無依人，心跡徒距踊。", "何人干共二，望蜀覬光寵。"]'),
('d279e0ef-c887-4949-8d0f-b67a5d6dcc23','寓江州分司衙随筆五首  其三','董嗣杲','宋','宋诗','song-poetry','','[]','閒中望廬阜，稜層翠如櫛。',72,'全唐诗/poet.song.237000.json','["閒中望廬阜，稜層翠如櫛。", "所恨身重累，莫學飛舉術。", "逺眺曉雲障，横截山半出。", "其下瞰蒼流，其上爍紅日。", "奇譎千萬狀，雲行自徐疾。", "江風忽西吹，雲氣轉頭失。"]'),
('0717ae1d-9fc6-4d58-84cd-656ddc76026b','寓江州分司衙随筆五首  其四','董嗣杲','宋','宋诗','song-poetry','','[]','前憂將盡捐，後慮方覺夥。',72,'全唐诗/poet.song.237000.json','["前憂將盡捐，後慮方覺夥。", "舉動必有礙，側近類鼈跛。", "但知就酸吟，不悔爲計左。", "秋令向老去，甘困樊籠鎻。", "愁境畏風波，慵捩秋江柁。", "四顧無可尋，白日醉白堕。"]'),
('1e3ad5e5-54f1-410d-b32f-2fb6520b1d30','寓江州分司衙随筆五首  其五','董嗣杲','宋','宋诗','song-poetry','','[]','掀簾掣吾肘，偶牽衫袖裂。',72,'全唐诗/poet.song.237000.json','["掀簾掣吾肘，偶牽衫袖裂。", "腐縷積汗垢，欲紉向誰說。", "忙起易衣披，不暇惜疊雪。", "試新反相惱，轉覺身觸熱。", "天凉日漸深，裝寒逼時節。", "身章素不尚，臨事轉添拙。"]'),
('71292335-2a8b-4a8a-bfc6-1f6799bae2ab','壬戌閏重九客中寫夢','董嗣杲','宋','宋诗','song-poetry','','[]','今日閏月九，重新做重陽。',264,'全唐诗/poet.song.237000.json','["今日閏月九，重新做重陽。", "東籬賸有花，金黄熨晚香。", "大江東下處，其地爲柴桑。", "靖節餘真祠，祠下荆棘荒。", "想像義熙年，此老醉花傍。", "寄情付傲睨，有句哀三良。", "我思前月九，菊蕾初含芳。", "萸氣却綻烈，登髙苦雨妨。", "閏延花盛開，東曦蕩晴光。", "遶徑行已匝，倦去憇竹床。", "逺夢入無何，随雲還故鄉。", "故鄉餘故園，境浄浩莫量。", "仰睇南峯松，俯引北海觴。", "小亭俯溪南，溪聲流宫商。", "兩年身不到，此時夢欲狂。", "夢歸轉無益，夢覺生悲傷。", "浮生能幾度，客久空回腸。", "醒來日已午，尋醉歌滄浪。", "江鮮可斫鱠，笑引杯行長。", "夕暉不相知，眩眼投西岡。", "歡情亦云暫，旅困空相望。", "月出照庾樓，思歸轉徬徨。"]'),
('03d85cf9-e5c5-4057-91f3-f5df761f731d','還彭澤山中早發','董嗣杲','宋','宋诗','song-poetry','','[]','揺落山中曙，秋氣滿林隈。',48,'全唐诗/poet.song.237000.json','["揺落山中曙，秋氣滿林隈。", "螢光映草頭，鳥影出枝來。", "殘星避日盡，斷霞逐風開。", "空返陶潜縣，終無宋玉才。"]'),
('d75564e3-6f4f-4fe7-bdf1-32f7c08e1bb3','清夜偶成','董嗣杲','宋','宋诗','song-poetry','','[]','東林與西林，祗有矮墻隔。',144,'全唐诗/poet.song.237000.json','["東林與西林，祗有矮墻隔。", "逺永共家風，各自立茅棘。", "我遊難盡興，入眼眩金碧。", "孤塔插空斜，萬樹屯雲窄。", "香爐擁烟紫，蓮花照亭白。", "未聞海潮音，多時坐饑迫。", "淮僧心膽麤，迎送勤朝夕。", "疾趨謂有禮，健論本無益。", "誰誇絕俗髙，反事望塵役。", "逆料達者性，冥心滅蹤跡。", "日西亂鳥啼，俯仰閲今昔。", "清遊未遽返，忍冷坐寒石。"]'),
('33696b5f-141f-4513-bd4f-2f5d62cb2032','與徐税過淮民家市果','董嗣杲','宋','宋诗','song-poetry','','[]','寒水落沙洲，随地營送年。',144,'全唐诗/poet.song.237000.json','["寒水落沙洲，随地營送年。", "徐卿邀我行，逺渡呼脚船。", "荒津絕鷄犬，斷籬掩人煙。", "柑梨土民收，飣坐風味全。", "及公出酒甌，提籃寘我前。", "甘香種子異，脆膩色澤妍。", "定價随語準，質直何其堅。", "淮鄉習俗純，處士亦如然。", "閒歷慨流離，百醜皆可憐。", "撫機奈失時，彼此嗟華顛。", "酒酣飫此快，哀歌地爐邉。", "携歸備晚需，雪片蒙江天。"]'),
('dc6ece7a-a988-454f-b9ea-9cccd85e60fc','潯陽館邉泛小舟夷猶沙浦中遇翟違大舟過','董嗣杲','宋','宋诗','song-poetry','','[]','沽來官亭酒，豔流勝琥珀。',96,'全唐诗/poet.song.237000.json','["沽來官亭酒，豔流勝琥珀。", "髙歌大江上，聊以信所適。", "借舟喜逢君，春沙涵潤澤。", "傍沙得鮮鮰，過似河魨白。", "斫鱠搜薑椒，食枯鄙殽核。", "浮陽下峯迅，晚風撼漁磧。", "深洲卸帆處，聞角易喪魄。", "津吏量水痕，兩夜長三尺。"]'),
('c432b9f8-ba11-4641-8091-77f8f77730f7','自富池江入興國軍港留三日歸回舟捷甚摭實寫意','董嗣杲','宋','宋诗','song-poetry','','[]','到此未入郡，入郡由别港。',216,'全唐诗/poet.song.237000.json','["到此未入郡，入郡由别港。", "不意好奇人，黄堂争說項。", "說項非所私，况無適時資。", "驅馳靡所憚，重苦登覧悲。", "開慶擾攘後，民力未通透。", "如斯斗底郡，俗習因仍陋。", "只今良二千，懇惻出心田。", "耕桑匝原野，謡頌周市廛。", "遡舟走麾下，容光託假借。", "坐卧寄酸吟，轉首已三夜。", "將行慰我深，語語吐直心。", "發笑酌我酒，垂情餉我金。", "平生慨可至，毋若此急義。", "忍違離荒津，陸行且無地。", "秋寒筋骨疲，風雨更厄之。", "病亦坐酒困，樂在遇已知。", "下水浩然涉，出港何其捷。", "及門祗霎時，不想無吏接。"]'),
('869568ca-f317-49af-ac34-ec5049180f92','重遊清虚庵','董嗣杲','宋','宋诗','song-poetry','','[]','夏初曾歷此，信宿强舍去。',144,'全唐诗/poet.song.237000.json','["夏初曾歷此，信宿强舍去。", "及其還城中，旅瑣若羈馭。", "凉秋復過時，又坐題詩處。", "黄冠苦相佞，往往多過譽。", "且謂筆力遒，真得鬼神助。", "但將虚名汙，不具實眼覷。", "顧予欲棲止，未有抛茅據。", "難忘整屐遊，贏得寘浮慮。", "地曠實仙源，野步豈宜遽。", "且須窮嵌巖，何在事啖茹。", "祗酌神泉清，垢净不待濾。", "撥雲峯下石，晚霽且箕踞。"]'),
('645ff282-4146-4b17-a80a-33894b55612d','風水僧善用期之不遇','董嗣杲','宋','宋诗','song-poetry','','[]','用僧期不來，子午針頭誤。',120,'全唐诗/poet.song.237000.json','["用僧期不來，子午針頭誤。", "沉迷負所傳，老去眼隔霧。", "言甘說中少，見陋遭時惡。", "三椽當道架，山色翠回互。", "空曠乏人守，有欲絕反顧。", "豈無世事非，何能日如故。", "昨收松下書，欲見展心晤。", "遍尋莫知蹤，望極柏山路。", "馬荒人亦倦，酒熟秋垂暮。", "浮身真是浮，參取折蘆渡。"]'),
('65d33501-bba3-4228-8d7c-89d7558e8ad7','招鐵鏡明上人同舟入京','董嗣杲','宋','宋诗','song-poetry','','[]','蓬麻冒日氣，舟過風遞香。',144,'全唐诗/poet.song.237000.json','["蓬麻冒日氣，舟過風遞香。", "香氣入晚秀，月色迷官塘。", "此時同載僧，眉上生毫光。", "心鏡不待磨，一碧眩四方。", "遂此終夕安，推篷睇渺茫。", "凌晨泊北津，分手各自忙。", "追随遊徑山，奈何吏鞅妨。", "何時重聚首，叙我歌河梁。", "世緣苦聚散，人事多短長。", "興言偶及爾，不覺耿中腸。", "薫風蕩柳煙，吹面無多凉。", "晨曦曬屋裂，獨恨衝塵黄。"]'),
('d0ab6abd-1f93-49e3-bd79-11352f3f1e08','對月','董嗣杲','宋','宋诗','song-poetry','','[]','徙倚短窗下，月色照平地。',96,'全唐诗/poet.song.237000.json','["徙倚短窗下，月色照平地。", "江頭見漁舸，更欲扣舷醉。", "山川藹夕霏，菰蒲顫凉翠。", "景色自紛糅，造化祗兒戲。", "慨嘆幾今古，不過榮與悴。", "胸中難貯愁，萬緣可棄置。", "三更北風暴，頃刻天地異。", "掩窗抱膝吟，欹枕不復睡。"]'),
('61cfbee6-357a-46ad-9a20-ef94ef2709d0','與葛秋巖小園看月','董嗣杲','宋','宋诗','song-poetry','','[]','回峯月魄上，照我方壺寒。',96,'全唐诗/poet.song.237000.json','["回峯月魄上，照我方壺寒。", "軒窗絕四掩，流光壓空闌。", "凉襲荷沼幽，陰寫竹逕乾。", "逺泉助清思，珮聲何珊珊。", "啼鳥寂無聞，何枝能擇安。", "空青閃虚碧，纎翳莫可干。", "有酒此不斟，徒坐夜漏殘。", "相逢此時快，瞠目終宵看。"]'),
('32f803c4-3a3a-456e-ae4d-881c5de0b858','贈接泥渡下李巡檢','董嗣杲','宋','宋诗','song-poetry','','[]','一官坐渡頭，事簡多是閒。',96,'全唐诗/poet.song.237000.json','["一官坐渡頭，事簡多是閒。", "口口說廟靈，祭賽紛强頑。", "逐日享餕餘，贏得酡客顔。", "江風吹不散，借此資身孱。", "俸錢給不多，悔離禁衛班。", "妻子號寒饑，語下嗟間闗。", "俟代尚爾遥，擲珓卜善還。", "随時了應酬，惟恨得酒慳。"]'),
('eb9ea657-1172-42c7-9057-359dd28e206e','山行','董嗣杲','宋','宋诗','song-poetry','','[]','山路本無雨，霧滃露點濕。',72,'全唐诗/poet.song.237000.json','["山路本無雨，霧滃露點濕。", "脚滑幾欲縮，舉步真如縶。", "剉過萬千山，雲磴莫計級。", "更多仙泉甘，潭深絕綆汲。", "力疲骨節酸，逺眺空竚立。", "曠懐無與言，付與詩收拾。"]'),
('871b892d-700d-4c65-9b4e-2f963c7f05b0','銀樹道上客懐  其一','董嗣杲','宋','宋诗','song-poetry','','[]','舟絕顧城湖，始知泊銀樹。',72,'全唐诗/poet.song.237000.json','["舟絕顧城湖，始知泊銀樹。", "脚夫亟裝擔，頓足跋涉懼。", "水行困弊舟，陸出藉芒屨。", "望逺有異觀，山水陶興趣。", "太息足力疲，趁程眠日暮。", "髙價租蹇驢，意欲代吾步。"]'),
('d50d7fac-ce00-4562-affb-694152306f5b','銀樹道上客懐  其二','董嗣杲','宋','宋诗','song-poetry','','[]','破輿不忍登，恐負看山眼。',72,'全唐诗/poet.song.237000.json','["破輿不忍登，恐負看山眼。", "遥程入荒夐，棧道踐𡾰嵼。", "蹇載亦徒勞，登頓資笑莞。", "氣餒不足甦，只得仰酒琖。", "暫免極寒侵，圍春想歌板。", "何當位經綸，盡把凹凸剗。"]'),
('3d9c5f22-1ff4-4acd-850b-7489ab811021','四安乘舟上安吉州','董嗣杲','宋','宋诗','song-poetry','','[]','日出雪意消，雲斂萬山紫。',96,'全唐诗/poet.song.237000.json','["日出雪意消，雲斂萬山紫。", "水步發船人，相競更填委。", "弛擔苦多虞，買渡須謹始。", "向來受摧挫，至今失料理。", "溪南樹陰開，沙上鴻聲起。", "獨行良辛苦，淹留嘆行李。", "寘恨復憐生，歸歟安坎止。", "奔程入湖城，渺茫東門水。"]'),
('3e31ca9f-7b0d-400b-8e11-18ca4442564f','又過妙智寺後因賦','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我貎甚癯棘，極愛山林住。',96,'全唐诗/poet.song.237000.json','["我貎甚癯棘，極愛山林住。", "纔說廬山去，不憚葺芒屨。", "鬰懐得少解，動脚即徤步。", "誰言多岌嶪，堂堂大驛路。", "萬景山渺莽，曠遊愜心慕。", "荒坊偶小憇，周覧入薄暮。", "西隅壁灰淨，半堵若縑素。", "方此欲題名，已觸野僧怒。"]'),
('2e96575b-9091-4137-8fd5-338ea9d4607d','遊盤塘山後廢寺','董嗣杲','宋','宋诗','song-poetry','','[]','前生修行來，見山入骨貪。',120,'全唐诗/poet.song.237000.json','["前生修行來，見山入骨貪。", "自昔盛緇流，無處無精藍。", "大風起江頭，吹我菊帽簮。", "景物日自殊，登頓我所甘。", "青紅夕陽光，隠約埋空嵐。", "矮松冷塵屋，暗燈明破龕。", "好月亦愛人，離雲印寒潭。", "詩壁不待題，禪偈不在談。", "還須蜕浮塵，投林結莎庵。", "平安火一烽，愁可寛江南。"]'),
('f6e95c15-6eac-4877-a63d-b5a5382455f4','舟中對月','董嗣杲','宋','宋诗','song-poetry','','[]','過峽水不清，渾濁甚他處。',144,'全唐诗/poet.song.237000.json','["過峽水不清，渾濁甚他處。", "今朝喜得晴，看月莫猶豫。", "盡力掀篷開，浄着兩眼覷。", "月色更婀娜，炯然洗積慮。", "前磯水衝撞，傳若小灔澦。", "令人厭水程，惟祝江靈助。", "天地境界古，恨無槁梧據。", "餘樽就手瀝，適口乏啖茹。", "囁嚅味自佳，不須勞舉筯。", "醒去掩篷眼，零落故衾絮。", "呼天招仙游，同學列子御。", "儻轉北頭風，穏涉蕪湖去。"]'),
('2b05afe4-7c4e-45f2-92a4-dd792890a2c8','雪後','董嗣杲','宋','宋诗','song-poetry','','[]','雪後江面淨，客子不畏寒。',96,'全唐诗/poet.song.237000.json','["雪後江面淨，客子不畏寒。", "掀篷篷上坐，静見天地寛。", "風平勢未減，小舟蕩渺漫。", "萬里瑩無波，瓊樹幻翠巒。", "大江此勝槩，景與心會難。", "須臾世界殊，月擁白玉槃。", "凡身寄廣漠，酒杯不可乾。", "嚴沍何能禁，醉眠更已殘。"]'),
('dce36756-38f4-40fe-8595-f66a698ff1d4','天池寺夜與主僧覺翁圓上共坐談浯溪山水之勝信筆因贈長句','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','空雲駕我登天池，江山秋渺無津涯。',376,'全唐诗/poet.song.237000.json','["空雲駕我登天池，江山秋渺無津涯。", "涉溪驀棧借杖藜，光景體認歸裁詩。", "崢嶸寺門窩風低，塔鈴喧風際天吹。", "方丈軒檻供毗尼，老僧喜氣揚鬚眉。", "浮屠名紀主簿題，偶拈椽筆書年時。", "秋稜初勁樹葉飛，蜀錦糝綴斜陽枝。", "文殊閣上爇香遲，天燈熒煌放者誰。", "暗中拾取懐袖携。", "一燈一葉光陸離，千古此奇不可知。", "獨此闌干納此奇，月落泉響松籟迷。", "畏寒蚨坐身如癡，覺禪論徤能祛疑。", "傷今悼古涕交頥，自矜夙抱山水資。", "曾爲浯溪强住持，浯溪溪上波渺瀰。", "波濤衝撞天寶碑，寺門廢圯日就衰。", "急拾斷碣分龜支，二水八景猶紛披。", "浮蹤又向廬山羈，殘骸未散挈鉢棲。", "所至殊忍弔迹遺，浯溪誰究稔禍妃。", "有唐立見宗社危，陵廟棄擲奔峩嵋。", "最苦杜陵嗟流移，元郎頌公雅可禆。", "大書紀勒中興辭，讀之憤悱生悽悲。", "平生未采湘江蘺，聞此幽妍空心期。", "覺翁泥古多發揮，逆知流輩莫我追。", "回思太史過浯溪，曾有野僧相追隨。", "儻如覺翁能投機，太史肯以庸目之。"]'),
('7981adf8-959e-46c7-a4ec-37a4f64e2b34','九江驛紀夢歌','董嗣杲','宋','宋诗','song-poetry','','[]','西風吹淨汀洲明，蕭蕭雨荻霜蘆聲。',144,'全唐诗/poet.song.237000.json','["西風吹淨汀洲明，蕭蕭雨荻霜蘆聲。", "江山幻出琉璃屏，誰歌謫傅琵琶行。", "三更月滿十二城，夢超弱水登蓬瀛。", "九派水，九叠山，水水山山錦四環。", "綠羆玄猿守朱闗，雪鶴舞影石臺乾。", "瑶樹琪花不可攀，花上結子千歲慳。", "花子錯落魚鱗斑，踐幽濟勝清肺肝。", "回首空睨雙雲鬟，蘿香點漬衣袂寒。", "不覺罡風吹倒還，瓊跳璧濺鳴珊珊。"]'),
('cf929cf8-1476-4cc2-85df-4db85585a01f','録秋日藁因寫客况寄王倅昆仲仲亦曾任衡倅','董嗣杲','宋','宋诗','song-poetry','','[]','富池羈客吟窮秋，吟成寫出還包羞。',160,'全唐诗/poet.song.237000.json','["富池羈客吟窮秋，吟成寫出還包羞。", "王家兄弟領此幽，識邁子瞻與子由。", "欲織寒江無機收，兩眼逺睨邉烽樓。", "前時水頽岸不修，今日雲族蒙荒洲。", "洲上秃樹葉不留，丹纈都漬泥塗浮。", "燒薪晚煮雲子柔，方纔落斧鳴潮頭。", "欲填饑腹消客愁，飽時熟睡迷荘周。", "蝴蝶夢破嗟年流，不觧俯首尋茶甌。", "飛鴻整陣聲何遒，憶君金玉孰可侔。", "自期雪夜訪君遊，乘興肯遜山陰舟。"]'),
('b7fd1d69-c1e2-48ad-a702-58a969635e42','寄程申叔','董嗣杲','宋','宋诗','song-poetry','','[]','奇才不泯揚馬名，善政況著龔黄績。',128,'全唐诗/poet.song.237000.json','["奇才不泯揚馬名，善政況著龔黄績。", "政績才名分外榮，山林意趣無方覔。", "人生富貴骨相中，何須强力争豪雄。", "三光五岳蟠心胸，歲寒春色梅花風。", "我有小隠傍石屋，石上幾回斸黄獨。", "看來我已不啻足，何事攅眉勞案牘。", "程子談何不碌碌，古意今情兩堪掬。", "歸與歸與毋忍辱，同尋牧童過天竺。"]'),
('ef641868-5292-41e7-aeb2-827781fb6d1b','初至江城寓分司衙','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','書生浪出值暑天，何啻千里身在船。',197,'全唐诗/poet.song.237000.json','["書生浪出值暑天，何啻千里身在船。", "今辰忽向船亭坐，頭眩猶類瀕江牽。", "履平剗地若恍惚，四體不舒慣{臯兀}杌。", "自嗟時滯久勞苦，驅馳負得貧筋骨。", "奉使衙深少吏胥，幹官占了東偏居。", "西偏有軒扁清足，憔悴幾竿蒼竹踈。", "射檐莫禁落日曬，平白將身隨爐鞴。", "不奈羸軀苦熱情，無故要償行脚債。", "富池狂遊期者誰，卷雪樓燬空有基。", "離船未久抱虛暈，孱弱忍蹈波濤危。", "官衙寂然且臥病，便行小伺西風勁。", "廬山夜眠不熟淚不乾，梧樹支離凋井闌。"]'),
('8a6d822b-464e-43ad-aff3-48885b6f944c','午陰坐清足軒','董嗣杲','宋','宋诗','song-poetry','','[]','雲過秋天亂擘絮，風透秋窗遺剪刀。',192,'全唐诗/poet.song.237000.json','["雲過秋天亂擘絮，風透秋窗遺剪刀。", "客衣難禁如此候，離家失侶徒呼號。", "肌骨癯然病易入，況復加以思慮勞。", "行來行往失神雋，蟄此何殊懸壁猱。", "莎底促織聲更苦，唧唧唧唧聲轉髙。", "闌檻謾爾寄清足，石階半落埋蓬蒿。", "無人洗竹起荒翳，脆竿蠧葉纒薜荔。", "繁陰不密絕午夢，安得清風襲襟袂。", "摧殘其來亦已久，心欲扶植茫無計。", "鈎簾癡坐空搔首，直睨秋雲割新霽。", "雲捲雲舒天自空，風生風止窗且閉。", "未暇冥搜清足吟，鄰園老鶴傳孤唳。"]'),
('fd678671-63f1-4b27-af15-029f61766e54','西風','董嗣杲','宋','宋诗','song-poetry','','[]','大江西風三日起，激起怒濤三萬里。',128,'全唐诗/poet.song.237000.json','["大江西風三日起，激起怒濤三萬里。", "客子口噤悄無語，縱有髙樓危莫倚。", "樓前秃樹剩幾葉，更有咽蟬埋葉裏。", "大船小船不見影，衝沙入峽蒼黄艤。", "偶籠窄衫上岡頭，茫茫莫辨天與水。", "浪花旋舞山岳迸，鱗鱗白露江豚齒。", "乾坤浩渺昬八極，秋髙偉事無過此。", "正愁梧上鳳栖空，誰傳水底蛟鬬死。"]'),
('599d5ec3-c03e-4714-82ea-1e2169f1b16e','得少順風又值小雨二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','浪遊幾抆還家淚，貧抱遺書羞擁篲。',64,'全唐诗/poet.song.237000.json','["浪遊幾抆還家淚，貧抱遺書羞擁篲。", "短篷獨載冒江濤，平生觸事成淹滯。", "所爲素守三不欺，人所不知心所知。", "欹枕賦就歸來兮，風伯前呵雨師隨。"]'),
('5ba4b5fc-e8da-4506-aa97-4547153ad7c6','得少順風又值小雨二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','風色幸順逢小雨，小雨冥濛細如縷。',64,'全唐诗/poet.song.237000.json','["風色幸順逢小雨，小雨冥濛細如縷。", "磯上積得雪片堅，雨暗煙沈無所覩。", "無邉無岸江氣埋，誰將混沌爲胞胎。", "送愁急取孤樽開，詩思不知從何來。"]'),
('10850d34-ed6f-4025-9d8f-a1fc1433fde0','午睡中懐約山遊','董嗣杲','宋','宋诗','song-poetry','','[]','蘇州藤枕蘄州簟，更着洪州蟬翼扇。',128,'全唐诗/poet.song.237000.json','["蘇州藤枕蘄州簟，更着洪州蟬翼扇。", "髙臥西窗風外榻，栩栩羲皇夢中見。", "客寄無聊歸未易，搜吟攪得酸腸徧。", "蓴香鱸肥自相憶，季鷹肯羡洛陽掾。", "爲客不似家居好，身老江湖已云倦。", "要盟東林逺法師，白家池上泉珠濺。", "聽泉坐石且幽尋，收拾勝跡歸吟卷。", "我欲往遊志已堅，只恐同遊心易變。"]'),
('66ff2b95-87d1-44ae-9aa4-12a60d820b51','貧遊','董嗣杲','宋','宋诗','song-poetry','','[]','厄貧作客嗟不辰，棲危更覺懐家頻。',160,'全唐诗/poet.song.237000.json','["厄貧作客嗟不辰，棲危更覺懐家頻。", "接泥渡頭漫簇雲，飛雪成塊打倒人。", "隔江黄梅山嶙峋，莫障疆場風沙塵。", "巴河未放船出津，歲晚客子多苦辛。", "伊誰急利行移新，茶引濡滯太不仁。", "書生枉困千金身，嘔盡心力無由伸。", "乾坤誤我此行役，徒然夢想南山宅。", "廬阜要窮仙佛跡，須将姓字磨崖石。", "春風春日春酒碧，脫却俗務勞雙屐。", "携耡賸采白雲薇，只欲了此心願歸。"]'),
('0987af56-6909-41e2-ae4b-db558ec4b311','辛酉富池元宵寫懐二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','七年交春七日强，濛濛春雨吞江鄉。',96,'全唐诗/poet.song.237000.json','["七年交春七日强，濛濛春雨吞江鄉。", "此夕莫知是元夕，地爐埋伏身猶僵。", "鼓簫聲絕想景物，燈火焰短如尋常。", "逢辰往往思濟勝，此際何異栖幽荒。", "推窗且畏江風惡，風柔却憶沙河塘。", "一竿星點富池廟，隨炙隨滅無精光。"]'),
('7a95babb-0b5a-4558-a015-ebdd0d8e895d','辛酉富池元宵寫懐二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','江南江北那識春，况此寄鎮埋煙塵。',96,'全唐诗/poet.song.237000.json','["江南江北那識春，况此寄鎮埋煙塵。", "卑棲客官困壟斷，無故汚此金玉身。", "濁醪自醉復自觧，空恨梗政吏不仁。", "忽傳街鼓聚嬉戯，兩株枯柴插燭銀。", "塗抹脂粉破涕淚，覔酒獻笑酬佳辰。", "震揺荒市官不嗔，傳是黄梅縣西人。"]'),
('1babaa62-09ed-4232-90a2-e413be2a0dc8','吟客枉訪酒邉走筆以贈','董嗣杲','宋','宋诗','song-poetry','','[]','讀書無靈時易過，剩得此身寄寒餓。',192,'全唐诗/poet.song.237000.json','["讀書無靈時易過，剩得此身寄寒餓。", "浮議徒然强雌黄，孤生已拚蟻旋磨。", "江湖說詩在處多，字不堪煮詩奈何。", "不若將軍氊帳醉，兒郎帳裏傳羌歌。", "歸尋種秫安愚分，微名微利天所靳。", "長沮桀溺隠者歟，耦耕曾答仲由問。", "濁世悲歡無歇時，公事不了歸癡兒。", "胸蟠今古何足恃，得醉且醉莫須疑。", "酒邊說詩真是贅，說詩斷是敗人意。", "醉入羲昊洪荒前，消取霎時邯鄲睡。", "歲年寕免驅塵勞，勞不成功亦滔滔。", "終須儕入千百衆，坐對柏烟穿布袍。"]'),
('8e6ac0f1-de96-4bbd-8937-1fcd1000e26e','余明逺訂遊廬山','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','清談得子夜已中，彼此歴叙平生窮。',96,'全唐诗/poet.song.237000.json','["清談得子夜已中，彼此歴叙平生窮。", "知子曾爲四明客，亦曾獻賦明光宫。", "萬人海裏不相逢，狂遊却向江城同。", "尋盟要采廬山杞，香爐峰頂煙生紫。", "便從山北過山南，趁取春光攅桃李。", "洗心滌慮先潄齒，况是天下第一水。"]'),
('3bdc0552-1f92-43f7-aae4-cbc665ace729','答問遊廬山日子','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','欲遊廬山恨不遍，游子先須兩脚徤。',64,'全唐诗/poet.song.237000.json','["欲遊廬山恨不遍，游子先須兩脚徤。", "山中浪走不知方，逢人問路空徬徨。", "人言五老山水窟，半是神仙半是佛。", "獨行直待西風髙，未可議我無仙骨。"]'),
('8f1901dc-02b4-4ad5-bc1c-40741b7d240d','刪舊藁感賦','董嗣杲','宋','宋诗','song-poetry','','[]','少年嗜吟如嗜蜜，諸公奇之有奇質。',160,'全唐诗/poet.song.237000.json','["少年嗜吟如嗜蜜，諸公奇之有奇質。", "學荒志曠不自量，躐登將壇多所嫉。", "薄遊六朝廢興處，逺嘅疆場分離日。", "江草江花幻縝密，下字如縛禪家律。", "吁嗟舊存無二三，側近所取不償失。", "因知嫉者豈輕易，斂盡浮華能就實。", "趣入空玄須正傳，趣得於心暗如漆。", "搜剔造化鬼神凴，天孫雲錦可織出。", "客寄多時轉蕭瑟，趁取風寒寫曠逸。", "九江五峯金翠濕，風月悉歸三寸筆。"]'),
('53855d5f-2878-4979-b681-f5cc775c1fce','官廨凉夕醉成','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','湓江城裏九江驛，今作分司主人宅。',128,'全唐诗/poet.song.237000.json','["湓江城裏九江驛，今作分司主人宅。", "我脱富池榷茶責，借住寛閒忘主客。", "移栽廬山竹半百，障得西廂斜日赤。", "西風揺影失半壁，夢覺只疑泥土窄。", "呼酒當天聊復適，說詩正可凉風夕。", "銀河萬頃鎔瓊色，曠放莫名狂太白。", "留此亦好歸亦得，免使向人說離拆。", "月明酒醒塵絕迹，直欲騎鯨泛空碧。"]'),
('4fe16f4c-36e8-40db-a1f5-b18a3080045a','離湋源口即事','董嗣杲','宋','宋诗','song-poetry','','[]','悠悠漾漾泛煙篷，兩耳聽徹江聲空。',96,'全唐诗/poet.song.237000.json','["悠悠漾漾泛煙篷，兩耳聽徹江聲空。", "水歩涉歷休折柳，晴宵又泊湋源口。", "何待月上淮山頭，黄昏更好尋泊休。", "紅糟醸魚可薦酒，劇飲誰能盡五斗。", "斗斜月出夜已分，江聲人語寂無聞。", "惜無蘇仙共此快，獨自吹簫離巡砦。"]'),
('1db87cec-cbee-4107-bac0-b74326ae564e','蟂磯','董嗣杲','宋','宋诗','song-poetry','','[]','蟂磯聳拔大江東，梟能害人時所惡。',192,'全唐诗/poet.song.237000.json','["蟂磯聳拔大江東，梟能害人時所惡。", "或謂水沃石上來，以澆易蟂本無據。", "前對三山削遥翠，左望邑廬如櫛布。", "政和觀額頒寧淵，青墩月出寒沙暮。", "仙屋周遭二十間，常容苦行掛單住。", "于湖題字跡已湮，拍磯只有風濤怒。", "下觀轉經送輪藏，若徒自希檀施顧。", "飽飲臨江望此磯，此水終身不曾渡。", "青鞋尋勝亦痛快，斜陽迅如箭鋒度。", "蒲帆掛起祗瞬息，頃刻便艤蕪湖歩。", "破舟可棄跡可安，邑橋官店暫尋寓。", "釃酒歡歌謝江靈，髙眺月江足詩句。"]'),
('2f0d730e-d2e7-4fbb-938c-6543fd05980b','苦寒','董嗣杲','宋','宋诗','song-poetry','','[]','陰崖月餘雪未消，春入富池江上遥。',64,'全唐诗/poet.song.237000.json','["陰崖月餘雪未消，春入富池江上遥。", "寒林萬木絕枝葉，終日强欲收墮樵。", "古屋羈人鬢蕭蕭，三冬煖曲無炭燒。", "掘地作爐煨榾柮，如此爲官徒折腰。"]'),
('56aa4fa9-7da1-4612-a3c1-2520b0247898','贈蕭鍊師公弼','董嗣杲','宋','宋诗','song-poetry','','[]','吾家阿京愛公弼，吾家澤兄敬公弼。',96,'全唐诗/poet.song.237000.json','["吾家阿京愛公弼，吾家澤兄敬公弼。", "半生夢與公弼遊，豈意相逢在今日。", "春風和氣見眉宇，玉壺冰鑑藏胸臆。", "人間萬事君自知，未必君材人盡識。", "蘇門水木無纎埃，聞君家近公和台。", "仙家近日多官府，黄帽青鞋歸去來。"]'),
('4460ff3e-3609-47a2-b8c7-c1ad66e72ff6','留九宫山封道士飯因贈','董嗣杲','宋','宋诗','song-poetry','','[]','菜本芃芃剪青玉，饌成澆飯填清腹。',64,'全唐诗/poet.song.237000.json','["菜本芃芃剪青玉，饌成澆飯填清腹。", "孤鶴出自九宫山，雙眸如鶻歩如鹿。", "我聞深谷少得鹽，食淡眠幽體已仙。", "軒軒意趣神氣全，中壽亦過八十年。"]'),
('c35d7848-d9d2-4ab7-b3ec-7fa034183d34','太平興國宫','董嗣杲','宋','宋诗','song-poetry','','[]','旌幢龍虎衛，臺殿鼓鐘浮。',48,'全唐诗/poet.song.237000.json','["旌幢龍虎衛，臺殿鼓鐘浮。", "水亂渾疑雨，山深祗見秋。", "九天嚴採訪，元老主焚脩。", "得祿安蕭散，前身幾世修。"]'),
('2314b2dc-68fd-42c7-b9a3-cc2fbf8a4877','過岳家市','董嗣杲','宋','宋诗','song-poetry','','[]','鄂侯遺部曲，多歲此爲農。',48,'全唐诗/poet.song.237000.json','["鄂侯遺部曲，多歲此爲農。", "茅店罷殘暑，松巒出亂鐘。", "溪流分别塢，晚色失前峯。", "去去遺仙跡，蒼雲幾萬重。"]'),
('15f103ac-bef9-4524-a1a1-450b560b1d50','過富池水軍寨前','董嗣杲','宋','宋诗','song-poetry','','[]','山暝沉晴靄，江春蕩夕暉。',48,'全唐诗/poet.song.237000.json','["山暝沉晴靄，江春蕩夕暉。", "水從螺港下，雲接鹿磯飛。", "雷鼓茶船衆，風旗酒店稀。", "黄昏入悽愴，營屋柝聲微。"]'),
('1ecec302-ea94-4d4c-b8fd-c75a049e11ac','宿雄江統制衙','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','往分蓮社供，歸向草廬眠。',48,'全唐诗/poet.song.237000.json','["往分蓮社供，歸向草廬眠。", "山寨差更鼓，春江走戰船。", "風光隨處别，鬢影倩誰憐。", "花柳西湖曲，招邀憶去年。"]'),
('182ce358-e37b-41f8-a32e-7167440cd9ae','李正將病歸','董嗣杲','宋','宋诗','song-poetry','','[]','從軍傳勇畧，信脚困行間。',48,'全唐诗/poet.song.237000.json','["從軍傳勇畧，信脚困行間。", "病廢羞長劍，秋歸見故山。", "鏡中雙鬢改，衆裏一身還。", "風雪沉昏夜，猶思戍散闗。"]'),
('49959038-9d5c-42d9-a8ba-5d6cb98fc606','客中擬遊廬山','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','依違春夢破，悲壮曉鷄鳴。',48,'全唐诗/poet.song.237000.json','["依違春夢破，悲壮曉鷄鳴。", "旅舍隣淮士，家書附遞兵。", "東風吹浦樹，落月下江城。", "辦取遊山具，天池聽水聲。"]'),
('a23c2080-5da3-4efe-8228-6a696f1bd774','懐廬山','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','屏心寒夢枕，屋角曉城鐘。',48,'全唐诗/poet.song.237000.json','["屏心寒夢枕，屋角曉城鐘。", "客子幾多想，廬山千萬峯。", "仙源雲氣叠，溪坂雨聲重。", "楊柳西門外，禪人屢此逢。"]'),
('e7cafa4a-970d-4168-b97a-224e8d2d7d89','泊安慶得郭澹溪書','董嗣杲','宋','宋诗','song-poetry','','[]','客簷停坐久，軍遞接程初。',48,'全唐诗/poet.song.237000.json','["客簷停坐久，軍遞接程初。", "狂醉舒城酒，欣將建業書。", "宦遊空嘆老，吟思未應疎。", "舉網誰家子，歡然餉巨魚。"]'),
('1ac40f63-4496-4919-9e6b-745fe7720480','江城春日寓懐','董嗣杲','宋','宋诗','song-poetry','','[]','丘園勞積夢，天地厭劬書。',48,'全唐诗/poet.song.237000.json','["丘園勞積夢，天地厭劬書。", "立晚分孤鶴，跳春喜衆狙。", "風多醉有竹，雨久飯無蔬。", "又見江西估，收苖蓄巨魚。"]'),
('58025ca4-1568-4ba4-8072-ca22d2e001c3','天池寺憶雪屋韶上人','董嗣杲','宋','宋诗','song-poetry','','[]','惠詩傳驛舊，立雪想師遥。',48,'全唐诗/poet.song.237000.json','["惠詩傳驛舊，立雪想師遥。", "一别此山去，清風不可招。", "經窗雲半掩，石塔水偏朝。", "托迹今三宿，伊誰共寂寥。"]'),
('193bb2ae-0db2-4b87-8f3e-e4e9affbb703','安慶新城','董嗣杲','宋','宋诗','song-poetry','','[]','清香凝燕寢，春色遍龍舒。',48,'全唐诗/poet.song.237000.json','["清香凝燕寢，春色遍龍舒。", "市井無遺地，人煙有定居。", "柝聲營屋邃，帘影酒坊虚。", "白首三山客，編茅作校書。"]'),
('f4d8eadc-aeda-404d-8950-38447e6d0ef4','過安慶舊城','董嗣杲','宋','宋诗','song-poetry','','[]','市邑新荆棘，風沙舊路岐。',48,'全唐诗/poet.song.237000.json','["市邑新荆棘，風沙舊路岐。", "重添多少恨，可想戰争時。", "蟒氣纒荒塔，螢光出廢池。", "纎纎城角草，應是得春遲。"]'),
('31a45f95-a088-4ec9-bea8-86c442b962c0','送劉統轄自黄岡歸光州','董嗣杲','宋','宋诗','song-poetry','','[]','偃武身還老，還家計未非。',48,'全唐诗/poet.song.237000.json','["偃武身還老，還家計未非。", "貧依山寨住，喜訪竹樓歸。", "度隴書鴻少，翻場戰馬肥。", "月明羞北望，誰擷故園薇。"]'),
('a49c957c-2e45-40e0-bb10-7cd8bcb35e53','贈圭上人','董嗣杲','宋','宋诗','song-poetry','','[]','幾年參四教，孤影托三衣。',48,'全唐诗/poet.song.237000.json','["幾年參四教，孤影托三衣。", "自識閒機了，誰甘苦行歸。", "秋藤溪水活，雨葉寺墻肥。", "覺得真如處，空房不掩扉。"]'),
('331b894b-25f9-4f9c-8db6-2d4b1ef711e5','秋巖入城後寄','董嗣杲','宋','宋诗','song-poetry','','[]','心知沈迹墮，耳熟舊詩誇。',48,'全唐诗/poet.song.237000.json','["心知沈迹墮，耳熟舊詩誇。", "返照僧歸寺，西風客憶家。", "微寒侵病骨，新夢惜年華。", "獨坐無聊賴，沿籬看菊花。"]'),
('79e8be3b-80fe-4d1c-910d-24795c3a17d6','拙寄','董嗣杲','宋','宋诗','song-poetry','','[]','岑寂風烟異，荒寒夢寐危。',48,'全唐诗/poet.song.237000.json','["岑寂風烟異，荒寒夢寐危。", "擇交貧可久，爲吏拙難醫。", "大閫糧艘上，孤營竹笛悲。", "快沽桑落酒，澆此滿懐詩。"]'),
('5eddb577-cf67-4b87-bba4-5587376578db','冷翠谷看瀑二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','聞得西巖竇，髙飛直下泉。',48,'全唐诗/poet.song.237000.json','["聞得西巖竇，髙飛直下泉。", "貪奇曾結屋，接潤可通田。", "晚竹侵雲老，凉蔬摘雨鮮。", "野猿常抱子，飼食下松顛。"]'),
('4a0e141a-fcbb-4d86-ac9a-3f1314e63aa1','冷翠谷看瀑二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','清嘯谷音答，閒眠松蔭便。',48,'全唐诗/poet.song.237000.json','["清嘯谷音答，閒眠松蔭便。", "山林微暑退，鐘鼓逺風傳。", "足繭憂羸僕，身輕羡散仙。", "乍暄思午盥，喜際石根泉。"]'),
('ef8f3eb1-e51f-4e07-887e-fb83faf0f0c8','贈天池寺覺翁圓上人','董嗣杲','宋','宋诗','song-poetry','','[]','單起浯溪寺，禪棲主簿峰。',48,'全唐诗/poet.song.237000.json','["單起浯溪寺，禪棲主簿峰。", "收詩入頑石，禮塔趁昏鐘。", "好古心何癖，觀空語更慵。", "覺翁纔覺處，明月出孤松。"]'),
('0ce20916-4f66-441a-a814-7956295bb59f','重遊東林','董嗣杲','宋','宋诗','song-poetry','','[]','溪水涵天影，山雲趁屐聲。',48,'全唐诗/poet.song.237000.json','["溪水涵天影，山雲趁屐聲。", "信緣重一到，流夢入三生。", "瀑勢翻空逺，林陰障雨平。", "爐峯閑覽勝，思附逺公名。"]'),
('37203f33-7109-458e-96fc-5c0340e5907f','留江城將還富池','董嗣杲','宋','宋诗','song-poetry','','[]','吟斷悲秋字，愁歸餞臘筵。',48,'全唐诗/poet.song.237000.json','["吟斷悲秋字，愁歸餞臘筵。", "天荒鵬路絕，水落鴈汀懸。", "白羽沈郵箭，滄江負釣船。", "投閒須有日，處順且添年。"]'),
('880f84a7-0e67-4c97-b1ae-b73419a0c5f5','天池寺晚歩','董嗣杲','宋','宋诗','song-poetry','','[]','傍通錦繡谷，上接鐵船峰。',48,'全唐诗/poet.song.237000.json','["傍通錦繡谷，上接鐵船峰。", "月出龍潭浄，風虚佛屋重。", "四維天象朗，孤閣野雲封。", "收得天燈葉，熒熒却絕蹤。"]'),
('8f5869c1-1402-4a2d-bf09-d13da90cc3f9','出西城','董嗣杲','宋','宋诗','song-poetry','','[]','舟車江郭隘，鐘鼓梵祠遥。',48,'全唐诗/poet.song.237000.json','["舟車江郭隘，鐘鼓梵祠遥。", "古馹停羈客，深林出晚樵。", "鷹呼風立至，鴉竄雪垂飄。", "市價招商急，殘冬未寂寥。"]'),
('5bce059b-6123-48dc-9840-cbd07715ff28','東林寺晚歩','董嗣杲','宋','宋诗','song-poetry','','[]','天地聚奇觀，山林負隠名。',48,'全唐诗/poet.song.237000.json','["天地聚奇觀，山林負隠名。", "月明僧影瘦，風定水聲清。", "不覺忘身世，何須問死生。", "有詩難舉似，真實避時英。"]'),
('0a9c3544-f16e-4d80-95e5-fc79cb4faa93','旅次感懐','董嗣杲','宋','宋诗','song-poetry','','[]','亂眼悲人事，追程老客顔。',48,'全唐诗/poet.song.237000.json','["亂眼悲人事，追程老客顔。", "鼉鳴風鼓浪，鴈斷日銜山。", "此際塵勞混，吾生賦予慳。", "吟聫朝晚積，負得賀嚢還。"]'),
('1fc48d83-e58b-4f21-a92b-fe76189e446d','周孚與髙伯庸同遊王氏庵歸而閭丘仲詩至因次韻貽顯庵主以紀一時事  其一','董嗣杲','宋','宋诗','song-poetry','','[]','寂寞城西寺，重來已素秋。',48,'全唐诗/poet.song.237000.json','["寂寞城西寺，重來已素秋。", "未霜芳草合，欲雨暮雲稠。", "濁酒羸方戒，新詩困復休。", "翻然會心處，煙徑有歸牛。"]'),
('103acdb6-a512-429e-a1aa-b469b75c8f1f','周孚與髙伯庸同遊王氏庵歸而閭丘仲詩至因次韻貽顯庵主以紀一時事  其二','董嗣杲','宋','宋诗','song-poetry','','[]','法水堪湔垢，僧廬自辟塵。',48,'全唐诗/poet.song.237000.json','["法水堪湔垢，僧廬自辟塵。", "飯炊雲子熟，茶泛乳花匀。", "草草情何厚，怱怱迹易陳。", "他年輞川上，爲畫兩綸巾。"]'),
('4908c341-8250-4e3a-9a06-e7f0b38c6af5','送史制機之鄂州','董嗣杲','宋','宋诗','song-poetry','','[]','宿戍供王事，膏車趲客程。',48,'全唐诗/poet.song.237000.json','["宿戍供王事，膏車趲客程。", "折榮湓浦柳，行色武昌城。", "借印科邉餉，巡江點騎兵。", "憂時心更切，滿望邑塵清。"]'),
('f61757f0-189c-4dc8-9d62-4f77a2344888','過分水嶺','董嗣杲','宋','宋诗','song-poetry','','[]','看雲忘斗峻，倚石望藤懸。',48,'全唐诗/poet.song.237000.json','["看雲忘斗峻，倚石望藤懸。", "鳥背斜陽去，牛翻淺草眠。", "井桐支野廟，溪水沃山田。", "隔嶺僧逢客，狂談馬祖禪。"]'),
('f91d0b35-8a06-4f0e-aabb-8b132318c00e','妙智寺','董嗣杲','宋','宋诗','song-poetry','','[]','空凉妙智寺，經始臥遺碑。',48,'全唐诗/poet.song.237000.json','["空凉妙智寺，經始臥遺碑。", "白日有精魅，長年無住持。", "雨淋泥竈壊，草迸石爐欹。", "纔入廬峯界，天風逐歩隨。"]'),
('13b3c0cb-0457-410c-b975-7784605a0202','琵琶亭','董嗣杲','宋','宋诗','song-poetry','','[]','艱難罹歉歲，寂寞向他州。',48,'全唐诗/poet.song.237000.json','["艱難罹歉歲，寂寞向他州。", "分絕青雲上，家遥滄海頭。", "空江蕩寒月，枯葦積荒洲。", "不奈譙城角，嗚嗚吹亂愁。"]'),
('b9208098-5b36-49a6-9495-762480deb8de','泊黄茅潭','董嗣杲','宋','宋诗','song-poetry','','[]','唳雪滄洲鴈，嘘雲碧浪鯨。',48,'全唐诗/poet.song.237000.json','["唳雪滄洲鴈，嘘雲碧浪鯨。", "茅深淮渡逺，日落海潮平。", "廟樹揺燈影，船風送鼓聲。", "勞思於此泊，無地趁春耕。"]'),
('6b06746f-c9bb-41f3-befe-8b84a30ef960','廣濟縣王氏山園','董嗣杲','宋','宋诗','song-poetry','','[]','憂世鬚眉覺，耡園夢想安。',48,'全唐诗/poet.song.237000.json','["憂世鬚眉覺，耡園夢想安。", "封疆南斗隘，天地北風寒。", "野水通眢井，山雲補蠧闌。", "故鄉營業墮，歲晚轉艱難。"]'),
('b0c2a26d-4680-4b24-ae61-08de362d9b22','曹家沙阻風與朱一夔歩入廬江縣','董嗣杲','宋','宋诗','song-poetry','','[]','剩浪淮南接，踈篷岸北留。',48,'全唐诗/poet.song.237000.json','["剩浪淮南接，踈篷岸北留。", "聮鑣入荒市，扶杖涉虚洲。", "有侣同尋醉，無歌可遣愁。", "風花猶未息，却望隔江舟。"]'),
('dbba545a-445d-495a-8c11-b8d2069f55c0','富池晚興','董嗣杲','宋','宋诗','song-poetry','','[]','江花迷望望，霜葉落紛紛。',48,'全唐诗/poet.song.237000.json','["江花迷望望，霜葉落紛紛。", "翠嶂明分燒，滄江逺載雲。", "聚舟應弭侮，營屋又屯軍。", "欲遂平戎捷，須將舊硯焚。"]'),
('c14a4752-fab9-46bc-ae65-3cda429210f8','小歩晚興','董嗣杲','宋','宋诗','song-poetry','','[]','板橋孤渡險，草屋四簷穿。',48,'全唐诗/poet.song.237000.json','["板橋孤渡險，草屋四簷穿。", "逺客感新月，短髭傷壮年。", "水籬微雪沍，天宇列星懸。", "無地尋朋好，歸情托七絃。"]'),
('01b448c2-1221-4457-b504-d1a0afce2cc3','宿潯陽館','董嗣杲','宋','宋诗','song-poetry','','[]','病身歸束縛，楓葉見飄零。',48,'全唐诗/poet.song.237000.json','["病身歸束縛，楓葉見飄零。", "雲淡秋星白，天遥戍火青。", "舊盟無處續，閒夢有時靈。", "月色江聲裏，愁多酒易醒。"]'),
('ca516939-1e21-474f-8403-b088123c1ae0','江墅秋晚','董嗣杲','宋','宋诗','song-poetry','','[]','秋林不可寄，九月已寒風。',48,'全唐诗/poet.song.237000.json','["秋林不可寄，九月已寒風。", "鴻鴈雲呼逺，蠅蚊雨洗空。", "籬花荒正色，岸蓼臥枯叢。", "别浦棲漁隠，何期共短篷。"]'),
('c9079dc3-809e-4b37-b965-e4f5dc92a185','入貴池逢張秀夫','董嗣杲','宋','宋诗','song-poetry','','[]','風姿欣邂逅，彼此略寒暄。',48,'全唐诗/poet.song.237000.json','["風姿欣邂逅，彼此略寒暄。", "爲客那知老，相看不忍言。", "湖魚朝上市，驛鼠夜穿垣。", "共爾添貧病，攅眉說故園。"]'),
('a44b68d1-5e1b-44a0-a313-cd93089dd375','逢林舜舉','董嗣杲','宋','宋诗','song-poetry','','[]','命逢元造厄，時使壮心違。',48,'全唐诗/poet.song.237000.json','["命逢元造厄，時使壮心違。", "淮海三年客，山林一布衣。", "有家惟母在，無犬寄書歸。", "明日重陽醉，休辭上翠微。"]'),
('f0bd2778-e43a-48cc-9236-9710447b941a','自接泥渡再還富池','董嗣杲','宋','宋诗','song-poetry','','[]','接泥當有渡，截水欲無梁。',48,'全唐诗/poet.song.237000.json','["接泥當有渡，截水欲無梁。", "白日風聲惡，滄波鷺點凉。", "閒身纒暑疢，故里報秋荒。", "渺渺孤生託，渾如墮絮忙。"]'),
('3e74687a-2156-4489-bf33-638171dd2b21','銀樹','董嗣杲','宋','宋诗','song-poetry','','[]','銀樹驛橋廢，征車難久停。',48,'全唐诗/poet.song.237000.json','["銀樹驛橋廢，征車難久停。", "月沉孤店柳，雪掩敗舟萍。", "野冡明荒燐，山田出斷銘。", "甫能投宿去，歷歷過郵鈴。"]'),
('36d6c57f-5c81-477b-9aff-fc428105e7ea','春近','董嗣杲','宋','宋诗','song-poetry','','[]','瀉月江當户，編茅屋背崖。',48,'全唐诗/poet.song.237000.json','["瀉月江當户，編茅屋背崖。", "久貧難養氣，獨酌且開懐。", "雪水喧淮土，天風破楚霾。", "鞭春明日早，環珮想堯階。"]'),
('dec1dc89-962f-48e8-b1c4-dd422bfdc545','愁中延客','董嗣杲','宋','宋诗','song-poetry','','[]','染衣塵土厚，覽鏡雪霜明。',48,'全唐诗/poet.song.237000.json','["染衣塵土厚，覽鏡雪霜明。", "朱墨増新病，身名失舊清。", "公？春草盛，野市臘醅輕。", "留客驅寥寞，江光射北楹。"]'),
('ec1c3cf8-ae1f-481e-ae9d-34391716b062','客江城歸期尚阻','董嗣杲','宋','宋诗','song-poetry','','[]','晴坂桑麻綠，春溪蘋藻香。',48,'全唐诗/poet.song.237000.json','["晴坂桑麻綠，春溪蘋藻香。", "家林方歉歲，身紀且殊鄉。", "澒洞時機密，淹留日計長。", "此生歸造物，不必殢行藏。"]'),
('a3449364-91f7-44ef-8add-3280de239f2b','客久','董嗣杲','宋','宋诗','song-poetry','','[]','身孤猶落葉，客久向餘英。',48,'全唐诗/poet.song.237000.json','["身孤猶落葉，客久向餘英。", "少睡夜逾悄，多聞心更清。", "縣樓訛漏點，雨市雜溪聲。", "海上仙槎在，思乘幾凝情。"]'),
('9f1f97bd-c7a6-4b3c-ae62-b5080445a341','贈歸客','董嗣杲','宋','宋诗','song-poetry','','[]','嚢槖依然負，煙波豁爾遊。',48,'全唐诗/poet.song.237000.json','["嚢槖依然負，煙波豁爾遊。", "窮秋多雨水，歸棹幾汀洲。", "艤月無言坐，聽梧不觧愁。", "退耕應在念，肯向客途留。"]'),
('906187b8-59d8-4dda-860a-17f62a5a054f','客寓即事','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','樹頭梅豆小，水際荻茅鮮。',48,'全唐诗/poet.song.237000.json','["樹頭梅豆小，水際荻茅鮮。", "老客携名酒，頑胥納俸錢。", "喜尋臨晚興，恨入惜春聫。", "不似西湖樂，東風蕩畫船。"]'),
('e1e16376-d0a5-44eb-a0e4-90f3aa04b0ae','獨客二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','獨客夢中過，千愁醉裏生。',48,'全唐诗/poet.song.237000.json','["獨客夢中過，千愁醉裏生。", "秋酲誰可觧，晚臥自難成。", "破屋無人氣，幽泉有雨聲。", "南窗多不掩，想像竹房清。"]'),
('a8db8f5e-7933-487b-85c6-29a914946f3e','獨客二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','官治寄棲冷，僧樓凝望遥。',48,'全唐诗/poet.song.237000.json','["官治寄棲冷，僧樓凝望遥。", "江山延客眼，風雨聚秋宵。", "薦酒蒸淮棗，烹魚糝漢椒。", "莫能諳食味，心跡轉寥寥。"]'),
('a6376561-ea17-49f1-a1ee-8eb5590421e1','泊貴池驛','董嗣杲','宋','宋诗','song-poetry','','[]','琴書湓浦擔，風雪貴池船。',48,'全唐诗/poet.song.237000.json','["琴書湓浦擔，風雪貴池船。", "問酒臨津醉，添衣入驛眠。", "漁翁寒補網，鄰女夜調絃。", "何日齊山去，尋僧學說禪。"]'),
('357a15f4-cd1a-40b1-8d9b-db6640c779aa','西林寺','董嗣杲','宋','宋诗','song-poetry','','[]','地分連寺樹，逕掩隔墻苔。',48,'全唐诗/poet.song.237000.json','["地分連寺樹，逕掩隔墻苔。", "破屋無僧住，深秋有客來。", "號猿歸秃樹，饑鳥立香臺。", "慧永當年塔，陰雲撥不開。"]'),
('61cab937-849f-44b6-bb5a-dcefa3bc7471','客寓鄰家有園嘗欲過之不可得','董嗣杲','宋','宋诗','song-poetry','','[]','形容淹白晝，意向落清樽。',48,'全唐诗/poet.song.237000.json','["形容淹白晝，意向落清樽。", "客榻猶移雨，鄰園自掩門。", "秋髙江一色，風起月多痕。", "忽忽孤生感，真難薄俗論。"]'),
('fc556cd8-e59b-4652-bd2c-450aacc322fb','送矩上人','董嗣杲','宋','宋诗','song-poetry','','[]','單懸淮楚寺，裓染歲時塵。',48,'全唐诗/poet.song.237000.json','["單懸淮楚寺，裓染歲時塵。", "踏雪歸何處，看雲悟此身。", "三乘新見性，一鉢晚隨人。", "江北蕭條甚，還期莫待春。"]'),
('4eccc57d-c3b0-42f8-8029-b73345b7e1d3','寄别余明逺','董嗣杲','宋','宋诗','song-poetry','','[]','别離臨水濶，迤邐望城微。',48,'全唐诗/poet.song.237000.json','["别離臨水濶，迤邐望城微。", "落日猶回首，空江獨自歸。", "遥峰攅石樹，饑鳥立沙磯。", "誰憫貂裘敝，還家且掩扉。"]'),
('fae16c88-98d4-4cb7-bf65-c25de60be14c','寓城一首','董嗣杲','宋','宋诗','song-poetry','','[]','推枕縈殘夢，開窗掃積塵。',48,'全唐诗/poet.song.237000.json','["推枕縈殘夢，開窗掃積塵。", "病深難禦酒，貧極莫依人。", "野樹依山暗，春林受雨新。", "晨興閒整履，休惜看花頻。"]'),
('bfc0ecfd-3696-4271-9d6f-d6cd43506b53','約余明逺','董嗣杲','宋','宋诗','song-poetry','','[]','靜極占鴉鵲，閒來棄簡書。',48,'全唐诗/poet.song.237000.json','["靜極占鴉鵲，閒來棄簡書。", "風停思晚醉，泥軟便春耡。", "透屋哀歌切，懐人吉夢疎。", "餘樽須共倒，莫惜過吾廬。"]'),
('3ae560ed-c2aa-40d6-b635-e1ef17b56e40','客約遊山久未踐盟','董嗣杲','宋','宋诗','song-poetry','','[]','居安懐蔀屋，處約客雄藩。',48,'全唐诗/poet.song.237000.json','["居安懐蔀屋，處約客雄藩。", "風日山川媚，城池草木蕃。", "花時貧久减，春醉約多番。", "顧我留情極，憐君苦事繁。"]'),
('cb34c543-467e-4308-87cd-e89d0cfca465','雨後','董嗣杲','宋','宋诗','song-poetry','','[]','一雨收殘暑，新凉夜頓添。',48,'全唐诗/poet.song.237000.json','["一雨收殘暑，新凉夜頓添。", "秋聲滿落葉，蟲語傍虚簷。", "衰疾便髙臥，游程嘆久淹。", "山林雖寂寞，亦足養吾恬。"]'),
('57c860a0-bd40-4667-b60c-230cb3d3a999','四安舟上','董嗣杲','宋','宋诗','song-poetry','','[]','復添三嘆處，回泊四安時。',48,'全唐诗/poet.song.237000.json','["復添三嘆處，回泊四安時。", "野市人言獷，官坊酒味醨。", "聚船要價重，滌釡待糧遲。", "客况那能遣，終身厭路岐。"]'),
('fb572fed-877d-4881-9e92-d519cf1f08f7','舟過彭澤','董嗣杲','宋','宋诗','song-poetry','','[]','柳移彭澤縣，江泛木蘭橈。',48,'全唐诗/poet.song.237000.json','["柳移彭澤縣，江泛木蘭橈。", "逺水初凝暮，青山獨去遥。", "沙明回斷鴈，月黒起寒潮。", "愛酒侔元亮，而今懶折腰。"]'),
('4f855410-43ef-4f23-97f7-a47bee7fad13','安豐朱一夔同舟','董嗣杲','宋','宋诗','song-poetry','','[]','寒勁滋煙浪，根浮蹈雪霜。',48,'全唐诗/poet.song.237000.json','["寒勁滋煙浪，根浮蹈雪霜。", "同舟諳楚俗，空槖返吳鄉。", "聚散羈情逺，行藏話柄長。", "驟逢接言笑，直覺背時粧。"]'),
('c0cf64ec-2ec5-4e4e-95f9-c3f30737325f','廬山中即事二首  其一','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','樹密攅烟靄，泉甘護土田。',48,'全唐诗/poet.song.237000.json','["樹密攅烟靄，泉甘護土田。", "粧嚴仙佛徧，呵護鬼神専。", "蓮社招無地，桃源别有天。", "萬峰空削玉，分絕構三椽。"]'),
('de8b2157-c525-4318-8bc9-5ba5c5ea3a65','廬山中即事二首  其二','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','聽泉聊觧带，望塔謾驅車。',48,'全唐诗/poet.song.237000.json','["聽泉聊觧带，望塔謾驅車。", "山屋潜花犬，沙溪泛葉魚。", "野僧朝自碓，牧子夜猶耡。", "風景渾生意，塵勞盡掃除。"]'),
('9ce40e09-2428-44c4-9c28-b6bcb6c971d1','舟泊蘄城下','董嗣杲','宋','宋诗','song-poetry','','[]','秋蕪埋戍雨，暮荻卷壕風。',48,'全唐诗/poet.song.237000.json','["秋蕪埋戍雨，暮荻卷壕風。", "禦侮弓刀利，揚威鼓角雄。", "雲連淮樹暗，月透漢營空。", "捩柂資遐眺，興衰自古同。"]'),
('51a47ece-2995-4ebb-98bb-9aaec7936ceb','題江州天慶觀','董嗣杲','宋','宋诗','song-poetry','','[]','隘寺鼓鐘透，殊庭瑞慶垂。',48,'全唐诗/poet.song.237000.json','["隘寺鼓鐘透，殊庭瑞慶垂。", "上清唐塑像，正一漢遺師。", "經籙青城派，樓臺紫極基。", "堯天躋壽域，羽佩有威儀。"]'),
('5ae83ca3-f69c-4bfe-af22-33ef13dd5ebf','妙智寺明上人他適因得一遊','董嗣杲','宋','宋诗','song-poetry','','[]','主僧何所往，閒客自來遊。',48,'全唐诗/poet.song.237000.json','["主僧何所往，閒客自來遊。", "山阜秋稜勁，村塍稻把稠。", "落烏攅梵廡，腥鴿墮經樓。", "借鼎烹茶去，無人說趙州。"]'),
('1d7fa7d1-ec5c-4c20-8505-29849e3cd012','留興國宫懐城中友人','董嗣杲','宋','宋诗','song-poetry','','[]','拜章壇下桂花清，客子看山眼更醒。',64,'全唐诗/poet.song.237000.json','["拜章壇下桂花清，客子看山眼更醒。", "萬竹梳風凉透碧，亂峰收雨曉爭青。", "城中佳客還相憶，月下幽泉政好聽。", "誰肯結茅鄰逺社，白家猶有舊池亭。"]'),
('1a002788-57fb-4d6d-8ba1-e65927c4fc0d','九江易帥遂得盡遊郡齋','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','郡吏東征迓衮衣，不知郡圃掩芳扉。',64,'全唐诗/poet.song.237000.json','["郡吏東征迓衮衣，不知郡圃掩芳扉。", "櫻桃熟處香山識，楊柳栽時靖節歸。", "壁帖嵌塵鐘鼎碎，樓歌壓市管絃飛。", "廬山面目清如此，幾客登臨幾夕暉。"]'),
('23d10310-2c2c-4cea-9a27-139074e5ec24','謝村','董嗣杲','宋','宋诗','song-poetry','','[]','暮役朝行此可停，臨平山色入船青。',64,'全唐诗/poet.song.237000.json','["暮役朝行此可停，臨平山色入船青。", "煙窑慘淡多逃户，泥井虚圓有廢亭。", "貧衲施茶營屋小，老漁曝網遶籬腥。", "客懐久困飄蕭裏，風撼枯桐不可聽。"]'),
('0f07cd40-e2f2-4080-b82f-1de565f761de','欲附蒲海雲制幹舟歸','董嗣杲','宋','宋诗','song-poetry','','[]','江上樓髙暝樹連，壮遊空慨禹山川。',64,'全唐诗/poet.song.237000.json','["江上樓髙暝樹連，壮遊空慨禹山川。", "客中問醉當秋晚，夢裏懐歸在燕先。", "水送流年遺楚恨，風吹殘雪上吳顛。", "幾番謾附鱗鴻便，不若相依買去船。"]'),
('c51ef9d2-7918-4cf9-a8f3-ce1bbf2f58f5','泊韶村','董嗣杲','宋','宋诗','song-poetry','','[]','汎然歸息苦冬陰，小泊煙塍却舊尋。',64,'全唐诗/poet.song.237000.json','["汎然歸息苦冬陰，小泊煙塍却舊尋。", "荷葉久空晴浦近，麥芒還吐晚村深。", "鱠鱸雨壓還吳興，寄鴈雲迷客楚心。", "便可放懐天地外，攬將奇思援孤琴。"]'),
('a66b8f21-8170-44a1-8dd0-dc1231b033de','又憇西林寺有乘馬人來同宿','董嗣杲','宋','宋诗','song-poetry','','[]','孤憑水閣坐斜曛，七級浮屠壓暝氛。',64,'全唐诗/poet.song.237000.json','["孤憑水閣坐斜曛，七級浮屠壓暝氛。", "慧永祠空依晉樹，率更碑古宿唐雲。", "自聽逺鶴情偏逸，誰策羸驂趣不羣。", "同向西林卸行槖，溪風摵摵葉紛紛。"]'),
('1e57c1a6-ac2e-4e2f-8941-07eb6fe2d0b9','岳園醉宿二首  其一','董嗣杲','宋','宋诗','song-poetry','','[]','荼䕷葉暗石床平，醉倚池臺午影清。',64,'全唐诗/poet.song.237000.json','["荼䕷葉暗石床平，醉倚池臺午影清。", "洗酌更嘗桑落味，推窗忍聽栗留聲。", "能仁寺裏塔孤立，見易園中人獨行。", "此地酬春誰得共，東方月上酒船横。"]'),
('cdadf558-46a4-4dd4-bd8e-20f61b78bd5c','岳園醉宿二首  其二','董嗣杲','宋','宋诗','song-poetry','','[]','名園獨歩欲誰羣，午醉醒時坐夕曛。',64,'全唐诗/poet.song.237000.json','["名園獨歩欲誰羣，午醉醒時坐夕曛。", "暝色移花侵几暗，野香带酒隔窗聞。", "逺山翠蓊春初老，落月弦消夜已分。", "杜宇苦催濡滯客，曉愁相併落歸雲。"]'),
('600b11df-a19f-4f77-a2f5-6d5349bce069','蓮花塘','董嗣杲','宋','宋诗','song-poetry','','[]','啼烟禽鳥役羈魂，又泊寒崖近水村。',64,'全唐诗/poet.song.237000.json','["啼烟禽鳥役羈魂，又泊寒崖近水村。", "暗谷靄深迷樹跡，敗塘水涸見蓮根。", "自收墮葉投官店，誰縛枯藤鎻廟門。", "濁酒不澆寒極恨，幾程陡入醉乾坤。"]'),
('7f073bc3-6617-46b9-b4cb-ac458aa9c85a','欲脱榷司東歸','董嗣杲','宋','宋诗','song-poetry','','[]','擔尾心期有破琴，絕憐無地覔知音。',64,'全唐诗/poet.song.237000.json','["擔尾心期有破琴，絕憐無地覔知音。", "形神怯冷猶迎客，風雨催春亟治任。", "眼落牛羊沙渡逺，情凝江漢寺樓深。", "津津誰染鵝黄柳，想可挨排醉綠陰。"]'),
('896f4f15-c221-40b9-be9f-9aa35db6795e','江州税亭清坐','董嗣杲','宋','宋诗','song-poetry','','[]','西郭江頭坐午前，春汀裂笛出商船。',64,'全唐诗/poet.song.237000.json','["西郭江頭坐午前，春汀裂笛出商船。", "纔晴旅舍湔裙雨，未晚軍營發爨煙。", "泥飲自知人共厭，思歸相視眼徒穿。", "征亭逢著田間老，又說今朝損額錢。"]'),
('18e15578-dd7a-4a0c-88f6-190497b264c5','舟歸富池紀懐','董嗣杲','宋','宋诗','song-poetry','','[]','風月幽情藉綠樽，奔馳水陸最無根。',64,'全唐诗/poet.song.237000.json','["風月幽情藉綠樽，奔馳水陸最無根。", "官舟獨載年窮雪，社鼓相迎晚泊村。", "到？茶商期又失，懐家蓴客眼添昏。", "煙蕪不斷休回首，心跡從誰逐節論。"]'),
('df245156-3d8f-4d2b-9f00-42309223d218','銅陵縣廢寺','董嗣杲','宋','宋诗','song-poetry','','[]','銅官山下梵坊欹，誰爲昭明太子悲。',64,'全唐诗/poet.song.237000.json','["銅官山下梵坊欹，誰爲昭明太子悲。", "鶴去不歸松下柱，龜埋空負草間碑。", "誰言象教無銷歇，自剖鴻濛有亂離。", "獨倚傾墻望淮水，殘僧絕影立移時。"]'),
('5aa1a9ff-07d1-427c-9ef8-8937432ae8d0','自興國軍治出富池','董嗣杲','宋','宋诗','song-poetry','','[]','澒洞塵沙跡寄浮，霜茅風棘斷堽頭。',64,'全唐诗/poet.song.237000.json','["澒洞塵沙跡寄浮，霜茅風棘斷堽頭。", "幾家白酒山城暮，一穗青烽野戍秋。", "戰馬向年荒此壘，羈鴻今夜宿何洲。", "扁舟直下寒江口，不見甘王卷雪樓。"]'),
('5575625f-308f-4be5-8b1a-c097d6f9c136','登臨','董嗣杲','宋','宋诗','song-poetry','','[]','登臨乘此暮江風，數盡南飛幾字鴻。',64,'全唐诗/poet.song.237000.json','["登臨乘此暮江風，數盡南飛幾字鴻。", "秋水已清天更碧，曉楓未赤棗先紅。", "諸公軒冕留情處，萬里山河拊髀中。", "壮志已銷思擁衲，飽餐蔬飯想虚空。"]'),
('bb6c9e65-e5ea-4622-bfe7-fb4d1584ca06','富池鎮上感懐  其一','董嗣杲','宋','宋诗','song-poetry','','[]','富池鎮上土風殊，誰憫流民涸轍魚。',64,'全唐诗/poet.song.237000.json','["富池鎮上土風殊，誰憫流民涸轍魚。", "樵子乞租營屋住，渡官强占廟門居。", "賈舟聚港傳官點，鬼店揚沙託法袪。", "第把沽漿招社賽，壚頭還有馬相如。"]'),
('b77ec1ce-f358-4e56-819f-62b4d83f1591','富池鎮上感懐  其二','董嗣杲','宋','宋诗','song-poetry','','[]','髑髏如雪混塗泥，浪打沙填晚更凄。',64,'全唐诗/poet.song.237000.json','["髑髏如雪混塗泥，浪打沙填晚更凄。", "烽警上流兵未觧，灰寒中土客徒栖。", "懐歸日積思鱸切，歌凱風聞集鴈齊。", "憂患轉深頭轉白，江雲不障夕陽西。"]'),
('8f7de92f-8d2e-4605-b656-d4a9ffc870c7','富池鎮上感懐  其三','董嗣杲','宋','宋诗','song-poetry','','[]','流民土著兩紛紛，朝暮惟知射利勤。',64,'全唐诗/poet.song.237000.json','["流民土著兩紛紛，朝暮惟知射利勤。", "隔縣小家多釣弋，近沙虛地少耕耘。", "望中紅葉秋何極，直北黄雲路不分。", "僻處絕無佳客過，酒邉安得有新聞。"]'),
('7fb7da0a-0f59-4d1b-b839-48b7b0923062','富池鎮上感懐  其四','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','荒村風物幾嗟吁，鬼笑陳人旅更孤。',64,'全唐诗/poet.song.237000.json','["荒村風物幾嗟吁，鬼笑陳人旅更孤。", "鴉黠待船抛食飽，骨靈撐岸蝕泥枯。", "酸腸百結攅年裏，古鎮三义截路隅。", "平漠展殘斜日赤，有書無鴈過西湖。"]'),
('20a2db0b-03bb-4436-b969-d6ab543cbf30','富池寓懐','董嗣杲','宋','宋诗','song-poetry','','[]','求佚徒將意揣摩，臨髙又惜歲蹉跎。',64,'全唐诗/poet.song.237000.json','["求佚徒將意揣摩，臨髙又惜歲蹉跎。", "隔江山秃秋煙空，入樹風號夜浪多。", "童子得錢思逺引，鄰翁借酒强髙歌。", "謾傳客路饒孤笛，若老山村只短蓑。"]'),
('66f193b6-5a76-4025-aa2a-0f4bf672c3e4','閉户','董嗣杲','宋','宋诗','song-poetry','','[]','客籬倐見野棠開，紅紫無心委雨苔。',64,'全唐诗/poet.song.237000.json','["客籬倐見野棠開，紅紫無心委雨苔。", "閉户自償書債去，題橋誰作酒傭來。", "晚知屋上青山改，老爲江頭白骨哀。", "島瘦郊寒詩是祟，斷然難畫入雲臺。"]'),
('bafa94d2-6788-4d25-840c-714c7ed396cb','重入東林寺','董嗣杲','宋','宋诗','song-poetry','','[]','鴈門市裏梵坊通，整理重登興未窮。',64,'全唐诗/poet.song.237000.json','["鴈門市裏梵坊通，整理重登興未窮。", "雙劍風髙雲氣壓，五杉閣峻水聲空。", "欲抛世網離塵境，要扣禪機演祖風。", "况有昔賢遺跡處，白家池上白蓮中。"]'),
('534c4441-e4ce-4fe9-82f8-dbc8982d3414','李勉之攝廣濟尉','董嗣杲','宋','宋诗','song-poetry','','[]','我滯湓城每自憐，相逢相倚杖頭錢。',64,'全唐诗/poet.song.237000.json','["我滯湓城每自憐，相逢相倚杖頭錢。", "盍簮愁想年窮夜，覽鏡羞稱壮士年。", "萱草滿階堪壽母，梅花遶屋可名仙。", "近家何往非安地，又買槃塘對岸船。"]'),
('1d7d7d26-c904-4d15-abf0-f5c71d10dd23','送張子秀入京','董嗣杲','宋','宋诗','song-poetry','','[]','玉立當歸香案傍，平時髙論凛秋霜。',64,'全唐诗/poet.song.237000.json','["玉立當歸香案傍，平時髙論凛秋霜。", "錦嚢自富驚人語，寶劍猶埋斷佞光。", "雨外雷聲隨地起，江頭虹氣接天長。", "有謨入告需時用，未忍將身學子房。"]'),
('d1b949fb-7e60-4d0d-8bd7-d199130c15b1','黄池客樓','董嗣杲','宋','宋诗','song-poetry','','[]','得子相慰忍袂分，還棲黄池朱子門。',64,'全唐诗/poet.song.237000.json','["得子相慰忍袂分，還棲黄池朱子門。", "雪花著鬢久方濕，酒味裂腸空自温。", "欲問笛起市樓破，不知井通河水渾。", "凍塵難浣見誰說，蝸角蠅頭爭噬吞。"]'),
('00f79274-6398-42db-aef6-2ac15e7cf226','送越人姚日章遊淮','董嗣杲','宋','宋诗','song-poetry','','[]','氣宇凌虹駕海長，薄遊感慨舊封疆。',64,'全唐诗/poet.song.237000.json','["氣宇凌虹駕海長，薄遊感慨舊封疆。", "家鄰賀老千秋觀，袖有曾公一瓣香。", "遍走江湖諳客况，快吟風雪過淮鄉。", "井蛙我且安愚分，未卜何時共酒觴。"]'),
('495ec4e3-03c7-4552-bf7d-0ee09d00fa45','重泊楊港','董嗣杲','宋','宋诗','song-poetry','','[]','交石夾頭棲落鴻，缷桅强飯傷飄篷。',64,'全唐诗/poet.song.237000.json','["交石夾頭棲落鴻，缷桅强飯傷飄篷。", "隔洲漁屋披亂草，入港客舟維古楓。", "際晚望斷風帘矗，纔晴洗得雪林空。", "舊僑野寺重尋懶，回眺炊煙揺葦叢。"]'),
('1d5f209b-f9ce-4561-aa6f-51f180024306','舟宿湖口  其一','董嗣杲','宋','宋诗','song-poetry','','[]','汀沙如雪水無聲，舟倚蒹葭鴈不驚。',64,'全唐诗/poet.song.237000.json','["汀沙如雪水無聲，舟倚蒹葭鴈不驚。", "霜氣隔篷纔數尺，斗杓插地已三更。", "抛書枕畔憐兒子，看劍鐙前慨友生。", "尚有乘桴無限意，催人揺櫓轉江城。"]'),
('af4f4e0b-c081-4278-ab4a-62996f2fc758','舟宿湖口  其二','董嗣杲','宋','宋诗','song-poetry','','[]','長年人海混潮聲，水宿荒凉却夜驚。',64,'全唐诗/poet.song.237000.json','["長年人海混潮聲，水宿荒凉却夜驚。", "月照空巢烏繞樹，風吹短草鴈知更。", "要觀此地秋濤壮，更待明年春水生。", "不比蜃樓多變見，綵雲初日擁層城。"]'),
('900045d9-5f50-4147-aa04-f2bbb67735b7','清明日懐孤山','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','身寄湓城歲月奔，逺懐仙苑自乾坤。',64,'全唐诗/poet.song.237000.json','["身寄湓城歲月奔，逺懐仙苑自乾坤。", "梅林有影吟魂在，陳柏無枝古意存。", "獨客此時思上塜，孤山今日定開門。", "西江不似西湖上，處處酬春把酒樽。"]'),
('79eb4d44-2087-43a8-be16-ce5c4917c252','重遊能仁寺','董嗣杲','宋','宋诗','song-poetry','','[]','古寺踞城爲甲刹，巍峨殿閣矗江雲。',64,'全唐诗/poet.song.237000.json','["古寺踞城爲甲刹，巍峨殿閣矗江雲。", "香煙昏壁沿廊黒，磚塔喧鈴徹郡聞。", "白日僧歸春更静，清明鬼哭夜初分。", "住持羞接閑人話，要訪時官杜廣文。"]'),
('ac88b744-15de-40b5-85e2-8fd52b9ccf98','過林静學湖荘','董嗣杲','宋','宋诗','song-poetry','','[]','宿雨初收湖水香，水邉風月闌干長。',64,'全唐诗/poet.song.237000.json','["宿雨初收湖水香，水邉風月闌干長。", "幽情多駐古松里，舊夢幾空春草塘。", "移竹栖鸞鍾野趣，卷簾通燕悵年光。", "衰殘謾自戀名酒，足弱體瘦誰扶將。"]'),
('98c4da94-00ce-4afa-b34e-225b79b38500','白家池亭','董嗣杲','宋','宋诗','song-poetry','','[]','白傅流風尚可尋，爐峰蓊紫掩天陰。',64,'全唐诗/poet.song.237000.json','["白傅流風尚可尋，爐峰蓊紫掩天陰。", "石埋遺像丹青落，泉遶虚堂歲月深。", "老木寒拖千谷翠，小蓮凉矗兩池金。", "挑包知是何方侣，空論能參惠逺心。"]'),
('cf1bef6a-934b-4970-90cd-975f6d463032','家書不至自嘲','董嗣杲','宋','宋诗','song-poetry','','[]','客愁難遏鬢華添，晝寢醒來飽黒甜。',64,'全唐诗/poet.song.237000.json','["客愁難遏鬢華添，晝寢醒來飽黒甜。", "春雨褪花粘蘚屐，晚風吹燕入蘆簾。", "自知闕下家書斷，不過城南卜肆占。", "蕭散形骸天分定，江城惟有醉厭厭。"]'),
('2f710415-3dea-4d3e-a7a4-1da0c9dd7674','江州寒食','董嗣杲','宋','宋诗','song-poetry','','[]','殊鄉寒食亦風柔，桃李春香掩燕樓。',64,'全唐诗/poet.song.237000.json','["殊鄉寒食亦風柔，桃李春香掩燕樓。", "周子墓頭誰拜掃，岳家園裏自嬉遊。", "雲連閫節旌旗暗，水泛商船鼓笛浮。", "江國日長饒客思，不知何事阻歸謀。"]'),
('af1ba4f0-4b15-4acb-a17f-76559d7ce656','暑中客懐','董嗣杲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','飄蓬於此趣何迂，破却牢愁是酒壺。',64,'全唐诗/poet.song.237000.json','["飄蓬於此趣何迂，破却牢愁是酒壺。", "世上利名休羡有，胸中丘壑不應無。", "秋侵客鬢從添白，春滿侯門亦謾朱。", "無地追凉身坐甑，藕花多處憶西湖。"]'),
('160dff22-48db-4dcf-8275-18a01bf81265','泊李家渡','董嗣杲','宋','宋诗','song-poetry','','[]','鴈字書空極勁遒，江流東去不流愁。',64,'全唐诗/poet.song.237000.json','["鴈字書空極勁遒，江流東去不流愁。", "夢歸破屋南山下，身落寒沙古渡頭。", "雪意已堅狂問酒，風威未厲懶添裘。", "土人識得滄浪客，特地相期劇醉留。"]'),
('44a312bb-3dd5-4a32-b821-424e72f19c43','入廬山','董嗣杲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','斷隴横溪出酒旗，乘疲小憇晚陰時。',64,'全唐诗/poet.song.237000.json','["斷隴横溪出酒旗，乘疲小憇晚陰時。", "幽林合翠痕痕净，逺瀑飛瓊派派奇。", "水迥起風傳鸛垤，村荒入夕見鷄塒。", "竹間誰拂農家壁，覔寫如今夜醉詩。"]'),
('f694cb7b-d2c4-41ba-b036-7aa5be383821','午睡','董嗣杲','宋','宋诗','song-poetry','','[]','茶竈煙沉午睡遲，故山雲逺思依依。',64,'全唐诗/poet.song.237000.json','["茶竈煙沉午睡遲，故山雲逺思依依。", "桑麻得雨侵簷長，燕雀臨風掠水飛。", "簮帽無花徒遶砌，探瓶有粟且扄扉。", "翔空何處胎仙唳，華表當年識令威。"]');
